-- Poems batch 200
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d1884b8b-7ffd-4259-8977-63eb1081ae43','次韻高陽吳中復待制見寄','趙抃','宋','宋诗','song-poetry','','[]','守蜀無堪詎足論，捫參天邈紫微垣。',64,'全唐诗/poet.song.19000.json','["守蜀無堪詎足論，捫參天邈紫微垣。", "歲時豐衍真爲幸，犴獄空虛冀不寃。", "素志未容龜曳尾，誤恩深愧鶴乘軒。", "嘉章益見公高誼，所得長逢左右原。"]'),
('dedd0c38-9c61-4c02-8987-24c7cb0710dd','次韻霍交中春游樂俗亭','趙抃','宋','宋诗','song-poetry','','[]','自憐拙政無他狀，强繼前賢樂遠民。',64,'全唐诗/poet.song.19000.json','["自憐拙政無他狀，强繼前賢樂遠民。", "軒豁四簷芳草岸，夷猶千櫂綠波春。", "岷山霽色塵氛斂，錦里風光氣候新。", "暮角未吹人未散，醉歌歡舞共紛綸。"]'),
('4c454816-7d10-4b12-bf4a-a507113ba23d','次韻蘇宷游學射山','趙抃','宋','宋诗','song-poetry','','[]','錦川風俗喜時平，上巳家家出郡城。',64,'全唐诗/poet.song.19000.json','["錦川風俗喜時平，上巳家家出郡城。", "射圃人稠諠畫鼓，龍湫波浄照紅旌。", "迎真昔詫登天虎，命侶今聞出谷鶯。", "勉爲遠民同樂事，使臺仍是得賢明。"]'),
('e5b7238e-0cba-4ec1-bcd6-1f9995f20aa4','送程給事守越州','趙抃','宋','宋诗','song-poetry','','[]','千騎從君臨照水，雙旌復我守錢塘。',64,'全唐诗/poet.song.19000.json','["千騎從君臨照水，雙旌復我守錢塘。", "當年已共攀蟾桂，今日休辭醉羽觴。", "行聽龔黄歌治譽，好追元白遞詩章。", "分符況與尋常異，彼此東西是故鄉。"]'),
('68f0e36d-3044-40cc-8897-ec347ed0df13','次韻前人寓越廨宇有懷','趙抃','宋','宋诗','song-poetry','','[]','越郡江南盡不如，樂天流語信非踈。',64,'全唐诗/poet.song.19000.json','["越郡江南盡不如，樂天流語信非踈。", "人從鎖闥中間出，宅在蓬萊向上居。", "言念玉符分鎮日，却思瓊苑拜恩初。", "臨風又辱詩筒寄，足見優游刃有餘。"]'),
('acefa530-fc17-4f62-b46b-c26d873bb3cf','再用韻','趙抃','宋','宋诗','song-poetry','','[]','一別三秋一日如，望中紅葉已蕭踈。',64,'全唐诗/poet.song.19000.json','["一別三秋一日如，望中紅葉已蕭踈。", "曾聞眷注行優召，自顧衰遲未退居。", "在昔游從今道舊，平生事契敢忘初。", "古人最重交情久，堪笑當年漢耳餘。"]'),
('8abe3bbd-5640-4f2a-9b9e-4c5a18a93744','和前人有懷二首  其一','趙抃','宋','宋诗','song-poetry','','[]','一日褰幃令必從，自慚前粃屬衰翁。',64,'全唐诗/poet.song.19000.json','["一日褰幃令必從，自慚前粃屬衰翁。", "聲回地底清霜角，訟自庭中冷缿筒。", "舊契世同知管鮑，新文人服似軻雄。", "公閒數有瓊瑶贈，又使鄉閭篤士風。"]'),
('88aa46a5-2ad1-4e12-a4d4-93f6a091352d','和前人有懷二首  其二','趙抃','宋','宋诗','song-poetry','','[]','遠如千里志還同，目斷雲天未易窮。',64,'全唐诗/poet.song.19000.json','["遠如千里志還同，目斷雲天未易窮。", "勉强一麾吳國分，雍容五馬浙江東。", "泉源自古流丹井，桂子還逢下月宮。", "盡占神仙真樂地，軒裳何敢羨三公。"]'),
('3759ae5f-9a81-437f-817b-43a3159bd6fc','次韻郡齋即事二首  其一','趙抃','宋','宋诗','song-poetry','','[]','鳳沼寵榮辭禁闥，龍山安穩駐車輪。',64,'全唐诗/poet.song.19000.json','["鳳沼寵榮辭禁闥，龍山安穩駐車輪。", "東方漸喜威嚴霽，屬郡爭傳號令新。", "試數歲華如過隙，宜將世事拂前塵。", "因思四十年同榜，吳越如今只兩人。"]'),
('29851eb5-97ed-44cc-b3d5-618b9f9807bb','次韻郡齋即事二首  其二','趙抃','宋','宋诗','song-poetry','','[]','田原多稼纔豐日，橘柚逢霜正熟初。',64,'全唐诗/poet.song.19000.json','["田原多稼纔豐日，橘柚逢霜正熟初。", "鑑水烟波乘興遠，蘭舟風月助吟餘。", "安知賀老惟修道，未必羲之祗嗜書。", "誰道蓬萊宮尚小，玉皇香案吏來居。"]'),
('7ea58763-4323-40b5-b0c4-b58d84e13e97','次韻見寄','趙抃','宋','宋诗','song-poetry','','[]','勇退猶慚大丈夫，兩州四任若冥符。',64,'全唐诗/poet.song.19000.json','["勇退猶慚大丈夫，兩州四任若冥符。", "未容上冢重官越，不謂班條再守吳。", "雲屋萬家誠樂地，濤江一水隔名都。", "同年後日同歸去，畫作東西二老圖。"]'),
('937b14d5-d2e7-4220-b574-c337106afa3d','次韻郡齋偶成','趙抃','宋','宋诗','song-poetry','','[]','兩火一刀名素勝，十分雙澗地長靈。',64,'全唐诗/poet.song.19000.json','["兩火一刀名素勝，十分雙澗地長靈。", "常心曾爲乘華舫，好手應難作畫屏。", "北海樓前千里靜，南山天末四時青。", "蓬萊自是仙家景，解使詩翁醉眼醒。"]'),
('3bff5123-8f03-4d88-b92b-35a696a4303a','武林即事寄前人二首  其一','趙抃','宋','宋诗','song-poetry','','[]','乞得錢塘下九天，徙從青社復三川。',64,'全唐诗/poet.song.19000.json','["乞得錢塘下九天，徙從青社復三川。", "坤維十往萬餘里，吳分重來七八年。", "鑑水坐遥懷舊治，柯峯歸晚愧前賢。", "東州賴有微之約，曾寄詩筒遞百篇。"]'),
('960b25c0-8774-4b1f-aef3-b1651969e4d9','武林即事寄前人二首  其二','趙抃','宋','宋诗','song-poetry','','[]','七十隨緣豈有由，樂天曾不厭杭州。',64,'全唐诗/poet.song.19000.json','["七十隨緣豈有由，樂天曾不厭杭州。", "青山未隱如千里，白首重來又九秋。", "月窟仙人遺桂子，海門神物助潮頭。", "自慚老守無心力，坐鎮吾民靜即休。"]'),
('c24d1ae0-35bb-442c-824e-1bebd6a60932','題杭州普應院偃松','趙抃','宋','宋诗','song-poetry','','[]','老松低偃四時榮，太守重來眼爲青。',64,'全唐诗/poet.song.19000.json','["老松低偃四時榮，太守重來眼爲青。", "密葉動摇翔鳳勢，深根盤屈卧龍形。", "每容狂客春携酒，長庇閒僧晝看經。", "一百年來霜雪操，肯隨羣木漫彫零。"]'),
('8bc3ea92-33ce-4c49-90cf-e22b6a696a5e','次韻程給事見懷','趙抃','宋','宋诗','song-poetry','','[]','烟水平湖千頃碧，樓臺佳木四時青。',64,'全唐诗/poet.song.19000.json','["烟水平湖千頃碧，樓臺佳木四時青。", "人瞻杳杳升天宅，客意峩峩望海亭。", "已是威懷寬帝念，更加豐稔慰民靈。", "退公莫厭音題密，去鯉來鴻不暫停。"]'),
('a08fa87c-bd98-456f-ae9a-532406b16881','有懷前人','趙抃','宋','宋诗','song-poetry','','[]','湖平去棹復鳴鼙，一別何時手重携。',64,'全唐诗/poet.song.19000.json','["湖平去棹復鳴鼙，一別何時手重携。", "龍榜昔同科甲乙，虎符今得郡東西。", "尋真曾憶觀丹井，乘興徒思泛剡溪。", "聞說公堂多暇豫，湖山無處不留題。"]'),
('a6f4ba1e-25ce-4549-887f-69c56e6a3102','登望越亭寄程給事','趙抃','宋','宋诗','song-poetry','','[]','望越亭無一點塵，迢迢東首座凝神。',64,'全唐诗/poet.song.19000.json','["望越亭無一點塵，迢迢東首座凝神。", "雨餘岫色濃如黛，日出波光爛若銀。", "我類武陵歸去客，君爲蓬島上頭人。", "誰知老守吾鄉便，得與詩翁作善隣。"]'),
('60562340-b5d8-4fcb-9a94-89546d20a5ae','有懷前人','趙抃','宋','宋诗','song-poetry','','[]','稽嶺樓臺真曠絕，武林風物競豪華。',64,'全唐诗/poet.song.19000.json','["稽嶺樓臺真曠絕，武林風物競豪華。", "兩川對望音題數，一水中分會晤差。", "東海渺茫排島嶼，西陵依約露人家。", "元和賡唱今猶古，此樂情懷豈有涯。"]'),
('03a495cc-79f3-4b2c-8c92-4c5338b8b35d','次韻臘月不見梅花','趙抃','宋','宋诗','song-poetry','','[]','隔江氣候不齊時，梅向杭開越上遲。',64,'全唐诗/poet.song.19000.json','["隔江氣候不齊時，梅向杭開越上遲。", "春遠未通蓬島信，臘深先放武林枝。", "嶺頭素艷從爭發，笛裏孤音却後期。", "虛白堂前攀折看，詠公詩句醉金巵。"]'),
('c9106946-6aee-4290-86d5-1fa7c3978843','次韻樓頭聞角','趙抃','宋','宋诗','song-poetry','','[]','龍蟄窮冬萬否開，蛩吟清曉在蓬萊。',64,'全唐诗/poet.song.19000.json','["龍蟄窮冬萬否開，蛩吟清曉在蓬萊。", "五更枕上驚殘夢，一曲樓頭動小梅。", "入牖涼颸聲咽絕，滿庭斜日思徘徊。", "新年合我七十一，柯嶺不如歸去來。"]'),
('7c1c4715-a64a-4f71-bf23-5bb2b16b7869','次韻歲暮有感','趙抃','宋','宋诗','song-poetry','','[]','歲月如流不用嗟，盛衰前定豈曾差。',64,'全唐诗/poet.song.19000.json','["歲月如流不用嗟，盛衰前定豈曾差。", "自憐覽照頭渾雪，猶喜觀書目未花。", "竺嶺兩曾逢落桂，龍山三見擷新茶。", "春元便欲休官去，誰顧杭州十萬家。"]'),
('27e43bb0-ae5e-429f-a69a-9450cc49fbb5','次韻即事見懷','趙抃','宋','宋诗','song-poetry','','[]','鑑水寬閒稱越國，河塘繁劇是杭州。',64,'全唐诗/poet.song.19000.json','["鑑水寬閒稱越國，河塘繁劇是杭州。", "蓬山君繼元丞相，竹馬予慚郭細侯。", "郡邑豐穰真可喜，人家飽煖更何憂。", "西陵隔岸無多遠，數上臨江百尺樓。"]'),
('5be7c8bd-0d57-4e4c-9c87-43629a878682','歲暮偶成寄前人','趙抃','宋','宋诗','song-poetry','','[]','宦途衰老改辭勤，只計斯民不計身。',64,'全唐诗/poet.song.19000.json','["宦途衰老改辭勤，只計斯民不計身。", "眷戀青山乖素約，遲留白首未歸人。", "舉頭舊治無三舍，屈指明朝又一春。", "珍重東州年契厚，趁潮雙鯉得書頻。"]'),
('cc1db6b2-5f9d-4a6b-89f8-f29709558e02','戊午元日偶成','趙抃','宋','宋诗','song-poetry','','[]','驅馳光景急如輪，復見元豐歲始春。',64,'全唐诗/poet.song.19000.json','["驅馳光景急如輪，復見元豐歲始春。", "七十一年欣入手，三千奏牘欲歸身。", "江濤有信人隨老，烟草無涯色又新。", "自是乞骸時節好，不應推托爲思蓴。"]'),
('6cd382bb-a746-49a9-9631-7b5dec422c8b','清風閣即事','趙抃','宋','宋诗','song-poetry','','[]','庭有松蘿砌有苔，退公聊此遠塵埃。',64,'全唐诗/poet.song.19000.json','["庭有松蘿砌有苔，退公聊此遠塵埃。", "湖音隱隱海門至，泉勢潺潺石縫來。", "夜榻衾裯仙夢覺，曉窗燈火佛書開。", "休官不久輕舟去，喜過嚴陵舊釣臺。"]'),
('beec641d-2aba-4283-9bb2-0f3d7b045a4b','杭州上元觀燈  其一','趙抃','宋','宋诗','song-poetry','','[]','元夕觀燈把酒杯，賓朋不倦醉中陪。',64,'全唐诗/poet.song.19000.json','["元夕觀燈把酒杯，賓朋不倦醉中陪。", "一輪丹桂當天滿，千頃紅蓮匝地開。", "烟火樓臺高復下，笙歌巷陌去還來。", "因民共作連宵樂，直待東方明始回。"]'),
('ee6021ac-53d0-4445-ab2d-03f0ffc3a705','杭州上元觀燈  其二','趙抃','宋','宋诗','song-poetry','','[]','初逢稔歲改初元，元夜從游駕兩轓。',64,'全唐诗/poet.song.19000.json','["初逢稔歲改初元，元夜從游駕兩轓。", "寺曲水燈多巧怪，河塘歌吹競喧繁。", "安排百戲無虛巷，開闢重關不鎖門。", "願以民心祝堯壽，從星高拱北辰尊。"]'),
('e4638356-ea98-40bf-ae4f-a59049e3522b','次韻程給事越州元夕觀燈','趙抃','宋','宋诗','song-poetry','','[]','隔江燈火越王城，別有新春喜復驚。',64,'全唐诗/poet.song.19000.json','["隔江燈火越王城，別有新春喜復驚。", "累夕思鄉還有感，三年懷旅豈忘情。", "歌鐘浩浩臨香陌，羅綺盈盈簇彩棚。", "秉燭夜遊公不倦，也知斯樂爲民行。"]'),
('5666c9a7-9fbd-42be-bb00-e7861312e03d','次韻前人治西園池館因懷昔日太守蔣堂侍郎二首  其一','趙抃','宋','宋诗','song-poetry','','[]','越有西園作者誰，公今不感詠歌之。',64,'全唐诗/poet.song.19000.json','["越有西園作者誰，公今不感詠歌之。", "千餘騎擁頻來賞，四十年間尚去思。", "稚耋行謠方載路，主賓高會正乘時。", "也知此樂同民樂，況有前賢臺沼詩。"]'),
('ad536f96-e89d-420a-a36b-649cd1be2201','次韻前人治西園池館因懷昔日太守蔣堂侍郎二首  其二','趙抃','宋','宋诗','song-poetry','','[]','去年春色染波瀾，畫舸朝遊暮可還。',64,'全唐诗/poet.song.19000.json','["去年春色染波瀾，畫舸朝遊暮可還。", "今歲屢聞臨曲水，隔江惟是仰高山。", "翻思賢守經營處，盡屬詩翁笑語間。", "公勿留連當亟召，德音行被對天顔。"]'),
('2ee1958b-b13a-466b-811d-6eae43bf640b','有懷前人','趙抃','宋','宋诗','song-poetry','','[]','却憶東舟去若仙，江亭分袂忽經年。',64,'全唐诗/poet.song.19000.json','["却憶東舟去若仙，江亭分袂忽經年。", "春風境上無多地，夜月湖中共一天。", "海閣坐觀濤擁鷺，山堂吟聽漏移蓮。", "新詩往復交情見，巨集成來已百篇。"]'),
('6f6d5f0d-3fdd-43f1-879a-5cac15d95419','次韻前人見寄','趙抃','宋','宋诗','song-poetry','','[]','阻奉交朋宴賞歡，杏林春發聖師壇。',64,'全唐诗/poet.song.19000.json','["阻奉交朋宴賞歡，杏林春發聖師壇。", "詩筒把玩初藏袖，鈴閣吟哦爲整冠。", "不啻夢昏驚玉磬，正如沈痼得金丹。", "夜來月下聞韶濩，並奏清音徹廣寒。"]'),
('0f9a3df1-1ef8-4651-a0f8-88868d62864d','寄酬前人','趙抃','宋','宋诗','song-poetry','','[]','落筆詞華矜白雪，棹尋花卉認紅雲。',64,'全唐诗/poet.song.19000.json','["落筆詞華矜白雪，棹尋花卉認紅雲。", "湖山對酌春將盡，風月高吟夜欲分。", "思入神酬青玉案，夢遊仙擁羽衣裙。", "近來章句聲名還，僻似雞林也得聞。"]'),
('628b4405-f5df-4f4f-b2df-dbedb9505184','寄酬前人上巳日鑑湖即事三首  其一','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','禊飲已經佳節後，畫船猶泛若耶濱。',64,'全唐诗/poet.song.19000.json','["禊飲已經佳節後，畫船猶泛若耶濱。", "未還魏闕陪仙使，且向稽山作主人。", "賡唱我知長引玉，懇歸誰道苦思親。", "鑑湖也似西湖好，兩處風光一樣春。"]'),
('b4e6659e-59c9-491d-ab3f-c5ef0f72d222','寄酬前人上巳日鑑湖即事三首  其二','趙抃','宋','宋诗','song-poetry','','[]','湖上初經上巳春，水邊遥見碧蕪新。',64,'全唐诗/poet.song.19000.json','["湖上初經上巳春，水邊遥見碧蕪新。", "輕舟競泛無涯樂，夾岸希逢不醉人。", "厨醞旋斟浮蟻釅，府茶深點卧龍珍。", "詩筒往復余知幸，垂老親仁得善隣。"]'),
('0d9eb11c-53fe-438e-a8f3-f31f24490e55','寄酬前人上巳日鑑湖即事三首  其三','趙抃','宋','宋诗','song-poetry','','[]','蓬萊高與卧龍俱，位望兼隆似合符。',64,'全唐诗/poet.song.19000.json','["蓬萊高與卧龍俱，位望兼隆似合符。", "絃管夜聲傳井邑，樓臺春影蘸江湖。", "休功即報朞年政，直節曾行萬里胡。", "真是玉皇得案吏，坐看歸去贊蘿圖。"]'),
('4a9b4e97-0e42-4090-83c6-e584cd7fcf23','次韻前人蓬萊閣即事','趙抃','宋','宋诗','song-poetry','','[]','蓬萊窗外曉光分，夢覺初驚杜宇魂。',64,'全唐诗/poet.song.19000.json','["蓬萊窗外曉光分，夢覺初驚杜宇魂。", "但有吏供衙府喏，斷無人到訟庭喧。", "濛濛宿靄開湖面，隱隱更潮過海門。", "一水兩州皆重鎮，越清杭劇不同論。"]'),
('b31222c6-fc4c-43db-a82d-81dc70e6e7e4','聞致政趙少師概入境寄獻','趙抃','宋','宋诗','song-poetry','','[]','我公優暇若神仙，八十高齡眾所賢。',64,'全唐诗/poet.song.19000.json','["我公優暇若神仙，八十高齡眾所賢。", "政府昔同俄一紀，留封今別又三年。", "及時和氣來吳國，度曲薰風入舜絃。", "昨日清臺應密奏，老人星照浙西天。"]'),
('9e947877-c280-4558-8241-2f2d8879160b','上天竺寺石巖花','趙抃','宋','宋诗','song-poetry','','[]','對植齊開古梵宮，欲求精筆畫難工。',64,'全唐诗/poet.song.19000.json','["對植齊開古梵宮，欲求精筆畫難工。", "直將春占三旬盛，誰謂花無十日紅。", "未羨山桃資客笑，且陪庭栢作家風。", "遍尋他處都無此，寶殿前頭只兩叢。"]'),
('e461320e-d36e-4734-b266-86ac6bd23d3d','次韻程給事寄獻趙少師','趙抃','宋','宋诗','song-poetry','','[]','暮春船艤浙西州，且喜樽前兩白頭。',64,'全唐诗/poet.song.19000.json','["暮春船艤浙西州，且喜樽前兩白頭。", "蓬閣屢傳賓榻解，濤江深阻故人遊。", "凝眸讌集踰天遠，屈指光陰若箭流。", "賴有詩筒并驛使，往還金玉共賡酬。"]'),
('8922b854-3be3-4e9a-9460-4dde80bc2a77','次韻趙少師寄程給事二首  其一','趙抃','宋','宋诗','song-poetry','','[]','輕舟來蜀幕春時，便向錢塘詠式微。',64,'全唐诗/poet.song.19000.json','["輕舟來蜀幕春時，便向錢塘詠式微。", "臨海阻陪三島會，隔江遥認五雲飛。", "殺雞炊黍初乘興，怨鶴驚猿却念歸。", "一水盈盈天一色，夜來千里共蟾輝。"]'),
('503557ad-20d1-44c9-b640-72ca8178eb2e','次韻趙少師寄程給事二首  其二','趙抃','宋','宋诗','song-poetry','','[]','襟懷冲曠憶江湖，老我全吳契不踈。',64,'全唐诗/poet.song.19000.json','["襟懷冲曠憶江湖，老我全吳契不踈。", "北闕乍違堯日遠，南風新入舜絃初。", "紵溪鑑水吟無厭，箭笋鎗茶味有餘。", "越絕主人招意重，卧龍山好駕安車。"]'),
('7c44380d-7659-46e7-b0e7-5783993d504b','少師自南都見訪爲詩以謝','趙抃','宋','宋诗','song-poetry','','[]','中懷和氣祗如春，對酒賡歌莫厭頻。',64,'全唐诗/poet.song.19000.json','["中懷和氣祗如春，對酒賡歌莫厭頻。", "半載昔同參國論，十年今長類天倫。", "不辭命駕踰千里，應念同心有二人。", "珍重宗盟恩意厚，歲寒終始見松筠。"]'),
('594a8442-5b25-4c38-81c0-a293b7764b8b','留前人度夏方回南都','趙抃','宋','宋诗','song-poetry','','[]','宮師彌壽降尊時，頓覺光華滿郡扉。',64,'全唐诗/poet.song.19000.json','["宮師彌壽降尊時，頓覺光華滿郡扉。", "況屬炎暉初可畏，未逢秋爽莫言歸。", "山堂酒嫩浮紅蟻，石縫茶新碾翠旂。", "有美望湖風四面，尚留揮汗雨霑衣。"]'),
('61585fcf-a439-4fe3-b2d3-f446ad60ac12','次韻前人題六和寺壁','趙抃','宋','宋诗','song-poetry','','[]','上方樓殿已幽深，更向諸峯勝處尋。',64,'全唐诗/poet.song.19000.json','["上方樓殿已幽深，更向諸峯勝處尋。", "金擺池魚驚俗眼，琴調山溜寫清音。", "紅芝九本初無種，翠栢千株自有心。", "眾羨宮師康且壽，始知功德積來陰。"]'),
('4c5a9675-638c-42b3-a849-bbac73598c9c','陪前人游西湖兼簡坐客','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','絲管喧喧擁畫船，澄瀾上下照紅蓮。',64,'全唐诗/poet.song.19000.json','["絲管喧喧擁畫船，澄瀾上下照紅蓮。", "一樽各盡十分酒，四老共成三百年。", "北闕音書休憶念，西湖風物且留連。", "杭民夾道焚香看，白髮朱顔長壽仙。"]'),
('4ce9ca0d-73fb-489a-a9e1-85d5637625d6','再用前韻','趙抃','宋','宋诗','song-poetry','','[]','共泛湖光范蠡船，持盃歡客倒金蓮。',64,'全唐诗/poet.song.19000.json','["共泛湖光范蠡船，持盃歡客倒金蓮。", "此時朋契偕行樂，何日郡恩許引年。", "照水暗知華髮改，倚樓高與紫雲連。", "安車盛暑盤桓好，況是人間一散仙。"]'),
('f3aa2b0c-89d0-4819-9017-aa34448a4bc6','武林言懷寄程給事','趙抃','宋','宋诗','song-poetry','','[]','歲豐公暇兩安舒，吳越詩筒不使踈。',64,'全唐诗/poet.song.19000.json','["歲豐公暇兩安舒，吳越詩筒不使踈。", "世契瓊瑶風誼厚，秋光懷袖氣涼初。", "二千石重閒無計，七十年過退有餘。", "得旨便歸田隴去，鄉人從笑老農如。"]'),
('16f9cdfd-c4ed-4b14-8502-61aefc81dd95','次韻前人懷西湖之游','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔時唐殿預英雄，今獨湖山幸會逢。',64,'全唐诗/poet.song.19000.json','["昔時唐殿預英雄，今獨湖山幸會逢。", "謫宦青錢曾萬選，承恩白首是三公。", "龍山我念經年別，虎榜君曾昔日同。", "老守七章還印綬，俞音朝暮出宸衷。"]'),
('2cba61e2-009f-475c-8a96-72ddb63a536b','次韻前人見寄二首  其一','趙抃','宋','宋诗','song-poetry','','[]','羨公鈴閤絕纖塵，顧我何嘗德被人。',64,'全唐诗/poet.song.19000.json','["羨公鈴閤絕纖塵，顧我何嘗德被人。", "訟牘自憐無日暇，詩筒翻喜入秋新。", "白頭未許還官政，紫詔頻煩慰老臣。", "一去蓬萊已踰歲，夢魂長到十洲春。"]'),
('3be19d28-cbc9-434d-a618-7712f14aecd4','次韻前人見寄二首  其二','趙抃','宋','宋诗','song-poetry','','[]','立賢中外聖情均，青鎖闈中輟邇臣。',64,'全唐诗/poet.song.19000.json','["立賢中外聖情均，青鎖闈中輟邇臣。", "越水澄清無俗慮，秋風蕭瑟助吟神。", "分符共治俄經歲，屈指同年尚幾人。", "退鼓近來衰氣覺，敢將詩酒敵東隣。"]'),
('852a3508-cfde-4e5a-b92b-b1cc7ad4e226','寄新筠守毛維瞻大夫','趙抃','宋','宋诗','song-poetry','','[]','倚廬聊見復睽乖，憶遺詩筒字字佳。',64,'全唐诗/poet.song.19000.json','["倚廬聊見復睽乖，憶遺詩筒字字佳。", "爲乏瓊瑶酬雅意，故憑筆牘寫離懷。", "程賒越北層雲斷，路入江南疊巘排。", "我望貽書何以報，要將風誼屬吾儕。"]'),
('c66d4228-c4c3-4b69-b5bb-a92b0ea1cc41','次韻許遵少卿見寄','趙抃','宋','宋诗','song-poetry','','[]','頭上有霜添白髮，囊中無藥駐朱顔。',64,'全唐诗/poet.song.19000.json','["頭上有霜添白髮，囊中無藥駐朱顔。", "堪驚積歲加衰老，未省何時得退閒。", "淵浄思臨浮石渚，喧譁羞對武林山。", "君恩早賜俞音下，即擁菟裘故里還。"]'),
('f8b81b85-8ab1-4e2a-8a1d-b5e9a64e537e','答前人喜杭越二守賡唱','趙抃','宋','宋诗','song-poetry','','[]','吳越江分兩郡齋，濤音朝夕聽風雷。',64,'全唐诗/poet.song.19000.json','["吳越江分兩郡齋，濤音朝夕聽風雷。", "且陪故友閒賡唱，未遂先廬歸去來。", "時節豐登饒鼓吹，湖山清曠見樓臺。", "中秋明月期公共，萬里烟氛徹曉開。"]'),
('4c957df7-b44c-4a8b-aac5-03cab69b6173','喜吳評少卿致政','趙抃','宋','宋诗','song-poetry','','[]','春秋七十更踰期，同甲同年世所稀。',64,'全唐诗/poet.song.19000.json','["春秋七十更踰期，同甲同年世所稀。", "未遂乞骸嗟我老，已輸先手羨公歸。", "良朋集有湖山樂，故里思無羽翼飛。", "預想俞音還印日，鷺濤秋色上行衣。"]'),
('f620cb43-671e-49dd-ad5c-7cf7bb25d410','次韻許少卿寄卧龍山茶','趙抃','宋','宋诗','song-poetry','','[]','越芽遠寄入都時，酬倡珍誇互見詩。',64,'全唐诗/poet.song.19000.json','["越芽遠寄入都時，酬倡珍誇互見詩。", "紫玉叢中觀雨脚，翠峯頂上摘雲旗。", "啜多思爽都忘寐，吟苦更長了不知。", "想到明年公進用，卧龍春色自遲遲。"]'),
('f6049088-3b93-4bab-90e2-252b0422eee6','次韻程給事郡齋即事','趙抃','宋','宋诗','song-poetry','','[]','望中吳越不爲賒，止隔濤江便一涯。',64,'全唐诗/poet.song.19000.json','["望中吳越不爲賒，止隔濤江便一涯。", "臺沼賜湖非俗地，蓬瀛標閣屬仙家。", "僧居壁古多留句，吏事庭虛只放衙。", "勝絕東方無復道，當年元相有詩誇。"]'),
('8dc50aa9-6cad-4a5c-953e-3234577be90c','次韻前人郡齋秋暑','趙抃','宋','宋诗','song-poetry','','[]','老爲鄉郡止偷安，自愧仙蹤未易攀。',64,'全唐诗/poet.song.19000.json','["老爲鄉郡止偷安，自愧仙蹤未易攀。", "八面松陰籠古寺，三秋桂子下靈山。", "良朋寄意詩篇裏，高會追陪夢寐間。", "却憶會稽清曠處，樵風朝暮若邪彎。"]'),
('27595ad5-6e4d-445d-b9d1-4a36b323c64d','觀寶林院塔偶成','趙抃','宋','宋诗','song-poetry','','[]','寶山新塔冠山形，心匠經營不日成。',64,'全唐诗/poet.song.19000.json','["寶山新塔冠山形，心匠經營不日成。", "突兀插天三百尺，莊嚴容佛一千名。", "下臨泉竇靈鰻蟄，上拂雲端過鴈驚。", "入境行人十餘里，指浮圖認越王城。"]'),
('b8c2afbf-0a7b-41a5-b1a2-bda24d9353b2','次韻毛維瞻度支過杭見贈','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳民疲病慚攻治，尋勝西湖不放稀。',64,'全唐诗/poet.song.19000.json','["吳民疲病慚攻治，尋勝西湖不放稀。", "秋後濤江增氣勢，夜深燈市鬭光輝。", "望雲翻憶青山舊，上印須添白髮歸。", "孝弟里閭松竹茂，柴扉誰復羨朱扉。"]'),
('14e432be-7c37-4797-b38b-985721b4fb07','送姚源道郎中赴闕','趙抃','宋','宋诗','song-poetry','','[]','我念同僚遽解携，贈言如古漫成詩。',64,'全唐诗/poet.song.19000.json','["我念同僚遽解携，贈言如古漫成詩。", "二年別乘臨岐日，八月登槎上漢時。", "莫阻十分斟釀蟻，不須三嘆聽歌驪。", "還朝寵數應非次，神聖方今大有爲。"]'),
('e4fbdc89-a7dd-4cec-9615-bd41866874da','寄致政范鎮郎中','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','分携常憶禁門東，四見光陰換歲筩。',64,'全唐诗/poet.song.19000.json','["分携常憶禁門東，四見光陰換歲筩。", "白玉堂吉辭舊相，青城山裏訪僊翁。", "當時大本從忠諫，此日長年益道風。", "應惜西湖猶未到，近來同賞有三公。"]'),
('8813fa69-8aad-4d13-946e-07bf900567e8','杭州鹿鳴宴示諸秀才','趙抃','宋','宋诗','song-poetry','','[]','秋闈賢詔出嚴宸，郡國詳延在得人。',64,'全唐诗/poet.song.19000.json','["秋闈賢詔出嚴宸，郡國詳延在得人。", "豹變文章重君子，鹿鳴歌詠集佳賓。", "初聞素履稱鄉閈，終起英名動縉紳。", "預想帝庭俱唱第，寵光榮宴杏園春。"]'),
('509258b2-8695-4ba6-bd80-6c2e5f61bfe8','遊元積之龍圖江湖堂','趙抃','宋','宋诗','song-poetry','','[]','高堂遊賞興無厭，況是江湖兩得兼。',64,'全唐诗/poet.song.19000.json','["高堂遊賞興無厭，況是江湖兩得兼。", "白傅閣危猶下視，子胥濤遠更前瞻。", "盤桓鼓吹風光盛，掩映烟波氣象添。", "太守老來難久戀，柯山朝暮欲歸潛。"]'),
('456bb56e-c6cd-4ad5-b2d8-9425a314c708','次韻程給事登蓬萊閣偶成','趙抃','宋','宋诗','song-poetry','','[]','蓬閣下臨千嶂起，戟扉前對五雲開。',64,'全唐诗/poet.song.19000.json','["蓬閣下臨千嶂起，戟扉前對五雲開。", "誇詩舊屬元之宅，叶氣今同老氏臺。", "月滿夜疑僊子降，風恬春喜故人來。", "近緣冗劇懷清曠，夢裏東遊到幾回。"]'),
('4f9cd7bc-02ec-4300-858c-fd3ebf5611af','次前人遊鑑湖','趙抃','宋','宋诗','song-poetry','','[]','湖治誰能繼後塵，馬侯祠閣至今存。',64,'全唐诗/poet.song.19000.json','["湖治誰能繼後塵，馬侯祠閣至今存。", "窮源上達僊翁井，引派旁通吏部園。", "紅旆遍遊償素志，畫橈歸去近黄昏。", "別懷屈指朞將半，況屬鄉州役夢魂。"]'),
('d8fcd304-0ff7-4dc4-8594-35fb73e3f2f7','次前人越州鹿鳴宴','趙抃','宋','宋诗','song-poetry','','[]','郡國秋闈籲俊辰，行修經治以名聞。',64,'全唐诗/poet.song.19000.json','["郡國秋闈籲俊辰，行修經治以名聞。", "芳筵縹緲開三島，大樂諠譁徹五雲。", "高桂折香期月窟，祥星垂彩應天文。", "集英唱第麻衣脫，得志無忘賢使君。"]'),
('12a51045-5621-4dc7-b21a-5edd0c57a1ad','次前人贈奉使高麗安燾密學','趙抃','宋','宋诗','song-poetry','','[]','爲嘉航海北徂南，雙節勤勞帝命銜。',64,'全唐诗/poet.song.19000.json','["爲嘉航海北徂南，雙節勤勞帝命銜。", "日下亟馳傳詔使，江邊遥訝過洋帆。", "才謀銳若金曾礪，德操剛同玉更鑱。", "機務須賢應並用，詩人莫惜詠巗巗。"]'),
('6f7bd848-e9bf-45f3-bcd6-26ce4ab808ba','次前人遊梅山寺','趙抃','宋','宋诗','song-poetry','','[]','上方金碧冠諸峯，知是蓬萊第幾宮。',64,'全唐诗/poet.song.19000.json','["上方金碧冠諸峯，知是蓬萊第幾宮。", "畫舫去尋湖面闊，危亭登望海門通。", "梅仙舊說爲真隱，佛子新傳倡祖風。", "我憶前春曾遍覽，至今來往夢魂中。"]'),
('69459c97-b3f2-4826-8e7e-ad5ff9a5dfd8','郡齋成寄前人','趙抃','宋','宋诗','song-poetry','','[]','退公真靜獨披襟，尚愧前賢探道深。',64,'全唐诗/poet.song.19000.json','["退公真靜獨披襟，尚愧前賢探道深。", "零落交游難屈指，崇高軒冕不關心。", "未還印綬饒鄉夢，猶倚湖山助老吟。", "訟缿虛空人事簡，錢塘安得似山陰。"]'),
('fcb97201-ba76-43e1-aca0-01493ebe9423','屢乞致政詔答未允述懷','趙抃','宋','宋诗','song-poetry','','[]','自愧孤忠荷聖慈，恩榮懇向九天辭。',64,'全唐诗/poet.song.19000.json','["自愧孤忠荷聖慈，恩榮懇向九天辭。", "于今蒲柳衰殘日，好是雲烟放曠時。", "玉闕累章煩賜詔，瀫江兩槳蹉歸期。", "宵征自有高人笑，漏盡鐘鳴曉未知。"]'),
('6dc8f375-c264-41ed-b308-6509346e7723','同毛維瞻度支遊烟霞洞','趙抃','宋','宋诗','song-poetry','','[]','洞有烟霞寺掛牌，武林奇處稱吟懷。',64,'全唐诗/poet.song.19000.json','["洞有烟霞寺掛牌，武林奇處稱吟懷。", "出城旌騎非虛往，同里交朋喜得偕。", "鷁首西征隨浪遠，鴈行南過入雲排。", "恩隆魏闕朝天日，寒晚鳴珂上禁街。"]'),
('72678aec-08db-4b17-a9bc-578e53d4c133','武林閱兵','趙抃','宋','宋诗','song-poetry','','[]','吳天霜曉弄寒暉，金鼓喧闐大閱時。',64,'全唐诗/poet.song.19000.json','["吳天霜曉弄寒暉，金鼓喧闐大閱時。", "帳下萬兵聽號令，軍中諸將肅威儀。", "采侯命中連三箭，花陣分排卓五旗。", "愧乏韜鈐當重寄，儒竹初是學書詩。"]'),
('f6a0fbef-cec8-47cd-97a9-5c01181a4f35','次韻程給事同孫覺學士楊憲景略遊天衣寺','趙抃','宋','宋诗','song-poetry','','[]','元是玉皇香案吏，等閒吟笑即成文。',64,'全唐诗/poet.song.19000.json','["元是玉皇香案吏，等閒吟笑即成文。", "松廊駐節排千騎，山逕尋真步五雲。", "諫院高風矜共賞，憲臺清論喜同聞。", "三賢一會誠難有，歸暮休辭酒十分。"]'),
('489b630d-adc1-4207-9d97-356df3612878','遊戒珠寺悼右軍故宅','趙抃','宋','宋诗','song-poetry','','[]','因山盛啟浮屠舍，遺像仍留內史祠。',64,'全唐诗/poet.song.19000.json','["因山盛啟浮屠舍，遺像仍留內史祠。", "筆塚近應爲塔塚，墨池今已作蓮池。", "書樓觀在人隨遠，蘭渚亭存世幾移。", "數紙黄庭誰不重，退之猶笑博鵞詩。"]'),
('717f5e3f-3f7f-4bc3-80f5-e09553860104','次趙少師敘感歎老','趙抃','宋','宋诗','song-poetry','','[]','稟靈南極老人星，貴得三公論道名。',64,'全唐诗/poet.song.19000.json','["稟靈南極老人星，貴得三公論道名。", "被旨入陪郊祀禮，放懷來聽海潮聲。", "朋從自古悠長少，勢利令人鄙吝生。", "公獨久要中外伏，直將金玉比純誠。"]'),
('6b3cfcfa-d018-41d9-a773-4487686c94f0','題孤山寺湖上閣','趙抃','宋','宋诗','song-poetry','','[]','孤峯諸寺聳雲樓，寺脚周環枕碧流。',64,'全唐诗/poet.song.19000.json','["孤峯諸寺聳雲樓，寺脚周環枕碧流。", "和靖久居勤賦詠，樂天臨別歎勾留。", "拏舟直度閒千騎，佩印重來僅十秋。", "預約前春掛冠去，湖山閣好換休休。"]'),
('6ae61c0d-515b-4ea9-86ba-5bc863183a87','次程給事題法雲寺方丈','趙抃','宋','宋诗','song-poetry','','[]','府公清眼照孤心，結構仍誇壺奧深。',64,'全唐诗/poet.song.19000.json','["府公清眼照孤心，結構仍誇壺奧深。", "師悟趙州庭栢境，我知青嶺震雷音。", "粟粘便是三千界，草用曾爲丈六金。", "一滴曹源誰可測，海門騰起浪千尋。"]'),
('ff4ce5ca-12fa-4664-b1ab-1c56cff39366','寄酬蔡仲偃都官','趙抃','宋','宋诗','song-poetry','','[]','守蜀思無羽翼飛，所思東向瀫江湄。',64,'全唐诗/poet.song.19000.json','["守蜀思無羽翼飛，所思東向瀫江湄。", "山林適意君先手，軒冕辭榮我後時。", "道阻八千通遠信，年迎七十是歸期。", "故人恩意如金玉，新得郵中數首詩。"]'),
('9da4fb8d-811c-4d17-908f-f1c8fda308ed','贈別周元忠秀才','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吾里推高節行孤，諸生師帳是規模。',64,'全唐诗/poet.song.19000.json','["吾里推高節行孤，諸生師帳是規模。", "窮經不治五畝宅，教子已爲千里駒。", "暫出林泉飛兩槳，且陪風月賞西湖。", "了知富貴儻來物，誰向浮雲問有無。"]'),
('ef400e06-11af-4c19-8a00-9180be2da291','次韻張僑慶毛維瞻得謝','趙抃','宋','宋诗','song-poetry','','[]','里人迎候巷居稀，未老先休世所奇。',64,'全唐诗/poet.song.19000.json','["里人迎候巷居稀，未老先休世所奇。", "兩頰朱顔公退速，滿頭霜鬢我歸遲。", "優游豈顧千鐘祿，收拾如終一局棋。", "飲食節調資壽祉，願同山下有雷頤。"]'),
('e8f48cd7-b686-43e8-b307-e8b488e2823f','武林冬至日即事','趙抃','宋','宋诗','song-poetry','','[]','況是東吳大有年，晨興佳氣滿平川。',64,'全唐诗/poet.song.19000.json','["況是東吳大有年，晨興佳氣滿平川。", "魯臺紀瑞光諸史，漢殿稱觴慶九天。", "鑾輅肅還禋禮畢，雞竿高揭赦書傳。", "勾萌競達人知否，占得羣陽一日先。"]'),
('a2088c26-011f-41ef-bbb3-4f99e0f7923e','次韻張著作過李虞部舊居','趙抃','宋','宋诗','song-poetry','','[]','美璞藏山寶在沙，急賢飛詔落幽遐。',64,'全唐诗/poet.song.19000.json','["美璞藏山寶在沙，急賢飛詔落幽遐。", "直廬去講先儒業，斸逕空存舊隱家。", "魏闕當時蒙雨露，衡門今日鎖雲霞。", "鳴珂一顧踟躕過，山掩寒林夕照斜。"]'),
('5a1dba51-195c-4b1b-a10f-ee48c5f1ec54','贈講僧遇清','趙抃','宋','宋诗','song-poetry','','[]','松檜成陰夾徑寒，喧卑無路得相關。',64,'全唐诗/poet.song.19000.json','["松檜成陰夾徑寒，喧卑無路得相關。", "因嗟勢利方爲市，故掩庵扉獨占山。", "薄俗性隨紅葉變，上人心與白雲閒。", "慇懃約我休官後，深筑隣齋數往還。"]'),
('81e4f366-79a6-42aa-93ee-4ca52f07959b','次韻毛維瞻白雲莊三詠 掬泉軒','趙抃','宋','宋诗','song-poetry','','[]','好山深處靜開軒，目送孤雲手弄泉。',64,'全唐诗/poet.song.19000.json','["好山深處靜開軒，目送孤雲手弄泉。", "枕石堂無金玉富，濯纓家有子孫賢。", "初尋舊隱逢三伏，已發新吟僅百篇。", "聞說夜分煩暑散，涼飚渾似素秋天。"]'),
('cf2f67b5-3b17-4c98-b736-2a709b5fb9d9','次韻毛維瞻白雲莊三詠 平溪堂','趙抃','宋','宋诗','song-poetry','','[]','亭號休休古退藏，豈如溪上構虛堂。',64,'全唐诗/poet.song.19000.json','["亭號休休古退藏，豈如溪上構虛堂。", "坐邀城市真瀟灑，却謂江湖太渺茫。", "下筆新題無俗事，搘筇野服是家常。", "臨流最有清風快，未見故人心已涼。"]'),
('8293b86c-a772-475d-b381-c4b271247ef6','次韻毛維瞻白雲莊三詠 眺望臺','趙抃','宋','宋诗','song-poetry','','[]','治圃我依浮石灘，筑臺君占白雲山。',64,'全唐诗/poet.song.19000.json','["治圃我依浮石灘，筑臺君占白雲山。", "三秋一日登臨外，千里同風咫尺間。", "峯黛陰晴長黯黯，溜琴朝夕自潺潺。", "休官誰道何曾見，林下如今兩處閒。"]'),
('c2f79407-1f70-4ce9-95af-9d339338ad5a','信筆示諸弟姪子孫','趙抃','宋','宋诗','song-poetry','','[]','進欲安舒退欲恬，要將高行與文兼。',64,'全唐诗/poet.song.19000.json','["進欲安舒退欲恬，要將高行與文兼。", "吾門自昔傳清白，聖世于今重孝廉。", "孔氏性情歸利正，仲舒仁義事摩漸。", "人生試看無聞者，徒爾區區歲月添。"]'),
('6351ef68-a130-45b8-a228-7c62368aff70','寄程汝玉秀才','趙抃','宋','宋诗','song-poetry','','[]','鄉閭推服孝廉名，謝絕辭闈樂太平。',64,'全唐诗/poet.song.19000.json','["鄉閭推服孝廉名，謝絕辭闈樂太平。", "黄卷不忘窮古聖，白頭無倦誨諸生。", "安車未召人爲晚，束帛重來世所榮。", "況有知音賢太守，懇章三度薦遺英。"]'),
('fba90f03-f1d6-4eab-ad89-23051a600de8','次韻梁浹瑞芝','趙抃','宋','宋诗','song-poetry','','[]','聖旦求賢野不遺，如公諸子定逢時。',64,'全唐诗/poet.song.19000.json','["聖旦求賢野不遺，如公諸子定逢時。", "默期苑裏留丹桂，喜向門前獲紫芝。", "香已與蘭盈一室，餌當同術有三枝。", "昔年書牖曾呈瑞，報爲登科眾所知。"]'),
('5c2fb04c-9d20-4ae5-b0ed-e3617e7d9084','十八男屼溫㞦迎于鴈蕩溫守石牧之以詩見寄次韻','趙抃','宋','宋诗','song-poetry','','[]','自諳趨拜力惟艱，柯嶺歸休遠帝寰。',64,'全唐诗/poet.song.19000.json','["自諳趨拜力惟艱，柯嶺歸休遠帝寰。", "抱甕不能師老圃，驅車猶足訪名山。", "魚書入手慇懃後，鴈字排空杳靄間。", "多荷主人期我意，謝公遺跡願躋攀。"]'),
('a57bcd54-f90e-496d-a3eb-a3bad2d6eae9','次韻台州姚舜諧見贈二首  其一','趙抃','宋','宋诗','song-poetry','','[]','解印全吳二載餘，近來人楷事何如。',64,'全唐诗/poet.song.19000.json','["解印全吳二載餘，近來人楷事何如。", "尋真徧賞台山後，假道行觀鴈嶺初。", "把酒幸陪登帢幘，泛舟忻得緩徒車。", "別來早獲魚中素，兩首新詩一紙書。"]'),
('920432d9-6c3d-4907-8a2b-854414f48750','次韻台州姚舜諧見贈二首  其二','趙抃','宋','宋诗','song-poetry','','[]','過婺遊台又倦勤，路旁馳看兩州民。',64,'全唐诗/poet.song.19000.json','["過婺遊台又倦勤，路旁馳看兩州民。", "也知勝處青山舊，自恨來遲白髮新。", "暫憩瀛宮求道侶，載瞻方廣想仁鄰。", "貳車章句猶憐我，爲是雲泉無事人。"]'),
('25d6f3b8-0759-4068-8961-ce240cc515a2','遊鴈蕩將抵溫州寄太守石牧之','趙抃','宋','宋诗','song-poetry','','[]','霜風雙鬢雪鬖鬖，物外尋真頓離凡。',64,'全唐诗/poet.song.19000.json','["霜風雙鬢雪鬖鬖，物外尋真頓離凡。", "子舍若非叨別乘，我車安得到靈巖。", "碧窺秋瀑心同洗，紅嚼山杷口似饞。", "多謝賢侯見招意，數貽嘉詠與珍函。"]'),
('85e0c3b1-2c71-4fd2-a029-530924ff056c','自溫將還衢郡題謝公樓','趙抃','宋','宋诗','song-poetry','','[]','鴈蕩周遊遂此過，永嘉人物竟如何。',64,'全唐诗/poet.song.19000.json','["鴈蕩周遊遂此過，永嘉人物竟如何。", "三賢籍籍風流守，一宿怱怱證道歌。", "城脚千家具舟楫，江心雙塔壓濤波。", "因留子舍欣踰月，歸去事知所得多。"]'),
('83aa2818-4e2b-4321-8a85-167707519716','將還三衢呈溫守石郎中','趙抃','宋','宋诗','song-poetry','','[]','尋山初爲子來迎，乘興隨潮入郡城。',64,'全唐诗/poet.song.19000.json','["尋山初爲子來迎，乘興隨潮入郡城。", "心賞皆如逸老願，禮隆仍盡主翁情。", "綵舟笳鼓雙雙鬧，金地樓臺處處明。", "風物雖嘉難久戀，安車朝夕且西行。"]'),
('524162a1-923b-443d-b830-f20171dd59b9','送鄭琰大夫赴建昌軍','趙抃','宋','宋诗','song-poetry','','[]','三擁朱輪志少酬，忠懷曾不爲身謀。',64,'全唐诗/poet.song.19000.json','["三擁朱輪志少酬，忠懷曾不爲身謀。", "桐江郡政居優課，柯嶺鄉評占上游。", "里彥昔陪公共薦，帝俞今幸我先休。", "分携莫憚炎威盛，到日清風一變秋。"]'),
('0f211494-c226-40f8-befe-9d0ee4034e2e','次毛維瞻溪庵','趙抃','宋','宋诗','song-poetry','','[]','退訪雲山遠世塵，結庵臺上古溪濱。',64,'全唐诗/poet.song.19000.json','["退訪雲山遠世塵，結庵臺上古溪濱。", "圍棊每放爭先手，隱几能安自在身。", "鷗鷺後前如舊物，龜魚游泳不疑人。", "曲肱飲水真賢樂，何用淵明漉酒巾。"]'),
('9d07ffa7-8125-4920-b6fe-cde572170a98','又白雲庵偶題','趙抃','宋','宋诗','song-poetry','','[]','紅塵無跡到山家，留待詩人大筆誇。',64,'全唐诗/poet.song.19000.json','["紅塵無跡到山家，留待詩人大筆誇。", "坐石與僧談翠竹，開樽邀客醉榴花。", "鷗隨釣叟孤舟遠，牛載村童一笠斜。", "占盡神仙瀟灑地，清風明月有誰遮。"]'),
('9938486a-b3a4-422e-b1b0-4a04825cbb3e','湖北運使學士十二弟揚生日','趙抃','宋','宋诗','song-poetry','','[]','原上分飛羨鶺鴒，今遥荆渚昔離青。',64,'全唐诗/poet.song.19000.json','["原上分飛羨鶺鴒，今遥荆渚昔離青。", "誕辰一紀阻良會，慶席百杯新永齡。", "對局每思樵客斧，爇香長奉老人星。", "辛勤五福康寧術，見說時看內景經。"]'),
('ff5cece0-5a6c-44aa-a77f-19fb48c5ddc5','送穆舜賓承議致政還鄉','趙抃','宋','宋诗','song-poetry','','[]','清修平日得無慚，學道勤行肯妄談。',64,'全唐诗/poet.song.19000.json','["清修平日得無慚，學道勤行肯妄談。", "軒冕諠譁公始悟，林泉瀟灑我先諳。", "曾憐避弋雲中鴈，每念纏絲繭裏蠶。", "畫舫西歸時節好，春山如黛水如藍。"]'),
('ec66e48e-3dfc-42d8-ae2d-8ef4dae77c85','送十七姪嶙承事赴任貴溪','趙抃','宋','宋诗','song-poetry','','[]','百里囂繁不易爲，乘時今去是鎡基。',64,'全唐诗/poet.song.19000.json','["百里囂繁不易爲，乘時今去是鎡基。", "直令爾邑成良俗，況自吾家有吏師。", "却扇涼飚驚熱奪，下車和氣覺春熙。", "綵衣迎養雙親志，此樂人間更有誰。"]'),
('48106718-cc99-4d09-a5d6-76f18d9d2ff0','送任浩朝散赴鄱陽景德鎮','趙抃','宋','宋诗','song-poetry','','[]','十年留滯尚爲郎，樂道無愁解到腸。',64,'全唐诗/poet.song.19000.json','["十年留滯尚爲郎，樂道無愁解到腸。", "去路溪山排古嶂，滿囊金玉貯新章。", "休論富貴可求事，況得神仙不死方。", "官罷錢塘好歸矣，濯纓清自有滄浪。"]'),
('1cc7d4eb-d585-4f03-949d-a0119505bba2','送范伯玉奉議赴闕','趙抃','宋','宋诗','song-poetry','','[]','富貴於身有重輕，平生忠鯁世知名。',64,'全唐诗/poet.song.19000.json','["富貴於身有重輕，平生忠鯁世知名。", "不須勇事歸田計，況有常推報國誠。", "通籍官聯分帝念，慶門恩賞作親榮。", "一帆西上瞻天去，九月霜風壯客程。"]'),
('8caec105-0ec7-46aa-b5a8-cff7625252fb','題毛維瞻懶歸閣','趙抃','宋','宋诗','song-poetry','','[]','溪流回合引方池，軒檻前臨面翠微。',64,'全唐诗/poet.song.19000.json','["溪流回合引方池，軒檻前臨面翠微。", "紫陌紅塵行不顧，白雲青嶂坐忘歸。", "方榮即隱誰能繼，未老先休世所稀。", "我昔凌晨登閣會，主翁留散見蟾輝。"]'),
('c9d6d9ff-5446-4ea9-b39e-1888167340a1','生日高齋曉起示諸弟妹子孫','趙抃','宋','宋诗','song-poetry','','[]','榮途四紀歷艱難，宦政天恩許賜還。',64,'全唐诗/poet.song.19000.json','["榮途四紀歷艱難，宦政天恩許賜還。", "曉起焚香清一室，夜來飛雪滿羣山。", "詩筒遠到披郵置，壽斝交行醉席間。", "弟妹五人三百歲，喜吾霜鬢尚朱顔。"]'),
('7f405054-b9e4-4da2-85fb-022b27e61a3c','題濯纓亭','趙抃','宋','宋诗','song-poetry','','[]','靜處高齋晝杜門，溪亭來往間開樽。',64,'全唐诗/poet.song.19000.json','["靜處高齋晝杜門，溪亭來往間開樽。", "釣臺逸老心非傲，浮石仙人跡尚存。", "對岸烟林雙佛寺，隔灘風笛一漁村。", "濯纓豈獨酬吾志，清有滄浪示子孫。"]'),
('40349ca4-56cd-41b1-bd69-e21deef32c7c','題葉坂梁氏南齋','趙抃','宋','宋诗','song-poetry','','[]','我愛黌堂用意精，義方垂訓爲趨庭。',64,'全唐诗/poet.song.19000.json','["我愛黌堂用意精，義方垂訓爲趨庭。", "學攻白玉須成器，教積黄金不似經。", "滿架簡編終歲樂，擁門松竹四時青。", "諸生有遂登榮者，一月光能掩眾星。"]'),
('b00ade61-5f1d-4b8c-b104-295f6518492a','會燕溪亭示同席','趙抃','宋','宋诗','song-poetry','','[]','新構園亭好客過，塵緣都不問如何。',64,'全唐诗/poet.song.19000.json','["新構園亭好客過，塵緣都不問如何。", "愛吟瀟灑封侯句，恥詠滄浪濯足歌。", "莫笑杯盤常藉草，且觀舟楫半隨波。", "子知此樂無涯否，盡是天恩與幸多。"]'),
('ffcdc87f-308c-4da4-9124-4820dde86522','哭康守趙師旦','趙抃','宋','宋诗','song-poetry','','[]','五月炎方祲氣浮，賊鋒殘忍入康州。',64,'全唐诗/poet.song.19000.json','["五月炎方祲氣浮，賊鋒殘忍入康州。", "肯拋孤壘偷生去，誓禦羣蠻竟死休。", "沒世不名賢者恥，長年爲辱古人羞。", "嗟嗟潛叔今何恨，憤血忠魂勁草秋。"]'),
('eabf4903-c6d1-4860-b2ef-11f0df8d799b','寄處州太守徐大夫','趙抃','宋','宋诗','song-poetry','','[]','潛山西畔紫溪邊，林下相逢豈偶然。',64,'全唐诗/poet.song.19000.json','["潛山西畔紫溪邊，林下相逢豈偶然。", "撫掌急於雲裏電，回頭還似火中蓮。", "黄花翠竹年年色，明月清風夜夜天。", "誰謂故人相去遠，好溪長與慎江連。"]'),
('1412b4e8-9f74-4de4-a92d-5a8f17bf0fa5','題真岩寺','趙抃','宋','宋诗','song-poetry','','[]','一炷清香一解顔，幾生修得到林間。',64,'全唐诗/poet.song.19000.json','["一炷清香一解顔，幾生修得到林間。", "朝無事也夕無事，坐看山兮行看山。", "梅玉破香供宴坐，松風奏曲度禪關。", "靜思四海五湖客，雖有黄金無此閒。"]'),
('268c410c-0cf4-4a66-920c-1e9c181cfa95','次韻楊鴻漸察判見贈','趙抃','宋','宋诗','song-poetry','','[]','縣令於是襲漢唐，震雷爲治制封疆。',160,'全唐诗/poet.song.19000.json','["縣令於是襲漢唐，震雷爲治制封疆。", "得人固可恩千室，無狀須憂病一方。", "愚品昔蒙登仕籍，薄材今幸預朝綱。", "但欣孤迹辭丘壑，豈有深謀贊廟堂。", "萬里山川來隴蜀，十分風物類江鄉。", "存心撫俗圖歸正，顧己臨民敢不莊。", "蓮幕似君誠慷慨，蘭言遺我極芬芳。", "自嗟寸善無裨補，更辱長篇盛播揚。", "投李莫嫌遲報贈，解琴終擬效更張。", "若孤朋照宜身愧，冠弁峨峨佩玉蒼。"]'),
('4221e496-27bf-422f-b0f8-b3c3423cdb1e','次韻前人見贈','趙抃','宋','宋诗','song-poetry','','[]','惟公治迹嶠之南，增秩頒金出帝僉。',384,'全唐诗/poet.song.19000.json','["惟公治迹嶠之南，增秩頒金出帝僉。", "蠻獠望風安畛域，城闉興筑賴韜鈐。", "恩行稚耋增和樂，令下姦豪盡伏潛。", "撫俗上寬當寧念，揚風深副遠民瞻。", "潮陽鱷去因誠禱，合浦珠還表性廉。", "五嶺盛傳威德著，九天俄下詔書嚴。", "紫宸入覲輸忠讜，青瑣歸來發滯淹。", "謇謇去爲中國使，皇皇寧許外夷覘。", "河冰日度疑鋪玉，朔雪時逢類撒鹽。", "持節塞垣先正席，過塗溪館盡窮閻。", "光華不辱熙朝命，誹訕因知黠虜憸。", "去路冬迎風若箭，還朝春早月如鐮。", "論勳已出庭臣右，得禮應須史筆添。", "賜對預陳官政致，稱褒親被德音恬。", "天人密語依旒冕，風日微和滿扇簾。", "得請鄉州心且適，暫違黼座義無嫌。", "都門客况千鐘餞，禁掖詩仍二府兼。", "巨艦解維桃浪緊，高樓夾岸柳絲纖。", "經途駐節頻開旆，密宴噴香似展匳。", "會友樽罍醅潑蟻，渡淮詩什硯磨蟾。", "居常志氣惟中立，雖久淹徊肯附炎。", "夜泊每窺漁父火，曉行遥認酒家帘。", "吳江橘柚津偏美，茂苑鱸蓴味正甜。", "上冢朋從空里巷，過家車馬擁門簷。"]'),
('567983fc-9467-4099-a702-12fe8b2ff6da','題馬伏波廟二首  其一','趙抃','宋','宋诗','song-poetry','','[]','壯敵無前老未休，賞功銷得到封侯。',32,'全唐诗/poet.song.19000.json','["壯敵無前老未休，賞功銷得到封侯。", "印歸新息不還葬，似與諸蠻一報仇。"]'),
('aad0ff50-22c0-41b8-b79f-88cba3150a5f','題馬伏波廟二首  其二','趙抃','宋','宋诗','song-poetry','','[]','平生忠勇建殊勳，薏苡疑珠竟不分。',32,'全唐诗/poet.song.19000.json','["平生忠勇建殊勳，薏苡疑珠竟不分。", "光武明如辯讒者，肯教千古負將軍。"]'),
('a4db8ff1-2811-4b51-a508-305737afdb7a','和沈太博見貽','趙抃','宋','宋诗','song-poetry','','[]','待得清明已半春，幕中何許可娛賓。',32,'全唐诗/poet.song.19000.json','["待得清明已半春，幕中何許可娛賓。", "堵觀不是穿楊手，珍重賢侯誨爾頻。"]'),
('ae0f977f-f269-4e35-be5f-38c67eb12fbe','和沈太博會春晚歸','趙抃','宋','宋诗','song-poetry','','[]','未醉樽前未可歸，青春九十日芳菲。',32,'全唐诗/poet.song.19000.json','["未醉樽前未可歸，青春九十日芳菲。", "名園一夜狂風雨，苔上殘花點綠衣。"]'),
('f6ab66a1-72a5-43a1-8b24-82c98fac48ab','何推官見招游嶽麓以郡中事冗弗克偕行口占二絕以謝  其一','趙抃','宋','宋诗','song-poetry','','[]','送客江亭一望間，隔江奇勝有千山。',32,'全唐诗/poet.song.19000.json','["送客江亭一望間，隔江奇勝有千山。", "江頭未必無舟子，自是名韁不暫閒。"]'),
('7e84d46e-d92a-4359-b934-f8a995b95985','何推官見招游嶽麓以郡中事冗弗克偕行口占二絕以謝  其二','趙抃','宋','宋诗','song-poetry','','[]','麓苑崟岑對橘洲，山如屏嶂水清流。',32,'全唐诗/poet.song.19000.json','["麓苑崟岑對橘洲，山如屏嶂水清流。", "誰能向此孤尋勝，案牒裝懷不自由。"]'),
('3f075364-925a-4e05-9cb1-10b9dd288550','和沈太博小圃偶作二首  其一','趙抃','宋','宋诗','song-poetry','','[]','名園雨後百花繁，人倚危樓十二蘭。',32,'全唐诗/poet.song.19000.json','["名園雨後百花繁，人倚危樓十二蘭。", "園裏芳菲樓上客，一般情緒怕春寒。"]'),
('7c0d1718-8850-4417-96be-4c7f639d2f8e','和沈太博小圃偶作二首  其二','趙抃','宋','宋诗','song-poetry','','[]','日烘薄霧開柔陌，風罥遊絲著柳條。',32,'全唐诗/poet.song.19000.json','["日烘薄霧開柔陌，風罥遊絲著柳條。", "語燕啼鶯自撩亂，驚人殘夢是春朝。"]'),
('43337dc6-3a43-4799-be5d-9119c4434356','不與祠嶽再呈通判沈侯','趙抃','宋','宋诗','song-poetry','','[]','蔡侯不是不尋仙，俗骨由來欠玉鞭。',32,'全唐诗/poet.song.19000.json','["蔡侯不是不尋仙，俗骨由來欠玉鞭。", "待得麻姑重前約，只應瀛海已桑田。"]'),
('305ff726-037f-49e7-80d0-35fd9bca83e3','次韻見和','趙抃','宋','宋诗','song-poetry','','[]','古祠靈鎮會真仙，一夕春霖激電鞭。',32,'全唐诗/poet.song.19000.json','["古祠靈鎮會真仙，一夕春霖激電鞭。", "待得歸航已新暑，小荷江上綠田田。"]'),
('216751aa-9390-43aa-9b9c-4627841565f9','代寄劉信臣','趙抃','宋','宋诗','song-poetry','','[]','無憀情緒滿眉頭，去後方知有別愁。',32,'全唐诗/poet.song.19000.json','["無憀情緒滿眉頭，去後方知有別愁。", "翠幰雕鞍杳何所，相望重上夕陽樓。"]'),
('b001bacf-ffae-40e0-8b69-d4771a501378','和前人見寄  其一','趙抃','宋','宋诗','song-poetry','','[]','此去山重水復重，登臨無復嘆途窮。',32,'全唐诗/poet.song.19000.json','["此去山重水復重，登臨無復嘆途窮。", "應將往事閒追憶，疑是邯鄲夢枕中。"]'),
('78ace6e5-9e80-4a7c-9e0b-d143d7f23fc9','和前人見寄  其二','趙抃','宋','宋诗','song-poetry','','[]','下馬郵亭夕照天，獨憑離緒問蓍圓。',32,'全唐诗/poet.song.19000.json','["下馬郵亭夕照天，獨憑離緒問蓍圓。", "故人此去無多地，何事銷魂重黯然。"]'),
('e324e2be-68be-40b0-886e-eab15f7d1eb4','和何節推重九','趙抃','宋','宋诗','song-poetry','','[]','喜陪佳客上高臺，醉策驊騮薄暮回。',32,'全唐诗/poet.song.19000.json','["喜陪佳客上高臺，醉策驊騮薄暮回。", "黄菊滿頭堪自笑，朱顔何必爲人開。"]'),
('86ebffb9-ba1b-49bf-9944-b1107298de1a','寄里中親友','趙抃','宋','宋诗','song-poetry','','[]','上盡危梯望社榆，亂山千疊隔吾廬。',32,'全唐诗/poet.song.19000.json','["上盡危梯望社榆，亂山千疊隔吾廬。", "四方盡是男兒志，敢嘆離羣與索居。"]'),
('c7c986f4-6097-4429-9105-d360ec24f16b','雨中見花戲呈伯庸秋曹','趙抃','宋','宋诗','song-poetry','','[]','臉紅消盡淚闌干，似向人前欲訴難。',32,'全唐诗/poet.song.19000.json','["臉紅消盡淚闌干，似向人前欲訴難。", "若是東君與爲主，肯教風雨盡摧殘。"]'),
('572cc615-9940-4cbd-af4b-93851a859d22','和勉三兄','趙抃','宋','宋诗','song-poetry','','[]','求賢在昔常推轂，訪道當年亦顧廬。',32,'全唐诗/poet.song.19000.json','["求賢在昔常推轂，訪道當年亦顧廬。", "聖旦光華今籲俊，長卿無苦歎貧居。"]'),
