('21da2aa1-eeb0-4676-a639-fb4f66557f4c','九峰巖','趙抃','宋','宋诗','song-poetry','','[]','龍丘石室人難繼，安正書堂世莫登。',32,'全唐诗/poet.song.19000.json','["龍丘石室人難繼，安正書堂世莫登。", "但見烟蘿最高處，九峯排列一層層。"]'),
('cf6d4482-350f-4c81-94b6-f723154d832f','引流聯句','趙抃','宋','宋诗','song-poetry','','[]','別派從江垠，邀流入農畎。',290,'全唐诗/poet.song.19000.json','["別派從江垠，邀流入農畎。", "淙淙來源深，㶁㶁度溝淺。", "園穿蕭艾芟，塹斷荆剪。", "疏功浹長長，溉利和步遠。", "田觀疑澤潴，坎聽類瓴建。", "北溟歸鑿池，幽岳漾裝巘。", "瀉埤紋湍駛，回灣波細轉。", "過竇石眼窺，經虛土口吮。", "浮行值落葉，浸長逢生蘚。", "孤鶴眼怪覘，纖魚鬣跳展。", "中沈無穢淤，底浄有紋{石霝}。", "映葦色莫分，喧琴韻難辨。", "增霖人鬧蛙，涵月夜驚犬。", "侵篁鞭起萌，逼水低垂菌。", "憐黄澆菊籬，惜紫沃蘭畹。", "吏咨窯甓甃，童戲芒車卷。", "灌携令手勞，漱掬致腰俛。", "庭秋臨加涼，軒夏尚消烜。", "我矜近濟能，僮賀遥汲免。", "貯戺埋巨甔，歸厨架修筧。", "供掏飯盎糧，給澳羹鼎臠。", "調藥修臼餌，煎茶試羅荈。", "坐客頻泛觴，蹲兒屢洗硯。", "聆寒心脫煩，挹冷酒除湎。"]'),
('68fd6349-ee10-48ec-b016-d12d6ca114e7','遊武夷山','趙抃','宋','宋诗','song-poetry','','[]','武夷之山千萬峰，溪水詰曲流其中。',160,'全唐诗/poet.song.19000.json','["武夷之山千萬峰，溪水詰曲流其中。", "噴雲涌雪可□楫，一櫂無覽仙人蹤。", "白鶴昂昂寫峭壁，雕虎長□□清風。", "懸崖蛻骨造化外，絕壑駕船神鬼功。", "寒岩鼎竈失雞犬，盤石松椿騰蛟龍。", "行行自喜浣塵俗，蕭散玉羽超樊籠。", "當年此日是高會，左仙右仙曲未終。", "紫星飄然天上去，曾孫虹橋路已窮。", "我生丹心涵太沖，欲脫韁鎖追鴻蒙。", "上邀軒轅宴玄圃，手摘日月相遊從。"]'),
('c6e68886-58c4-4a2e-8041-a879e9a914ae','青州聞雷','趙抃','宋','宋诗','song-poetry','','[]','退食公堂自憑几，不動不摇心似水。',64,'全唐诗/poet.song.19000.json','["退食公堂自憑几，不動不摇心似水。", "霹靂一聲透頂門，驚起從前自家底。", "舉頭蒼蒼喜復喜，剎剎塵塵無不是。", "中下之人不得聞，妙用神通而已矣。"]'),
('7be45690-5deb-49da-8d16-94663d52ffe9','題高齋','趙抃','宋','宋诗','song-poetry','','[]','腰佩黄金已退藏，個中消息也尋常。',32,'全唐诗/poet.song.19000.json','["腰佩黄金已退藏，個中消息也尋常。", "時人要識高齋老，只是柯村趙四郎。"]'),
('83fb0da6-a0a2-4c9a-b6c4-4ca8739f143a','歙硯詩','趙抃','宋','宋诗','song-poetry','','[]','君家歙溪邊，自採歙溪石。',48,'全唐诗/poet.song.19000.json','["君家歙溪邊，自採歙溪石。", "刓磨清泉根，刳斬紫虬脊。", "羅紋洗瑩緻，蛾眉隱纖直。", "叩聲清而長，觸手生汗液。"]'),
('db425267-6d6b-4131-a880-a7a3718d7461','應夢游','趙抃','宋','宋诗','song-poetry','','[]','龍穴藏身穩，泉源撫掌清。',48,'全唐诗/poet.song.19000.json','["龍穴藏身穩，泉源撫掌清。", "紅塵人絕慮，白日世長生。", "我分諳沖寂，誰能顧利名。", "夢中休指笑，又作洞霄行。"]'),
('9e28651f-9aee-4f0e-8d67-b1ece36cb747','趙佗疑冢','方信孺','宋','宋诗','song-poetry','','[]','漫說曹瞞七十餘，老佗疑冢更模糊。',32,'全唐诗/poet.song.190000.json','["漫說曹瞞七十餘，老佗疑冢更模糊。", "不知禹葬會稽處，也有纍纍如許無。"]'),
('69de97d0-e520-4377-bd8e-4e8df59ea950','寶象峰勝因寺','方信孺','宋','宋诗','song-poetry','','[]','鴻濛誰闢此山川，龍象新開二十年。',32,'全唐诗/poet.song.190000.json','["鴻濛誰闢此山川，龍象新開二十年。", "最恨東坡早仙去，只教蒲澗入詩篇。"]'),
('796ab657-e81f-441e-8a07-c190f3d8aed6','虎跑泉','方信孺','宋','宋诗','song-poetry','','[]','破寺高僧夜不眠，一聲猛虎月明天。',32,'全唐诗/poet.song.190000.json','["破寺高僧夜不眠，一聲猛虎月明天。", "起來難覓新蹄跡，半滴空餘石罅泉。"]'),
('bd5196ce-09d5-4e87-a70a-c517103f826b','動石','方信孺','宋','宋诗','song-poetry','','[]','山中塊石老僧言，一叱應知轉法輪。',32,'全唐诗/poet.song.190000.json','["山中塊石老僧言，一叱應知轉法輪。", "元是世人心自動，請將消息問風幡。"]'),
('b6bebf6a-a326-4622-b057-d31088bfb6a8','白雲洞','方信孺','宋','宋诗','song-poetry','','[]','金剎憑陵尺五天，勝遊何必羨登仙。',32,'全唐诗/poet.song.190000.json','["金剎憑陵尺五天，勝遊何必羨登仙。", "安期想見身千億，汗漫人間若箇邊。"]'),
('8246e972-7f70-4ca0-bf71-5345e250d826','三教殿','方信孺','宋','宋诗','song-poetry','','[]','大道茫茫鼎峙分，箇中誰爲破重籓。',32,'全唐诗/poet.song.190000.json','["大道茫茫鼎峙分，箇中誰爲破重籓。", "須知問禮當時地，不必西方兩足尊。"]'),
('393682fa-e7dc-4db8-b277-c281142f2339','鶴舒臺','方信孺','宋','宋诗','song-poetry','','[]','危臺老石寄層巔，鶴駕逢迎不記年。',32,'全唐诗/poet.song.190000.json','["危臺老石寄層巔，鶴駕逢迎不記年。", "今日歸來應一笑，山川城郭故依然。"]'),
('20281481-cee1-41b9-ac8e-3536ffced29b','大小水簾洞','方信孺','宋','宋诗','song-poetry','','[]','碧澗東西春水添，四時疏雨落晴檐。',32,'全唐诗/poet.song.190000.json','["碧澗東西春水添，四時疏雨落晴檐。", "珠宮貝闕無尋處，空見重重排玉簾。"]'),
('07425904-d6ed-4835-ba75-39c6a789f36f','虎頭巖','方信孺','宋','宋诗','song-poetry','','[]','絕壁空巖踞虎頭，鳥飛不渡野猿愁。',32,'全唐诗/poet.song.190000.json','["絕壁空巖踞虎頭，鳥飛不渡野猿愁。", "人間有此真奇境，便好乘風訪十洲。"]'),
('1540d56d-0c8d-4c04-8471-7702d3e0a88c','景泰山七仙寺','方信孺','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','老衲誅茅昔小留，七仙陰爲護巖幽。',32,'全唐诗/poet.song.190000.json','["老衲誅茅昔小留，七仙陰爲護巖幽。", "不將石履呈奇怪，安得西歸好話頭。"]'),
('68b43643-88a8-45c8-a6ff-8ad06ad84b5c','卓錫泉','方信孺','宋','宋诗','song-poetry','','[]','泉源無處不流通，隠顯何關卓錫功。',32,'全唐诗/poet.song.190000.json','["泉源無處不流通，隠顯何關卓錫功。", "欲識海潮連地脈，祗今雙蟹出泉中。"]'),
('47445440-d6f8-4241-b6c0-d97c4f06097c','順庵','方信孺','宋','宋诗','song-poetry','','[]','詞人自結一間茅，天上宸奎舞瘦蛟。',32,'全唐诗/poet.song.190000.json','["詞人自結一間茅，天上宸奎舞瘦蛟。", "見說鬼神猶衛護，瑞光前夜起山坳。"]'),
('e7166276-8ad0-4601-8dec-c90219f66b75','陵山','方信孺','宋','宋诗','song-poetry','','[]','龜趺無處問行蹤，惆悵連江荔子紅。',32,'全唐诗/poet.song.190000.json','["龜趺無處問行蹤，惆悵連江荔子紅。", "鐵鑄崔嵬真大錯，驪山銅柱久成空。"]'),
('df2df602-0d50-408c-bd3d-3200ef4d6fe2','馬鞍山','方信孺','宋','宋诗','song-poetry','','[]','塹山堙谷浪爲謀，餘力猶窮嶺外洲。',32,'全唐诗/poet.song.190000.json','["塹山堙谷浪爲謀，餘力猶窮嶺外洲。", "見說揭竿從壠上，祖龍當日漫東遊。"]'),
('39a141be-61f4-40a1-b9e7-67795adf54a2','琵琶洲','方信孺','宋','宋诗','song-poetry','','[]','髣髴琵琶海上洲，年年常與水沉浮。',32,'全唐诗/poet.song.190000.json','["髣髴琵琶海上洲，年年常與水沉浮。", "客船昨夜西風起，應有江頭商婦愁。"]'),
('c1b7d717-c94b-4e44-aa49-0b331399b533','相對岡','方信孺','宋','宋诗','song-poetry','','[]','海門高並兩峰寒，大艑輕帆自往還。',32,'全唐诗/poet.song.190000.json','["海門高並兩峰寒，大艑輕帆自往還。", "安得百靈移一島，却教塵世看三山。"]'),
('b9ddc773-daa7-4d3d-9560-85f44e9c5993','南海廟','方信孺','宋','宋诗','song-poetry','','[]','官闕參差海上開，吐吞波浪起風雷。',32,'全唐诗/poet.song.190000.json','["官闕參差海上開，吐吞波浪起風雷。", "英靈萬古無宗社，奚醜區區何足摧。"]'),
('7130480f-60a9-4dba-838c-6c4dfa3cef12','浴日亭','方信孺','宋','宋诗','song-poetry','','[]','亭倚蓬萊幾許高，下臨無地有驚濤。',32,'全唐诗/poet.song.190000.json','["亭倚蓬萊幾許高，下臨無地有驚濤。", "坡仙想得江山助，八語端爲天下豪。"]'),
('3ffde517-9716-46fa-ba0a-4824054a14dd','銅鼓','方信孺','宋','宋诗','song-poetry','','[]','石鼓嵯峨尚有文，舊題銅鼓更無人。',32,'全唐诗/poet.song.190000.json','["石鼓嵯峨尚有文，舊題銅鼓更無人。", "寶釵寂寞蠻花老，空和楚歌迎送神。"]'),
('241dc55e-4a55-473e-a7bf-d58114fbf989','波羅蜜果','方信孺','宋','宋诗','song-poetry','','[]','纍纍圓實大於瓜，想見移根博望槎。',32,'全唐诗/poet.song.190000.json','["纍纍圓實大於瓜，想見移根博望槎。", "三百餘篇誰識此，世間寧復有張華。"]'),
('767d0f4f-89a5-4d88-b7d7-ce33c7a55005','王登洲','方信孺','宋','宋诗','song-poetry','','[]','四瀆初分有物尸，天開地闢共爲期。',32,'全唐诗/poet.song.190000.json','["四瀆初分有物尸，天開地闢共爲期。", "齊東野語真堪笑，請誦昌黎十丈碑。"]'),
('d5468bc0-99e4-49a7-a7fd-49d3f0352b6f','靈化寺','方信孺','宋','宋诗','song-poetry','','[]','黄木灣前一畝宮，廟靈規地古來雄。',32,'全唐诗/poet.song.190000.json','["黄木灣前一畝宮，廟靈規地古來雄。", "江頭不見風雷惡，多謝禪師受戒功。"]'),
('2ca03b7d-6e13-42a2-a963-c5f776c3f927','走珠石','方信孺','宋','宋诗','song-poetry','','[]','底事明珠解去來，當時合浦已堪猜。',32,'全唐诗/poet.song.190000.json','["底事明珠解去來，當時合浦已堪猜。", "賈胡不省何年事，老石江頭空綠苔。"]'),
('5eafe5ed-8b93-494b-ab3f-af6961ae1471','盧循河南故城','方信孺','宋','宋诗','song-poetry','','[]','蛙據方州妄自尊，沈郎百萬若雲屯。',32,'全唐诗/poet.song.190000.json','["蛙據方州妄自尊，沈郎百萬若雲屯。", "歸舟無路尋巢穴，空有盧亭舊子孫。"]'),
('248f8803-2fb1-40a8-bdd1-fac6d679ae68','大通寺','方信孺','宋','宋诗','song-poetry','','[]','老木槎牙欲擘雲，門前流水我知津。',32,'全唐诗/poet.song.190000.json','["老木槎牙欲擘雲，門前流水我知津。", "過江一雨如盆瀉，競禮真如不動身。"]'),
('0ce8bdc8-be55-4235-a4ab-ab8556df8563','抱旂山','方信孺','宋','宋诗','song-poetry','','[]','面勢翩翩天外山，彩旂常在翠雲間。',32,'全唐诗/poet.song.190000.json','["面勢翩翩天外山，彩旂常在翠雲間。", "太平官府無公事，儘好高牙相對閒。"]'),
('b84fc129-1163-4b3e-b1dd-53f56b48de5f','花山寺','方信孺','宋','宋诗','song-poetry','','[]','萬花春老正紅酣，不是叢林優鉢曇。',32,'全唐诗/poet.song.190000.json','["萬花春老正紅酣，不是叢林優鉢曇。", "山下女郎來問訊，未饒萱草解宜男。"]'),
('2869169a-e565-4597-8d3b-44d0dbbd3f7d','黄巢磯','方信孺','宋','宋诗','song-poetry','','[]','天下縱橫轍迹環，舳艫不許度前灣。',32,'全唐诗/poet.song.190000.json','["天下縱橫轍迹環，舳艫不許度前灣。", "江神少爲摧凶焰，要使留金六祖山。"]'),
('2751fe1c-0080-4967-8ebf-4f4fb013fc34','金芝巖','方信孺','宋','宋诗','song-poetry','','[]','碧落三洲天下奇，仙城誰復識金芝。',32,'全唐诗/poet.song.190000.json','["碧落三洲天下奇，仙城誰復識金芝。", "可憐隔斷黄茅路，不得騷人賦一詩。"]'),
('2322aebb-68f8-415e-9090-06ca42e7d9a2','清遠峽','方信孺','宋','宋诗','song-poetry','','[]','崑崙截竹事空傳，不見春潮送客船。',32,'全唐诗/poet.song.190000.json','["崑崙截竹事空傳，不見春潮送客船。", "只似蜀江江上路，兩山中峽手巾天。"]'),
('9dc7996f-b9b8-4942-9f59-05bb6a9e101f','峽山廣慶寺','方信孺','宋','宋诗','song-poetry','','[]','韋郎故地久蕭條，只有泉聲響夜潮。',32,'全唐诗/poet.song.190000.json','["韋郎故地久蕭條，只有泉聲響夜潮。", "行客往來回首地，玉環無處覓嬌嬈。"]'),
('eeeb0da7-41dc-4234-b115-52cfa6327bac','飛來殿','方信孺','宋','宋诗','song-poetry','','[]','嵯峨古殿記飛來，千古傳聞亦怪哉。',32,'全唐诗/poet.song.190000.json','["嵯峨古殿記飛來，千古傳聞亦怪哉。", "龍象漸隨塵土化，却疑神物欲飛回。"]'),
('eadd5b1e-98a9-40ae-b3d0-99a5a02e95e8','達磨石','方信孺','宋','宋诗','song-poetry','','[]','葱嶺初無一字傳，名山到處即爲禪。',32,'全唐诗/poet.song.190000.json','["葱嶺初無一字傳，名山到處即爲禪。", "只今石上留公案，面壁何須更九年。"]'),
('d4eaa1c0-4fba-4741-ac97-34630269da0e','釣臺','方信孺','宋','宋诗','song-poetry','','[]','釣得神魚金作鱗，廢臺百尺漫嶙峋。',32,'全唐诗/poet.song.190000.json','["釣得神魚金作鱗，廢臺百尺漫嶙峋。", "絲綸不入非熊夢，當日何人老渭濱。"]'),
('6398f342-3992-414d-9a51-c8a2419d657f','和光洞','方信孺','宋','宋诗','song-poetry','','[]','和光深洞隠昌期，門鎖煙蘿不可窺。',32,'全唐诗/poet.song.190000.json','["和光深洞隠昌期，門鎖煙蘿不可窺。", "欲問榴花好消息，只今難問舊題詩。"]'),
('f95f9d0e-943f-41bb-bd6d-63b1dfb7893c','沉犀潭','方信孺','宋','宋诗','song-poetry','','[]','西來異獸路應迷，金鎖何年落此溪。',32,'全唐诗/poet.song.190000.json','["西來異獸路應迷，金鎖何年落此溪。", "不比李侯心似水，歸舟自擲石門西。"]'),
('87e5c3fd-25f6-4226-a450-cc2f5dc801c6','龍磨角石','方信孺','宋','宋诗','song-poetry','','[]','舊說神龍水底蟠，何年電掣與雷奔。',32,'全唐诗/poet.song.190000.json','["舊說神龍水底蟠，何年電掣與雷奔。", "至今舟子相呼喚，猶指江邊石上痕。"]'),
('edde314c-b275-4266-b800-405f77562a88','老人松','方信孺','宋','宋诗','song-poetry','','[]','上古輪囷說壽樗，何人玉斧劚霜腴。',32,'全唐诗/poet.song.190000.json','["上古輪囷說壽樗，何人玉斧劚霜腴。", "有知定見非凡物，盍作堂堂五大夫。"]'),
('cd84f1f7-8a35-4480-89bd-6451c288bc5b','資福寺羅漢閣','方信孺','宋','宋诗','song-poetry','','[]','千柱依然跨寶坊，庭前柏子久荒凉。',32,'全唐诗/poet.song.190000.json','["千柱依然跨寶坊，庭前柏子久荒凉。", "明珠白璧無人識，頼有斯文萬丈光。"]'),
('9cd00f18-0c00-4833-9c64-fb1a11019fea','鳳皇臺','方信孺','宋','宋诗','song-poetry','','[]','鳳去臺空歲月更，百年陳迹埽榛荆。',32,'全唐诗/poet.song.190000.json','["鳳去臺空歲月更，百年陳迹埽榛荆。", "清時已慶三登瑞，盍向朝陽更一鳴。"]'),
('c68acbcb-dca4-4e74-a647-226af05af64a','會仙觀','方信孺','宋','宋诗','song-poetry','','[]','綽約長眉海上仙，久餐雲母學長年。',32,'全唐诗/poet.song.190000.json','["綽約長眉海上仙，久餐雲母學長年。", "山中丹井今無恙，爲弔南充謝自然。"]'),
('466c9701-a39e-45ea-a7e2-3d3e9ad68c78','龍窟','方信孺','宋','宋诗','song-poetry','','[]','變化靈蹤亦可疑，玲瓏數穴似仇池。',32,'全唐诗/poet.song.190000.json','["變化靈蹤亦可疑，玲瓏數穴似仇池。", "滄溟咫尺不歸去，安得神龍如許癡。"]'),
('00e81089-b951-4cab-a7c9-67f1b69c0b8b','金牛山','方信孺','宋','宋诗','song-poetry','','[]','金牛去後久淒涼，好景乾坤亦祕藏。',32,'全唐诗/poet.song.190000.json','["金牛去後久淒涼，好景乾坤亦祕藏。", "滄海無窮月無盡，從今收拾入詩囊。"]'),
('4ace917e-2b47-407a-a1c4-28ce2a1ccc57','仙湧山','方信孺','宋','宋诗','song-poetry','','[]','龍伯何年釣巨鰲，兩峰漂蕩入洪濤。',32,'全唐诗/poet.song.190000.json','["龍伯何年釣巨鰲，兩峰漂蕩入洪濤。", "人間靈迹無尋處，仙湧羅浮相對高。"]'),
('ddac5900-56e6-45f3-b74a-97deecf87b16','媚川都','方信孺','宋','宋诗','song-poetry','','[]','漭漭愁雲弔媚川，蚌胎光彩夜連天。',32,'全唐诗/poet.song.190000.json','["漭漭愁雲弔媚川，蚌胎光彩夜連天。", "幽魂水底猶相泣，恨不生逢開寶年。"]'),
('780ada3b-6840-43bf-bab4-598d832a8602','劉氏山','方信孺','宋','宋诗','song-poetry','','[]','一徑縈紆夾粉牆，嚮來臺館化僧房。',32,'全唐诗/poet.song.190000.json','["一徑縈紆夾粉牆，嚮來臺館化僧房。", "周遭老木依然在，曾見劉家僞帝王。"]'),
('6ba6abc5-fc79-40e3-bee1-fc078ff5dfc0','虞山','方信孺','宋','宋诗','song-poetry','','[]','西風攪桂樹，落日明楓林。',132,'全唐诗/poet.song.190000.json','["西風攪桂樹，落日明楓林。", "遊子懷歸期，予悲渺登臨。", "虞山一何高，湘水一何深。", "英皇僅枯冢，寂寞薰兮琴。", "我欲奏古曲，俗耳更哇淫。", "古器不可見，聊作相思吟。", "相思長相思，相思無古今。", "一歌衆鳥聽，再歌萬籟喑。", "推手君勿歌，有酒且孤斟。", "落落此時意，寥寥千載心。", "五絃毋庸絕，四海誰知音。"]'),
('da2b229a-cba3-4024-a7ec-086e5e776536','龍隠巖','方信孺','宋','宋诗','song-poetry','','[]','石門元不鎖，巖屋本無基。',48,'全唐诗/poet.song.190000.json','["石門元不鎖，巖屋本無基。", "九夏花猶在，千年樹倒垂。", "僧閒方定起，客到每歸遲。", "甚欲眠蓮葉，沿崖讀斷碑。"]'),
('c2d98fc7-8e58-41d2-935e-579785071b0c','灕山雲崖軒','方信孺','宋','宋诗','song-poetry','','[]','不用窮探費杖藜，隠然林壑挾城陴。',64,'全唐诗/poet.song.190000.json','["不用窮探費杖藜，隠然林壑挾城陴。", "曾遵月洞千岩上，更著雲崖一段奇。", "拂拭軒窗容俎豆，發揮泉石借聲詩。", "瞿曇頗似知人意，已約梅花带雪移。"]'),
('dd743c1a-2183-4be0-8ed5-ad0a8f13098d','西山鑿池種白蓮作','方信孺','宋','宋诗','song-poetry','','[]','池開新白遍天涯，未許東風擅一家。',64,'全唐诗/poet.song.190000.json','["池開新白遍天涯，未許東風擅一家。", "蒼桂叢中蒼桂樹，碧蓮峰裏碧蓮花。", "波光分破湖千頃，雲影斜飛水一漥。", "待著欄干橫淺綠，浮萍開處見魚蝦。"]'),
('dbbc5dfd-f1cc-4ce3-9a65-24631ed7ef25','咏西山海棠','方信孺','宋','宋诗','song-poetry','','[]','真珠幾顆最深紅，點綴偏方造化工。',64,'全唐诗/poet.song.190000.json','["真珠幾顆最深紅，點綴偏方造化工。", "好事何年移蜀種，美人清曉出吳宮。", "妖嬈能得幾時賞，零落纔消一夜風。", "自有生香人不識，繡衾全覆錦熏籠。"]'),
('55f19780-751d-4a2c-b188-74c77198156b','清秀山','方信孺','宋','宋诗','song-poetry','','[]','尋徧洞天三十六，蒼靈獨閉此巖扉。',64,'全唐诗/poet.song.190000.json','["尋徧洞天三十六，蒼靈獨閉此巖扉。", "旋除野草開新徑，遮莫寒藤刺客衣。", "歲月偶同題壁字，烟霞似不放人歸。", "把茅欲作開山主，已落瞿曇第二機。"]'),
('f105bd01-c620-4669-b7b3-9dbefddb561e','還珠洞','方信孺','宋','宋诗','song-poetry','','[]','歸舟多載小江春，重訪東巖舊屐痕。',64,'全唐诗/poet.song.190000.json','["歸舟多載小江春，重訪東巖舊屐痕。", "插水峭崖猶有路，垂天怪石本無根。", "金華仙伯真知己，薏苡將軍足斷魂。", "安得北山公可作，倩渠移取向家園。"]'),
('70c236d1-e008-4f93-a556-9b95410479c0','題龍隠巖  其一','方信孺','宋','宋诗','song-poetry','','[]','愛山那惜走千回，生怕前驅後騎催。',64,'全唐诗/poet.song.190000.json','["愛山那惜走千回，生怕前驅後騎催。", "石上參差鱗甲動，眼中在處畫圖開。", "驂鸞未辦乘風去，浮鷁何妨載雨來。", "人事百年俱變滅，祇應題字不塵埃。"]'),
('133f459d-1450-4aef-ab6c-72ee6849a32d','題龍隠巖  其二','方信孺','宋','宋诗','song-poetry','','[]','雨脚初收魚尾霞，滿溪流水半溪花。',64,'全唐诗/poet.song.190000.json','["雨脚初收魚尾霞，滿溪流水半溪花。", "尋源曾識武陵洞，泛宅如浮苕水家。", "但得嵌空元有路，何如峭絕不容車。", "道人辛苦經雲水，成塔從來是劫沙。"]'),
('5918f244-4557-4cbb-9d3d-d6f81c968c51','慶遠龍隠洞','方信孺','宋','宋诗','song-poetry','','[]','南山山北北山南，一洞中分路口三。',64,'全唐诗/poet.song.190000.json','["南山山北北山南，一洞中分路口三。", "飛鶴叫雲聲自遠，懶龍慳雨睡方酣。", "襄公淡墨留蒼壁，太史高風拂翠嵐。", "百尺岩前清絕處，道人先我著茅菴。"]'),
('bd46811a-0588-411a-bacb-b79aee27ca89','龍隠巖','方信孺','宋','宋诗','song-poetry','','[]','曾榜武夷九曲，何如桂嶺七星。',28,'全唐诗/poet.song.190000.json','["曾榜武夷九曲，何如桂嶺七星。", "水石小容螭隠，烟雲長带龍腥。"]'),
('cd0f2764-9d09-4691-b5cc-05a96541cf3d','題龍隠巖','方信孺','宋','宋诗','song-poetry','','[]','春波飽微淥，斗柄函空明。',204,'全唐诗/poet.song.190000.json','["春波飽微淥，斗柄函空明。", "方舟貫巖腹，鵝鸛相酬鳴。", "仰窺穹窿頂，宛轉百怪呈。", "僅餘鱗甲碎，不見頭角獰。", "下闖清泠淵，演迤萬頃澄。", "但同魚鳥參，勿遣蛟龍驚。", "抉苔撫奇篆，倚棹看題名。", "三將標殊勳，自與山不傾。", "誰歟贅小築，正恐山靈嗔。", "南澗更幽絕，仙佛依崢嶸。", "太虛可爲室，豈復資欒楹。", "乳泉助茗椀，中有冰雪清。", "何須驂鸞去，此即白玉京。", "鼎來不速客，抱琴忽逢迎。", "愛此無絃曲，巖溜同一聲。", "爲君洗塵耳，喚我詩魂醒。", "祗愁白衣至，好句亡繇成。"]'),
('0fd48571-9c9f-49d8-93d6-ea76236d9fa2','題萬歲寺','方信孺','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','磊磊洞庭石，渺渺蒼梧雲。',48,'全唐诗/poet.song.190000.json','["磊磊洞庭石，渺渺蒼梧雲。", "客行離騷國，長歌酹湘君。", "湘君不可見，古廟藏江氛。", "空壇頗亡恙，誰爲真將軍。"]'),
('501a605f-97d1-4cca-a5b8-ade671595ff6','凌丹亭','方信孺','宋','宋诗','song-poetry','','[]','風馭來三峽，雲章下九天。',48,'全唐诗/poet.song.190000.json','["風馭來三峽，雲章下九天。", "名山開窟宅，飛宇納光躔。", "未見烟霞約，聊將歲月鎸。", "神游誰復識，空誦白雲篇。"]'),
('95d62837-f52e-47a3-8393-e8fbb24fed48','題學宮壁','方信孺','宋','宋诗','song-poetry','','[]','淮水原同泗水流，東家便是孔家丘。',64,'全唐诗/poet.song.190000.json','["淮水原同泗水流，東家便是孔家丘。", "千年源委詩書澤，一日風雷變化秋。", "劫火不能移突兀，子衿正合勉藏修。", "相魁自昔稱吳蔡，衣鉢相傳未肯休。"]'),
('cb493134-f7e0-4dce-a643-b7b017f7cdaa','贈寫真求贊者  其一','方信孺','宋','宋诗','song-poetry','','[]','向□瓦礫憐□□，頗欲丹青結勝緣。',64,'全唐诗/poet.song.190000.json','["向□瓦礫憐□□，頗欲丹青結勝緣。", "大似欠渠佳句在，不妨時復繫漁船。", "城東秀山不知數，城西新湖政自佳。", "一春車馬欠行迹，萬斛塵埃裝我□。"]'),
('ef492852-cf99-4b49-a39e-c5af33c19b9d','贈寫真求贊者  其二','方信孺','宋','宋诗','song-poetry','','[]','行樂頓因人事懶，坐忘常覺世緣輕。',48,'全唐诗/poet.song.190000.json','["行樂頓因人事懶，坐忘常覺世緣輕。", "琴清臨水容魚聽，篁暖當筵學鳳鳴。", "便道登僊豈欺我，芙蓉花繞桂林城。"]'),
('13c4384d-d959-4e87-a6b9-065b30f8b24d','贈寫真求贊者  其三','方信孺','宋','宋诗','song-poetry','','[]','十年紅紫□，容易怨春園。',24,'全唐诗/poet.song.190000.json','["十年紅紫□，容易怨春園。", "不向瓶中見，還從檐上看。"]'),
('d423834e-7d6d-4a79-b22e-196779675480','義寧華岩洞和純陽真人  其一','方信孺','宋','宋诗','song-poetry','','[]','巖前綠水無人渡，洞裏碧桃花正開。',32,'全唐诗/poet.song.190000.json','["巖前綠水無人渡，洞裏碧桃花正開。", "東望蓬瀛三萬里，等閒飛去等閒來。"]'),
('87e74ee9-5e08-41f7-b464-89e396985fcf','義寧華岩洞和純陽真人  其二','方信孺','宋','宋诗','song-poetry','','[]','跨鶴曾來不記年，洞中流水綠依然。',32,'全唐诗/poet.song.190000.json','["跨鶴曾來不記年，洞中流水綠依然。", "紫簫吹徹無人見，萬里西風月滿天。"]'),
('a65c1dcb-6beb-4ca6-ad83-79cb29047c34','偈頌一百四十一首  其一','釋師範','宋','宋诗','song-poetry','','[]','前三後三，今日明日。',20,'全唐诗/poet.song.190000.json','["前三後三，今日明日。", "達磨不會，九年面壁。"]'),
('1e6b6a74-e047-4df1-b15d-6307c1546e18','偈頌一百四十一首  其二','釋師範','宋','宋诗','song-poetry','','[]','祖師巴鼻，衲僧巴鼻。',20,'全唐诗/poet.song.190000.json','["祖師巴鼻，衲僧巴鼻。", "有些巴鼻，全沒巴鼻。"]'),
('aa7ab331-0df9-4d4d-916c-164fe0178ae5','偈頌一百四十一首  其三','釋師範','宋','宋诗','song-poetry','','[]','靈山話月，曹溪指月。',20,'全唐诗/poet.song.190000.json','["靈山話月，曹溪指月。", "遞代相傳，證龜成鼈。"]'),
('5d1a9f64-0989-44d2-99fa-fcb1d71b08c1','偈頌一百四十一首  其四','釋師範','宋','宋诗','song-poetry','','[]','一箇是一箇，兩個是兩箇。',32,'全唐诗/poet.song.190000.json','["一箇是一箇，兩個是兩箇。", "東土小釋迦，西天胡達磨。", "卞璧驪珠成滯貨。"]'),
('837293b6-4dc7-415e-aa88-351f07c2cc1a','偈頌一百四十一首  其五','釋師範','宋','宋诗','song-poetry','','[]','今朝又值四月八，天下叢林皆浴佛。',32,'全唐诗/poet.song.190000.json','["今朝又值四月八，天下叢林皆浴佛。", "清涼有令不能行，隨例大家廝淈𣸩。"]'),
('e67db69e-3462-4bcc-a9b0-f95232dc5d92','偈頌一百四十一首  其六','釋師範','宋','宋诗','song-poetry','','[]','十四十五，賤如泥土。',36,'全唐诗/poet.song.190000.json','["十四十五，賤如泥土。", "十六十七，貴如金璧。", "此意分明說向誰，天上人間惟我知。"]'),
('74beee41-caa9-46e6-abe5-931e29d06010','偈頌一百四十一首  其七','釋師範','宋','宋诗','song-poetry','','[]','來住清涼寺，怱怱一箇月。',52,'全唐诗/poet.song.190000.json','["來住清涼寺，怱怱一箇月。", "閑時閑有餘，忙時忙不徹。", "誰知忙與閑，秤鎚渾是鐵。", "舜若多神笑點頭，驕梵鉢提長吐舌。"]'),
('26c004ea-46de-4450-b7cb-f3bbd82884bf','偈頌一百四十一首  其八','釋師範','宋','宋诗','song-poetry','','[]','瞿曇瞬目，迦葉破顔。',20,'全唐诗/poet.song.190000.json','["瞿曇瞬目，迦葉破顔。", "山僧聞得，咬定牙關。"]'),
('d59327b6-0fac-4433-8e04-308438ccea18','偈頌一百四十一首  其九','釋師範','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一葉落，天下秋。',72,'全唐诗/poet.song.190000.json','["一葉落，天下秋。", "一塵起，大地收。", "新羅打鐵火星飛，燒著廬山羅漢院裏王和尚脚指頭。", "磧境廟大王忍痛不禁，直得通身汗流。", "起來道恩大難酬，笑倒溈山水牯牛。"]'),
('298ae565-f1af-46d9-8b1e-3550ca6e6c22','偈頌一百四十一首  其一○','釋師範','宋','宋诗','song-poetry','','[]','尋常月是中秋月，中秋月是尋常月。',47,'全唐诗/poet.song.190000.json','["尋常月是中秋月，中秋月是尋常月。", "看來真箇只尋常，道是尋常又還別。", "別別，無物堪比倫，教我如何說。"]'),
('cb437f9d-0f38-40cd-9bb3-84a429796d52','偈頌一百四十一首  其一一','釋師範','宋','宋诗','song-poetry','','[]','雲從龍，風從虎，聖人作而萬物覩。',52,'全唐诗/poet.song.190000.json','["雲從龍，風從虎，聖人作而萬物覩。", "雪峰輥三箇木毬，禾山老一味打皷。", "海水揚波，須彌作舞。", "皇天無親，惟德是輔。"]'),
('238320c9-d7e6-4e54-9b9b-8028e95cd55d','偈頌一百四十一首  其一二','釋師範','宋','宋诗','song-poetry','','[]','陽春曲，無弦琴。',38,'全唐诗/poet.song.190000.json','["陽春曲，無弦琴。", "聲偃六律，韵排五音。", "月冷兮風清，山高兮水深，舉世有誰知此心。"]'),
('0912fbd9-0b86-4197-8473-de9ddce6401e','偈頌一百四十一首  其一三','釋師範','宋','宋诗','song-poetry','','[]','索寞清凉寺，家風實可憐。',48,'全唐诗/poet.song.190000.json','["索寞清凉寺，家風實可憐。", "白雲迷谷口，黄葉聚階前。", "衲破通身冷，柴生滿室烟。", "誰知今日事，不異普通年。"]'),
('6055b733-2e81-4876-be05-3b91bd26a859','偈頌一百四十一首  其一四','釋師範','宋','宋诗','song-poetry','','[]','鶴唳于天，魚躍于淵。',46,'全唐诗/poet.song.190000.json','["鶴唳于天，魚躍于淵。", "涵波泳月兮悠悠，乘雲馭風兮翩翩。", "時哉時哉，不可得而明焉，令人長憶老南泉。"]'),
('a1b3a53c-d536-4e65-95b9-225754522269','偈頌一百四十一首  其一五','釋師範','宋','宋诗','song-poetry','','[]','客從遠方來，遺我徑寸璧。',24,'全唐诗/poet.song.190000.json','["客從遠方來，遺我徑寸璧。", "中有四箇字，不必重拈出。"]'),
('44c56077-0808-4c31-8dbd-d49358d099a2','偈頌一百四十一首  其一六','釋師範','宋','宋诗','song-poetry','','[]','一不得收，二不得放。',32,'全唐诗/poet.song.190000.json','["一不得收，二不得放。", "是則迦葉擎拳，非則阿難合掌，誌公不是閑和尚。"]'),
('fca14346-8307-4563-8fa5-f8058110d389','偈頌一百四十一首  其一七','釋師範','宋','宋诗','song-poetry','','[]','老胡半夜見明星，瞎却平生兩眼睛。',32,'全唐诗/poet.song.190000.json','["老胡半夜見明星，瞎却平生兩眼睛。", "直至如今無摸索，一回舉著一傷情。"]'),
('074b10ca-53aa-4304-9565-8e946716d423','偈頌一百四十一首  其一八','釋師範','宋','宋诗','song-poetry','','[]','春日遲遲，春風浩浩。',36,'全唐诗/poet.song.190000.json','["春日遲遲，春風浩浩。", "靈利衲僧，點即不到。", "唯有東村王大翁，放牛喫我谿邊草。"]'),
('57a2f61b-d4bd-40f9-aa7a-3cd03fcebeb6','偈頌一百四十一首  其一九','釋師範','宋','宋诗','song-poetry','','[]','和麩糶麫，夾糠炊米。',34,'全唐诗/poet.song.190000.json','["和麩糶麫，夾糠炊米。", "半夜三更，瞞神謼鬼。", "冷地有人覷見，直得左手掩鼻。"]'),
('5080a866-e3db-496e-a221-305e28aa274c','偈頌一百四十一首  其二○','釋師範','宋','宋诗','song-poetry','','[]','糓熟豆熟，粥足飯足。',20,'全唐诗/poet.song.190000.json','["糓熟豆熟，粥足飯足。", "仰面看天，兩手捫腹。"]'),
('b400be7b-c3c7-4a84-9735-3ed1ed86c8ec','偈頌一百四十一首  其二一','釋師範','宋','宋诗','song-poetry','','[]','衲僧用處，了無定度。',20,'全唐诗/poet.song.190000.json','["衲僧用處，了無定度。", "握土成金，握金成土。"]'),
('71d2dde2-011e-4257-8ae6-1c0a465cd619','偈頌一百四十一首  其二二','釋師範','宋','宋诗','song-poetry','','[]','八月十五，月圓當戶。',70,'全唐诗/poet.song.190000.json','["八月十五，月圓當戶。", "夜半正明，天曉不露。", "取箇眼兮耳必聾，捨箇耳兮目必瞽。", "君不見老長沙弄爪牙，一踏踏倒小釋迦。", "將謂是箇老大蟲，元來却是一隻虎。"]'),
('4278552c-137c-478b-a6f7-e558f0db2aa4','偈頌一百四十一首  其二三','釋師範','宋','宋诗','song-poetry','','[]','一冬二冬，你儂我儂。',53,'全唐诗/poet.song.190000.json','["一冬二冬，你儂我儂。", "暗中偷笑，當面脫空。", "雖是尋常茶飯，誰知米裏有蟲。", "豈不見南泉道夜來好風，吹折門前一枝松。"]'),
('cc99619b-506b-46b0-8714-d06c2d43875b','偈頌一百四十一首  其二四','釋師範','宋','宋诗','song-poetry','','[]','一飽忘百饑，人人盡展眉。',24,'全唐诗/poet.song.190000.json','["一飽忘百饑，人人盡展眉。", "太平無事日，唱箇囉囉哩。"]'),
('b8b07c63-74fe-408d-bcb4-030e27968aa7','偈頌一百四十一首  其二五','釋師範','宋','宋诗','song-poetry','','[]','過去已過去，未來亦未來。',24,'全唐诗/poet.song.190000.json','["過去已過去，未來亦未來。", "即今名現在，現在安在哉。"]'),
('44b2268e-c42b-4360-81b8-8a606779aa56','偈頌一百四十一首  其二六','釋師範','宋','宋诗','song-poetry','','[]','年年是好年，日日是好日。',24,'全唐诗/poet.song.190000.json','["年年是好年，日日是好日。", "好事大家知，今朝正月一。"]'),
('584f270a-6dc3-4d91-8bcc-7a30a60dde20','偈頌一百四十一首  其二七','釋師範','宋','宋诗','song-poetry','','[]','人看人，火照火。',16,'全唐诗/poet.song.190000.json','["人看人，火照火。", "無雜壞，忘彼我。"]'),
('936c8fcd-e794-40bb-8c75-89f0fb4b5ee4','偈頌一百四十一首  其二八','釋師範','宋','宋诗','song-poetry','','[]','一拽石，二搬土。',32,'全唐诗/poet.song.190000.json','["一拽石，二搬土。", "三分甜，七分苦。", "糞箕拈起兩肩擔，颺下钁頭無覓處。"]'),
('856875ac-3e7f-4112-8bc7-5724e2a42893','偈頌一百四十一首  其二九','釋師範','宋','宋诗','song-poetry','','[]','安居結制，現前三昧。',20,'全唐诗/poet.song.190000.json','["安居結制，現前三昧。", "普化摇鈴，老盧踏碓。"]'),
('be56071f-b9a6-4be3-8b94-73f0b37badfb','偈頌一百四十一首  其三○','釋師範','宋','宋诗','song-poetry','','[]','這兩箇老凍儂，頑處似牛皮，爛處如壞絮。',49,'全唐诗/poet.song.190000.json','["這兩箇老凍儂，頑處似牛皮，爛處如壞絮。", "雖然各有機關，爭奈渾無展處。", "只麽低頭懡㦬歸，不知忘却來時路。"]'),
('056b82ba-7908-49fc-98fe-b9562af27709','偈頌一百四十一首  其三一','釋師範','宋','宋诗','song-poetry','','[]','一止一切止，一動一切動。',57,'全唐诗/poet.song.190000.json','["一止一切止，一動一切動。", "入荒田不揀，信手拈來用。", "昨日有人從西川來，却得江東信。", "說道趙州親見老南泉，鎮州蘿蔔三斤重。"]'),
('4c19729b-2bf3-4d2d-8b50-2561a1c9d23a','偈頌一百四十一首  其三二','釋師範','宋','宋诗','song-poetry','','[]','摩騰入漢，平地風波。',20,'全唐诗/poet.song.190000.json','["摩騰入漢，平地風波。", "達磨西來，重增殃禍。"]'),
('d89c6297-665f-4ce8-bac0-a9f05d6d6b85','偈頌一百四十一首  其三三','釋師範','宋','宋诗','song-poetry','','[]','作者相逢，你西我東。',44,'全唐诗/poet.song.190000.json','["作者相逢，你西我東。", "水歸滄海，月上孤峰。", "放出城中老鼠，咬殺村裏大蟲。", "因甚如此，閩蜀同風。"]'),
('bf9bd22d-3414-4888-a6e6-8f84ef4fd4b5','偈頌一百四十一首  其三四','釋師範','宋','宋诗','song-poetry','','[]','鼻繩拽脫上梅谿，橫卧千峰適所宜。',32,'全唐诗/poet.song.190000.json','["鼻繩拽脫上梅谿，橫卧千峰適所宜。", "豈謂業緣逃不得，依前拽耙與牽犁。"]'),
('3752096a-b448-461b-afdf-aacc1c9df7d2','偈頌一百四十一首  其三五','釋師範','宋','宋诗','song-poetry','','[]','上元正月半，無油不點燈。',24,'全唐诗/poet.song.190000.json','["上元正月半，無油不點燈。", "誰人知此意，有月上危層。"]'),
('f45d736d-65c9-4daf-b7a4-07c72eb94c18','偈頌一百四十一首  其三六','釋師範','宋','宋诗','song-poetry','','[]','去年梅，今歲柳。',18,'全唐诗/poet.song.190000.json','["去年梅，今歲柳。", "顔色馨香，依舊依舊。"]'),
('5b0261c5-2807-42e8-9e79-c2bc0d113de4','偈頌一百四十一首  其三七','釋師範','宋','宋诗','song-poetry','','[]','住亦無可說，去亦無可說。',24,'全唐诗/poet.song.190000.json','["住亦無可說，去亦無可說。", "竇八布衫穿，金剛嚼生鐵。"]'),
('c69d90e9-3e7c-4a08-b556-dc2522e798ba','偈頌一百四十一首  其三八','釋師範','宋','宋诗','song-poetry','','[]','三門佛殿，一見便見。',20,'全唐诗/poet.song.190000.json','["三門佛殿，一見便見。", "踢倒浄瓶，撼動門扇。"]'),
('17839b0d-7427-4aa4-8439-5229ebddf95e','偈頌一百四十一首  其三九','釋師範','宋','宋诗','song-poetry','','[]','你不識我，我不識你。',36,'全唐诗/poet.song.190000.json','["你不識我，我不識你。", "狹路相逢，腦門著地。", "仁者見之謂之仁，智者見之謂之智。"]'),
('eace3901-5509-4265-9c5c-8d0dccc27402','偈頌一百四十一首  其四○','釋師範','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夜暗晝明，天平地平。',53,'全唐诗/poet.song.190000.json','["夜暗晝明，天平地平。", "三日一雨，五日一晴。", "達磨大師不安本分，被人打落當門板齒，廬山歸宗和尚無端拭壞一雙眼睛。"]'),
('37c23575-6562-4fe4-aab6-249efc1be877','偈頌一百四十一首  其四一','釋師範','宋','宋诗','song-poetry','','[]','十字街頭道得一句，三家村裏使不著。',34,'全唐诗/poet.song.190000.json','["十字街頭道得一句，三家村裏使不著。", "三家村裏道得一句，十字街頭使不著。"]'),
('0da5bc61-fa8f-47f2-92a8-c193541be335','偈頌一百四十一首  其四二','釋師範','宋','宋诗','song-poetry','','[]','正覺山前，雙林樹下。',36,'全唐诗/poet.song.190000.json','["正覺山前，雙林樹下。", "弄假像真，弄真像假。", "臨風哮吼戴嵩牛，顧影嘶鳴韓幹馬。"]'),
('01d40318-95ae-45eb-b63d-48b48606264a','偈頌一百四十一首  其四三','釋師範','宋','宋诗','song-poetry','','[]','今朝七月一，明朝七月二。',24,'全唐诗/poet.song.190000.json','["今朝七月一，明朝七月二。", "一日是一日，幾箇知慚愧。"]'),
('c5ddeac5-4353-4ce5-80a9-723446b2deb7','偈頌一百四十一首  其四四','釋師範','宋','宋诗','song-poetry','','[]','重陽九月九，箇箇盡知有。',47,'全唐诗/poet.song.190000.json','["重陽九月九，箇箇盡知有。", "喫了茱萸茶，多是眉頭皺。", "唯有陶靖節獨歡顔，解道採菊東籬下，悠然見南山。"]'),
('8e9632b8-ff1a-4944-aae1-03ce3b2f889b','偈頌一百四十一首  其四五','釋師範','宋','宋诗','song-poetry','','[]','信息既通，奉君盡忠。',18,'全唐诗/poet.song.190000.json','["信息既通，奉君盡忠。", "風從虎兮雲從龍。"]'),
('d5139499-abda-4959-98a1-114a0e67d8b0','偈頌一百四十一首  其四六','釋師範','宋','宋诗','song-poetry','','[]','迦葉擎拳，阿難合掌。',44,'全唐诗/poet.song.190000.json','["迦葉擎拳，阿難合掌。", "黄面瞿曇，全無伎倆。", "新乳峰一時見了，却燒沉香供養。", "從教人道是罰是賞。"]'),
('cc752fad-363e-4db4-adc4-ac8eef534108','偈頌一百四十一首  其四七','釋師範','宋','宋诗','song-poetry','','[]','方交正月一，又過了五日。',24,'全唐诗/poet.song.190000.json','["方交正月一，又過了五日。", "世事冗如麻，光陰劈箭急。"]'),
('62b5d963-4970-4248-ba45-77a20b6bf92d','偈頌一百四十一首  其四八','釋師範','宋','宋诗','song-poetry','','[]','東邊有知事，西邊有頭首。',28,'全唐诗/poet.song.190000.json','["東邊有知事，西邊有頭首。", "山僧贏得倚欄干，盡日仰頭看雲走。"]'),
('5dc9b41f-a020-4a79-b2e0-ae8c3f13c9e5','偈頌一百四十一首  其四九','釋師範','宋','宋诗','song-poetry','','[]','春日晴，黄鶑鳴。',49,'全唐诗/poet.song.190000.json','["春日晴，黄鶑鳴。", "山花似錦，汀草如茵。", "堪悲堪笑，公塘寨裏王節級到處巡捕，自己不知不覺，打失一雙眼睛。"]'),
('66ba1cfa-9b69-4708-8c77-13385882eb20','偈頌一百四十一首  其五○','釋師範','宋','宋诗','song-poetry','','[]','這老禿，無面目。',87,'全唐诗/poet.song.190000.json','["這老禿，無面目。", "不具些子慈悲，却有十分惡毒。", "喜亦不可近，怒尤不可觸。", "我昔被渠禁害，逼得頑蛇生足。", "以至今日燒一炷香謾禮三拜，要且笑不成笑哭不成哭。", "此冤此恨若爲伸，唵部臨唵齒臨。"]'),
('f30632eb-bf3d-4f5e-a0f7-7f90e95f58aa','偈頌一百四十一首  其五一','釋師範','宋','宋诗','song-poetry','','[]','佛法也不會，世法也不會。',24,'全唐诗/poet.song.190000.json','["佛法也不會，世法也不會。", "一夏九十日，瞎馿隨大隊。"]'),
('bf8c3dc4-f30e-42ae-bc82-9fbe492ae32f','偈頌一百四十一首  其五二','釋師範','宋','宋诗','song-poetry','','[]','二由一有，一亦莫守。',72,'全唐诗/poet.song.190000.json','["二由一有，一亦莫守。", "新羅日午打三更，回首面南看北斗。", "堪悲堪笑，黄面禪和到處行脚，只管將鼻孔東邊嗅西邊嗅。", "自己鼻尖上有一點糞，十箇五雙因甚不覺臭。"]'),
('29c32d10-a7a7-496f-a36c-d42cf1daef2e','偈頌一百四十一首  其五三','釋師範','宋','宋诗','song-poetry','','[]','曲中直，直中曲。',32,'全唐诗/poet.song.190000.json','["曲中直，直中曲。", "有增減，無數目。", "等閑放在暗窗前，冷地令人看不足。"]'),
('bead47f9-a283-4e63-8c6f-58702d6c982d','偈頌一百四十一首  其五四','釋師範','宋','宋诗','song-poetry','','[]','本色行脚人，須具行脚眼。',24,'全唐诗/poet.song.190000.json','["本色行脚人，須具行脚眼。", "千箇與萬箇，多是空檐版。"]'),
('c633172b-246f-4725-93ba-81f8b737bcce','偈頌一百四十一首  其五五','釋師範','宋','宋诗','song-poetry','','[]','秋江清淺時，白露和煙島。',24,'全唐诗/poet.song.190000.json','["秋江清淺時，白露和煙島。", "搘筇寂寞中，望斷無人到。"]'),
('1ef701dd-ba1a-4860-8274-e1a0d9f8204c','偈頌一百四十一首  其五六','釋師範','宋','宋诗','song-poetry','','[]','上下三指，彼此七馬。',46,'全唐诗/poet.song.190000.json','["上下三指，彼此七馬。", "似有似無，半真半假。", "乳峰被人問著，五年分疎不下。", "阿呵呵，笑倒東村王大姊。"]'),
('cf15cc02-f60c-4264-81ab-bf337fd2fbdd','偈頌一百四十一首  其五七','釋師範','宋','宋诗','song-poetry','','["\u8861\u5c71"]','語是謗，寂是誑。',44,'全唐诗/poet.song.190000.json','["語是謗，寂是誑。", "擬即乖，動即喪。", "明眼人，難近傍。", "絕塵情，忘伎倆。", "江西馬大師，南嶽讓和尚。"]'),
('ef691a3a-8aa7-4903-8783-4c8cd8fbf2ab','偈頌一百四十一首  其五八','釋師範','宋','宋诗','song-poetry','','[]','一冬二冬，叉手當胸。',20,'全唐诗/poet.song.190000.json','["一冬二冬，叉手當胸。", "珠鑽九曲，直在其中。"]'),
('171a7b57-6afd-4865-b1c9-4f396a43e4a2','偈頌一百四十一首  其五九','釋師範','宋','宋诗','song-poetry','','[]','上元正月半，燈火連霄漢。',24,'全唐诗/poet.song.190000.json','["上元正月半，燈火連霄漢。", "千人與萬人，聚頭相共看。"]'),
('1bed9195-1f0b-4b69-af83-d2ba6c8dbc20','偈頌一百四十一首  其六○','釋師範','宋','宋诗','song-poetry','','[]','作家相見，有底憑據。',28,'全唐诗/poet.song.190000.json','["作家相見，有底憑據。", "迥無人處，聚頭共語。", "寂子無端撼茶樹。"]'),
('b5199409-e106-46b2-b085-3cdcad3b9a35','偈頌一百四十一首  其六一','釋師範','宋','宋诗','song-poetry','','[]','眼底年來胡種滅，叢林喜見太平時。',32,'全唐诗/poet.song.190000.json','["眼底年來胡種滅，叢林喜見太平時。", "太平消息誰相委，只許張公李老知。"]'),
('62d284cf-b436-4d2a-ab6b-6b3df9472db5','偈頌一百四十一首  其六二','釋師範','宋','宋诗','song-poetry','','[]','萬木驚霜風，千林著秋色。',24,'全唐诗/poet.song.190000.json','["萬木驚霜風，千林著秋色。", "堪笑寒山子，到處覓不得。"]'),
('31a5c530-5d6a-4a17-9b93-edcf3a188751','偈頌一百四十一首  其六三','釋師範','宋','宋诗','song-poetry','','[]','乳峰今日開爐，不會挑灰撥火。',72,'全唐诗/poet.song.190000.json','["乳峰今日開爐，不會挑灰撥火。", "大家衲被幪頭，只麽團圞打座。", "不求諸聖，不重己靈。", "從他門外區區，世路擾擾紅塵。", "夏了秋，秋了冬，冬了春，思量也是慕西秦。"]'),
('6886faf1-5459-4298-9146-1c54bb0d28b5','偈頌一百四十一首  其六四','釋師範','宋','宋诗','song-poetry','','[]','聲前一句，不封不樹。',35,'全唐诗/poet.song.190000.json','["聲前一句，不封不樹。", "坐斷舌頭，如何通吐。", "昨日有人從天台來，却往徑山去。"]'),
('e6d91986-a8f0-47d5-8375-5340ce726905','偈頌一百四十一首  其六五','釋師範','宋','宋诗','song-poetry','','[]','臨濟爲睦州所誤，雪峰遭巖頭毒手。',26,'全唐诗/poet.song.190000.json','["臨濟爲睦州所誤，雪峰遭巖頭毒手。", "沒齒銜冤，萬世不朽。"]'),
('b86377cd-e927-4b90-9244-7e198206ec01','偈頌一百四十一首  其六六','釋師範','宋','宋诗','song-poetry','','[]','前面是懸崖萬仞，後面是荆棘叢林。',47,'全唐诗/poet.song.190000.json','["前面是懸崖萬仞，後面是荆棘叢林。", "兩邊烈焰火聚，於中如何轉身。", "趙州老漢在青州，作一領布衫重七斤。"]'),
('ee22e115-bf30-48b4-88b8-836f2fe4dded','偈頌一百四十一首  其六七','釋師範','宋','宋诗','song-poetry','','[]','今朝正月一，只是尋常日。',24,'全唐诗/poet.song.190000.json','["今朝正月一，只是尋常日。", "就中殊異處，徧界鋪銀色。"]'),
('a2cfb920-2786-465c-9a0f-b5bcb5b8ee6b','偈頌一百四十一首  其六八','釋師範','宋','宋诗','song-poetry','','[]','王道平平，其壽綿綿。',36,'全唐诗/poet.song.190000.json','["王道平平，其壽綿綿。", "漁歌樵唱，共樂堯年。", "無爲焉，無私焉，乾坤一統舊山川。"]'),
('5e1a4515-cf68-47be-9ed0-18420eeed8de','偈頌一百四十一首  其六九','釋師範','宋','宋诗','song-poetry','','[]','萬別千差處，事同一家。',44,'全唐诗/poet.song.190000.json','["萬別千差處，事同一家。", "事同一家時，萬別千差。", "太白山前水磨日夜輪轉不歇，乳峰寺裏參退喫茶。"]'),
('4870d939-974b-4805-a896-3479539b7559','偈頌一百四十一首  其七○','釋師範','宋','宋诗','song-poetry','','[]','縱無所畏，說大脫空。',20,'全唐诗/poet.song.190000.json','["縱無所畏，說大脫空。", "雖有希求，辨最上供。"]'),
('2fd913c7-cf31-4502-89ef-77507f78408d','偈頌一百四十一首  其七一','釋師範','宋','宋诗','song-poetry','','[]','智度菩薩母，容受一切法。',50,'全唐诗/poet.song.190000.json','["智度菩薩母，容受一切法。", "然於一切法，而離分別相。", "分別既離，諸法如如。", "蜀江萬派朝滄海，閩嶺千尋插太虛。"]'),
('6631491f-67f7-4671-aac3-f1f9f71aa2f9','偈頌一百四十一首  其七二','釋師範','宋','宋诗','song-poetry','','[]','擊皷陞堂，大衆雲集。',24,'全唐诗/poet.song.190000.json','["擊皷陞堂，大衆雲集。", "佛法有底商量，今日熱如昨日。"]'),
('c56f561a-3025-456a-afd8-0c4c28e7cf09','偈頌一百四十一首  其七三','釋師範','宋','宋诗','song-poetry','','[]','克期取證，繫縛盲馿。',20,'全唐诗/poet.song.190000.json','["克期取證，繫縛盲馿。", "休夏自陳，且莫鬼語。"]'),
('919ef756-9587-4453-9e50-6e882f4dbd3f','偈頌一百四十一首  其七四','釋師範','宋','宋诗','song-poetry','','[]','秋高增爽氣，夜寒添夾被。',50,'全唐诗/poet.song.190000.json','["秋高增爽氣，夜寒添夾被。", "草蟲吟壁根，黄葉飄庭際。", "直得山僧展轉返側，喜而不寐。", "阿呵呵，伸脚元在縮脚裏。"]'),
('4c32cc72-024d-46d2-b280-7d31975aa76e','偈頌一百四十一首  其七五','釋師範','宋','宋诗','song-poetry','','[]','面面相看，眼眼廝覷。',36,'全唐诗/poet.song.190000.json','["面面相看，眼眼廝覷。", "衣外別傳，有甚憑據。", "倒却門前剎竿著，鳳棲不在梧桐樹。"]'),
('8936dccc-3bd4-461d-beba-74ed09641c94','偈頌一百四十一首  其七六','釋師範','宋','宋诗','song-poetry','','[]','火焰爲三世諸佛說法，三世諸佛立地聽。',74,'全唐诗/poet.song.190000.json','["火焰爲三世諸佛說法，三世諸佛立地聽。", "聽在說處，說在聽處。", "聽說兩忘，如何剖露。", "經入藏，禪歸海。", "唯是馬簸箕，拈弄有餘態。", "每遇中秋玩月時，尋思直是令人愛。"]'),
('fadc5803-dde5-4d1c-94ca-b7f864e37c48','偈頌一百四十一首  其七七','釋師範','宋','宋诗','song-poetry','','[]','大惠老漢無端，隨後說難說易。',22,'全唐诗/poet.song.190000.json','["大惠老漢無端，隨後說難說易。", "拈得口兮失却鼻。"]'),
('8daefbaa-cae1-4f57-b0e6-db75d5842dcd','偈頌一百四十一首  其七八','釋師範','宋','宋诗','song-poetry','','[]','坦坦平如鏡，彎彎曲似鈎。',24,'全唐诗/poet.song.190000.json','["坦坦平如鏡，彎彎曲似鈎。", "無人收拾得，颺在糞堆頭。"]'),
('bac74903-31ac-4b83-815f-7ec832e068de','偈頌一百四十一首  其七九','釋師範','宋','宋诗','song-poetry','','[]','無味乃真味，真味真無味。',40,'全唐诗/poet.song.190000.json','["無味乃真味，真味真無味。", "若知真味者，更不說真味。", "曾聞一飽忘百饑，今日山僧身便走。"]'),
('9b60908b-f3dc-49b4-96a9-ef1ccc4d076c','偈頌一百四十一首  其八○','釋師範','宋','宋诗','song-poetry','','[]','雲門一曲，從來無譜。',36,'全唐诗/poet.song.190000.json','["雲門一曲，從來無譜。", "韵出五音，調高千古。", "就中妙旨許誰知，幾擬黄金鑄子期。"]'),
('16c51ae6-5372-493d-acfc-dbcfd3f10841','偈頌一百四十一首  其八一','釋師範','宋','宋诗','song-poetry','','[]','我有一語，非甜非苦。',36,'全唐诗/poet.song.190000.json','["我有一語，非甜非苦。", "既遇知音，如何通吐。", "夜來點得柳土獐，如今變成尾火虎。"]'),
('0b880a43-1a06-499b-96f9-620c07f9939c','偈頌一百四十一首  其八二','釋師範','宋','宋诗','song-poetry','','[]','靈山山上葛藤樹，引蔓牽枝徧界生。',32,'全唐诗/poet.song.190000.json','["靈山山上葛藤樹，引蔓牽枝徧界生。", "慚愧波旬推倒後，東西有路與人行。"]'),
('c69e756a-140a-418e-acdc-508bec5d236a','偈頌一百四十一首  其八三','釋師範','宋','宋诗','song-poetry','','[]','貍奴白牯，相共證明，大難大難。',41,'全唐诗/poet.song.190000.json','["貍奴白牯，相共證明，大難大難。", "碧眼黄頭，亦須莽鹵。", "黄連甜，甘草苦，發機須是千鈞弩。"]'),
('624c7392-1be6-4f77-aaa9-8964394f83ba','偈頌一百四十一首  其八四','釋師範','宋','宋诗','song-poetry','','[]','從這裏流出，滔滔無盡日。',24,'全唐诗/poet.song.190000.json','["從這裏流出，滔滔無盡日。", "巨浪湧千尋，誰知無一滴。"]'),
('53e202eb-48ed-4dc8-8dcd-b8bc8d510fe6','偈頌一百四十一首  其八五','釋師範','宋','宋诗','song-poetry','','[]','韶光爛熳時，百卉皆妍秀。',54,'全唐诗/poet.song.190000.json','["韶光爛熳時，百卉皆妍秀。", "處處有春風，村村自花柳。", "靈雲眼裏添釘，玄沙袖中出手。", "除非自解倒騎馿，一生不著隨人後。"]'),
('9a7c16f2-071a-4941-950d-9ef80ad9ca6d','偈頌一百四十一首  其八六','釋師範','宋','宋诗','song-poetry','','[]','太白峰前收陣脚，鑑湖歸唱村田樂。',70,'全唐诗/poet.song.190000.json','["太白峰前收陣脚，鑑湖歸唱村田樂。", "無端調轉入新豐，誰知錯處非常錯。", "直得洞水逆流，乳峰倒卓。", "石女攢眉，木人淚落。", "此曲如今誰共聞，越山無際天無垠。"]'),
('04da758b-cdd8-4db4-98f0-ec9196ce6ade','偈頌一百四十一首  其八七','釋師範','宋','宋诗','song-poetry','','[]','三日前，五日後，藥若不瞑眩，厥疾弗瘳，折脚雲門見睦州。',27,'全唐诗/poet.song.190000.json','["三日前，五日後，藥若不瞑眩，厥疾弗瘳，折脚雲門見睦州。"]'),
('eb715836-6d79-481b-8a65-399554f1dd0f','偈頌一百四十一首  其八八','釋師範','宋','宋诗','song-poetry','','[]','今朝九月九，談禪不開口。',44,'全唐诗/poet.song.190000.json','["今朝九月九，談禪不開口。", "若是陶淵明，攢眉便回首。", "籬邊黄菊正芬披，一枝兩枝三枝四五六七枝。"]'),
('9f83849b-083b-474f-81ce-72800c2d22c5','偈頌一百四十一首  其八九','釋師範','宋','宋诗','song-poetry','','[]','一句子，墨漆黑。',26,'全唐诗/poet.song.190000.json','["一句子，墨漆黑。", "無欛柄，有準則。", "碓搗東南，磨推西北。"]'),
('96c589d3-e75a-4662-b550-4a8853de4ed3','偈頌一百四十一首  其九○','釋師範','宋','宋诗','song-poetry','','[]','清寥寥，白滴滴。',38,'全唐诗/poet.song.190000.json','["清寥寥，白滴滴。", "匙挑不上，針劄不入。", "是則是，須知花發不干春，切忌寒灰煨殺人。"]'),
('2d60741c-7af1-480b-9696-2c007ecfc637','偈頌一百四十一首  其九一','釋師範','宋','宋诗','song-poetry','','[]','千討萬討討不見，都不要討却成現。',32,'全唐诗/poet.song.190000.json','["千討萬討討不見，都不要討却成現。", "十字街頭逢阿爺，眉毛蓋眼胡鬚面。"]'),
('8eede903-9dee-468b-975d-83ebc762c503','偈頌一百四十一首  其九二','釋師範','宋','宋诗','song-poetry','','[]','天上星，地下木。',80,'全唐诗/poet.song.190000.json','["天上星，地下木。", "見便見，休□速。", "老瞿曇，空捏目。", "三七日，心返復。", "從此拏空便脫空，天上人間徧流毒。", "带累兒孫直至今，醫得耳聾成瞎禿。", "鄮峰雖與同路行，却不與他同處宿。"]'),
('65c2a506-3e1e-4d7c-a57d-e2ef5c8b7e4a','偈頌一百四十一首  其九三','釋師範','宋','宋诗','song-poetry','','[]','擬即差，動即隔。',32,'全唐诗/poet.song.190000.json','["擬即差，動即隔。", "忘伎倆，絕聲色。", "兩手揶揄懡㦬休，東村有箇王大伯。"]'),
('4f1a3dad-7824-4082-b4dd-76b29f8bd59f','偈頌一百四十一首  其九四','釋師範','宋','宋诗','song-poetry','','[]','鳳凰臺畔，玉几峰前。',20,'全唐诗/poet.song.190000.json','["鳳凰臺畔，玉几峰前。", "築著磕著，夙世生冤。"]'),
('3d261553-672c-4d5a-ba1a-c0d10df810e5','偈頌一百四十一首  其九五','釋師範','宋','宋诗','song-poetry','','[]','有一物，黑似漆，亙古今，無人識。',41,'全唐诗/poet.song.190000.json','["有一物，黑似漆，亙古今，無人識。", "却被秋蟲知，唧唧空嘆息。", "而今拈出普請看，分文不直。"]'),
('a11faf5a-e8d0-4b0c-9487-6d61b03bc862','偈頌一百四十一首  其九六','釋師範','宋','宋诗','song-poetry','','[]','人皆競賞中秋，惟有山僧不管。',28,'全唐诗/poet.song.190000.json','["人皆競賞中秋，惟有山僧不管。", "大都天上月圓，只是尋常月半。"]'),
('dea3473b-3a9c-4d31-a83b-0988093415c8','偈頌一百四十一首  其九七','釋師範','宋','宋诗','song-poetry','','[]','行不動塵，語不動唇。',35,'全唐诗/poet.song.190000.json','["行不動塵，語不動唇。", "現成行貨，黄金白銀。", "君不見洞山老，問佛直答麻三斤。"]'),
('3952f1c4-33b0-490e-b5ad-59262c11f819','偈頌一百四十一首  其九八','釋師範','宋','宋诗','song-poetry','','[]','輕如鴻毛輕，重若丘山重。',34,'全唐诗/poet.song.190000.json','["輕如鴻毛輕，重若丘山重。", "安排不得處，信手拈來用。", "雖是死蛇，却要活弄。"]'),
('76776cb4-f43b-4104-9aae-0104f833bd6c','偈頌一百四十一首  其九九','釋師範','宋','宋诗','song-poetry','','[]','衲僧門下，無可不可。',42,'全唐诗/poet.song.190000.json','["衲僧門下，無可不可。", "熱則到處乘凉，寒則圍爐向火。", "饑則餐，困則卧。", "執法修行，如牛拽磨。"]'),
('4e9368a5-16b4-4cb5-ad1f-435dfd717e1a','偈頌一百四十一首  其一○○','釋師範','宋','宋诗','song-poetry','','[]','二月春光明媚，是處花酣柳醉。',28,'全唐诗/poet.song.190000.json','["二月春光明媚，是處花酣柳醉。", "五湖四海禪流，切忌開眼瞌睡。"]'),
('32e8aaf9-0d43-445f-a983-82f045811752','偈頌一百四十一首  其一○一','釋師範','宋','宋诗','song-poetry','','[]','來無所從，南高峰，北高峰。',52,'全唐诗/poet.song.190000.json','["來無所從，南高峰，北高峰。", "去無所至，東澗水，西澗水。", "幻泡忽滅，證得烏龜成白鱉。", "清風未已，須信高原元不死。"]'),
('9a8e5ba2-f6b6-48f3-a0ce-829a83b154da','偈頌一百四十一首  其一○二','釋師範','宋','宋诗','song-poetry','','[]','名不得，狀不得，復是何物。',53,'全唐诗/poet.song.190000.json','["名不得，狀不得，復是何物。", "見得到，用得親，不由別人。", "有時恁麽，有時不恁麽，無毛鷂子貼天飛，带角大蟲當路卧。"]'),
('b04e9795-105f-423a-9d41-5ed54478abd9','偈頌一百四十一首  其一○三','釋師範','宋','宋诗','song-poetry','','[]','當明有暗，當暗有明。',36,'全唐诗/poet.song.190000.json','["當明有暗，當暗有明。", "口說如啞，眼見如盲。", "門外一條通驛路，朝朝暮暮有人行。"]'),
('db6c2740-2711-483a-816e-8383f40c4238','偈頌一百四十一首  其一○四','釋師範','宋','宋诗','song-poetry','','[]','炎炎六月，飄風灑雪。',36,'全唐诗/poet.song.190000.json','["炎炎六月，飄風灑雪。", "百丈耳聾，黄蘗吐舌。", "海闊山高誰與論，一回飲水一回噎。"]'),
('9350d629-c67e-448b-b321-57a6e5962089','偈頌一百四十一首  其一○五','釋師範','宋','宋诗','song-poetry','','[]','瞿曇你自瞿曇，達磨從他達磨。',28,'全唐诗/poet.song.190000.json','["瞿曇你自瞿曇，達磨從他達磨。", "佛法有底商量，各自歸堂向火。"]'),
('0a6a74a4-3b5e-4fb9-88a2-779c94d10dcc','偈頌一百四十一首  其一○六','釋師範','宋','宋诗','song-poetry','','[]','半真半假千家貨，非實非虛百寶囊。',32,'全唐诗/poet.song.190000.json','["半真半假千家貨，非實非虛百寶囊。", "盡底打開都見了，有誰合火共分贓。"]'),
('e2cf7e66-5e3c-499b-b773-75c368942793','偈頌一百四十一首  其一○七','釋師範','宋','宋诗','song-poetry','','[]','二由一有，一亦莫守。',20,'全唐诗/poet.song.190000.json','["二由一有，一亦莫守。", "一心不生，萬法無咎。"]'),
('5a80f76a-a1f1-4b73-88e9-b894cce3c2d4','偈頌一百四十一首  其一○八','釋師範','宋','宋诗','song-poetry','','[]','現前三昧，了無向背。',20,'全唐诗/poet.song.190000.json','["現前三昧，了無向背。", "雪壓樓臺，風號松檜。"]'),
('76ad88b1-1394-4480-8815-016c6327065d','偈頌一百四十一首  其一○九','釋師範','宋','宋诗','song-poetry','','[]','內空外空內外空，四大五藴不可得，山河大地不可得。',40,'全唐诗/poet.song.190000.json','["內空外空內外空，四大五藴不可得，山河大地不可得。", "不可得亦不可得，舜若多神面皮黑。"]'),
('d5da2719-19cc-4362-819f-67dd22864493','偈頌一百四十一首  其一一○','釋師範','宋','宋诗','song-poetry','','[]','拄杖子，難摸索。',34,'全唐诗/poet.song.190000.json','["拄杖子，難摸索。", "有時喜，有時惡。", "攪動滄溟，衝開碧落，何如普化摇鈴鐸。"]'),
('eb093193-80a7-4fa8-a5ca-577ee24795dc','偈頌一百四十一首  其一一一','釋師範','宋','宋诗','song-poetry','','[]','形名未兆，文彩全彰。',58,'全唐诗/poet.song.190000.json','["形名未兆，文彩全彰。", "短者自短，長者自長。", "黄面瞿曇徒自說黄道黑，胡鬚達磨何須歷魏遊梁。", "長憶江南二三月，鷓鴣啼處百花香。"]'),
('c1c0dfbc-edf5-4277-8af9-fd037a7278e9','偈頌一百四十一首  其一一二','釋師範','宋','宋诗','song-poetry','','[]','三月春將老，萬木獻青杪。',43,'全唐诗/poet.song.190000.json','["三月春將老，萬木獻青杪。", "微雨濕殘紅，泉聲雜幽鳥。", "堪悲堪笑，寒山子，歸不得，忘却來時道。"]'),
('83bbb32e-2816-4dc2-87a8-186d1b7da740','偈頌一百四十一首  其一一三','釋師範','宋','宋诗','song-poetry','','[]','荷葉團團團似鏡，菱角尖尖尖似錐。',32,'全唐诗/poet.song.190000.json','["荷葉團團團似鏡，菱角尖尖尖似錐。", "風吹柳絮毛毬走，雨打梨花蛺蝶飛。"]'),
('8159d831-aa61-4001-80ab-51fedac2aaff','偈頌一百四十一首  其一一四','釋師範','宋','宋诗','song-poetry','','[]','萬籟聲沉沉，虛堂夜寂寂。',34,'全唐诗/poet.song.190000.json','["萬籟聲沉沉，虛堂夜寂寂。", "不見寒山子，未免空相憶。", "休相憶，元來在這裏。"]'),
('b61b2199-d5a6-4671-99bc-28a389c25832','偈頌一百四十一首  其一一五','釋師範','宋','宋诗','song-poetry','','[]','今朝八月二十五，記得洞山離查渡。',60,'全唐诗/poet.song.190000.json','["今朝八月二十五，記得洞山離查渡。", "韶石山頭打不回，追至如今無本據。", "問佛便答麻三斤，何似庭前柏樹子。", "蒼鷹搦卧兔，貓兒捉老鼠。"]'),
('193b0e68-a3e3-4e98-8d5c-f7dcdaecfd91','偈頌一百四十一首  其一一六','釋師範','宋','宋诗','song-poetry','','[]','萬籟風悽悽，千林露滴滴。',46,'全唐诗/poet.song.190000.json','["萬籟風悽悽，千林露滴滴。", "塞鴈起平沙，夜蟲吟破壁。", "舉一不得，舉二放過一著，更聽拄杖子露箇消息。"]'),
('468e6cff-6600-425c-95a0-d445e7c763ac','偈頌一百四十一首  其一一七','釋師範','宋','宋诗','song-poetry','','[]','無道可學，無禪可參。',49,'全唐诗/poet.song.190000.json','["無道可學，無禪可參。", "黄頭碧眼，徒話指南。", "霧歛雲收天宇寬，門前幸有千朵青山萬朵青山，徘徊贏得倚欄干。"]'),
('51ae0c44-3b98-449e-bf87-e3e2caedf558','偈頌一百四十一首  其一一八','釋師範','宋','宋诗','song-poetry','','[]','橫說豎說何曾動著舌頭，逆行順行總是家常茶飯。',36,'全唐诗/poet.song.190000.json','["橫說豎說何曾動著舌頭，逆行順行總是家常茶飯。", "有準繩，無畔岸，吾道一以貫。"]'),
('e3b1e2b8-df21-4721-bc6d-eff763787c23','偈頌一百四十一首  其一一九','釋師範','宋','宋诗','song-poetry','','[]','一陽生，萬彙生。',26,'全唐诗/poet.song.190000.json','["一陽生，萬彙生。", "正當生，作麽生。", "羣陰消殄，吾道大亨。"]'),
('45ec2a3a-0fe5-423f-b320-e4b88aa3ede3','偈頌一百四十一首  其一二○','釋師範','宋','宋诗','song-poetry','','[]','一年十二月，此月乃當盡。',54,'全唐诗/poet.song.190000.json','["一年十二月，此月乃當盡。", "一月三十日，此日方起頭。", "此日即是尋常日，那裏是起頭處。", "此月即是尋常月，那裏是盡頭處。"]'),
('feb4938e-a9a6-4e80-8b6b-acf64d0e2b5b','偈頌一百四十一首  其一二一','釋師範','宋','宋诗','song-poetry','','[]','聲前句，量外機。',42,'全唐诗/poet.song.190000.json','["聲前句，量外機。", "明歷歷，峭巍巍。", "舉者既少，見者亦稀。", "抖擻多年穿破衲，襤毿一半逐雲飛。"]'),
('8a6901b2-c2f4-4f2f-8a96-dfe0554302c4','偈頌一百四十一首  其一二二','釋師範','宋','宋诗','song-poetry','','[]','春風浩浩，春雨綿綿。',50,'全唐诗/poet.song.190000.json','["春風浩浩，春雨綿綿。", "花凝曉露，柳带寒煙。", "造化無作而作，萬法不然而然。", "達磨九年空面壁，善財走得脚皮穿。"]'),
('dcbc6e3b-b549-47c2-ad02-441f302e9198','偈頌一百四十一首  其一二三','釋師範','宋','宋诗','song-poetry','','[]','淺聞深悟，深聞不悟。',20,'全唐诗/poet.song.190000.json','["淺聞深悟，深聞不悟。", "迷逢達磨，趙婆呷醋。"]'),
('5e2fb0b8-ae2a-4c7d-98bd-1ed70f798f11','偈頌一百四十一首  其一二四','釋師範','宋','宋诗','song-poetry','','[]','木中有火，鑽之始明。',43,'全唐诗/poet.song.190000.json','["木中有火，鑽之始明。", "鑛中有金，煉之始精。", "諸人分上各各有無價之寶，如何甘自溺於陰入之坑。"]'),
('dd067ad3-4bf7-4bb9-9c92-ca9b2ed63beb','偈頌一百四十一首  其一二五','釋師範','宋','宋诗','song-poetry','','[]','一夏逡巡已過半，往往精勤成懶慢。',53,'全唐诗/poet.song.190000.json','["一夏逡巡已過半，往往精勤成懶慢。", "幸然底事十分現成，因甚到夜打疊不辦。", "君不見趙州末上見南泉，何似雪峰參老觀。"]'),
('f226113a-95dd-4125-ab0a-7d0e1a8b0d11','偈頌一百四十一首  其一二六','釋師範','宋','宋诗','song-poetry','','[]','阿剌剌，橫該抹。',41,'全唐诗/poet.song.190000.json','["阿剌剌，橫該抹。", "天何高，地何闊。", "碧眼與黄頭，徒自閙聒聒。", "育王恁麽道，也是將鹽止渴。"]'),
('925c104d-c1a0-4fe6-8947-ffcbc3627247','偈頌一百四十一首  其一二七','釋師範','宋','宋诗','song-poetry','','[]','一處通，處處通，手頭活落，脚下玲瓏。',34,'全唐诗/poet.song.190000.json','["一處通，處處通，手頭活落，脚下玲瓏。", "常記南泉提起處，刈禾鎌子快如風。"]'),
('bcf6c759-fe8a-4add-b644-3955943a4295','偈頌一百四十一首  其一二八','釋師範','宋','宋诗','song-poetry','','[]','仰面看天，低頭覷地。',46,'全唐诗/poet.song.190000.json','["仰面看天，低頭覷地。", "明眼衲僧，討甚巴鼻。", "豈不見山前明覺寺裏有箇陳闍黎，解道蘇嚕蘇嚕悉唎悉唎。"]'),
('9057d3d2-9154-45a7-bd22-14e35af37013','偈頌一百四十一首  其一二九','釋師範','宋','宋诗','song-poetry','','[]','前月只此月，後月亦此月。',24,'全唐诗/poet.song.190000.json','["前月只此月，後月亦此月。", "何得塵世人，競賞中秋節。"]'),
('d533c27c-0add-4aaa-bf55-f5d888e69b7d','偈頌一百四十一首  其一三○','釋師範','宋','宋诗','song-poetry','','[]','九日當佳節，黄花處處新。',31,'全唐诗/poet.song.190000.json','["九日當佳節，黄花處處新。", "相逢多醉客，少見獨醒人。", "打草只要蛇驚。"]'),
('db2fb0dc-87e5-415f-8f90-edc47b7284a8','偈頌一百四十一首  其一三一','釋師範','宋','宋诗','song-poetry','','[]','七佛已前，無消息處有消息，那箇不知。',54,'全唐诗/poet.song.190000.json','["七佛已前，無消息處有消息，那箇不知。", "七佛已後，有消息處無消息，是人不會。", "知不知，會不會，璞玉渾金，泥團土塊。"]'),
('11cc47ca-2b67-4de8-b655-f6af2763dafb','偈頌一百四十一首  其一三二','釋師範','宋','宋诗','song-poetry','','[]','一年十二月，只餘此一月。',36,'全唐诗/poet.song.190000.json','["一年十二月，只餘此一月。", "此月極盡處，又見明年月。", "循環既無端，何勞强分別。"]'),
('df514c40-186e-4438-bad3-790d8cb61406','偈頌一百四十一首  其一三三','釋師範','宋','宋诗','song-poetry','','[]','錦包特石，鐵裹泥團。',36,'全唐诗/poet.song.190000.json','["錦包特石，鐵裹泥團。", "現成活計，格外鄉談。", "明眼衲僧會不得，月移梅影上欄干。"]'),
('0dbc4dfd-adb1-4c72-a22c-a9c91c667b0f','偈頌一百四十一首  其一三四','釋師範','宋','宋诗','song-poetry','','[]','二月十五，瞿曇滅度。',20,'全唐诗/poet.song.190000.json','["二月十五，瞿曇滅度。", "諸天悲泣，羣魔鼓舞。"]'),
('fdca7bef-21cc-4b75-905b-770f0ec30be0','偈頌一百四十一首  其一三五','釋師範','宋','宋诗','song-poetry','','[]','春色依依，花木芳菲。',36,'全唐诗/poet.song.190000.json','["春色依依，花木芳菲。", "滿眼滿耳，絕毫絕釐。", "惟有子規知此意，一聲聲道不如歸。"]'),
('d5892954-483d-4163-a3d5-0b0a9f47db32','偈頌一百四十一首  其一三六','釋師範','宋','宋诗','song-poetry','','[]','黄蘗樹頭蜜果，破蓆袋裏珠珍，愈藏愈顯，日久日新。',40,'全唐诗/poet.song.190000.json','["黄蘗樹頭蜜果，破蓆袋裏珠珍，愈藏愈顯，日久日新。", "爭似颺從閑壁角，聽教人道不逢春。"]'),
('0df36e23-37cc-4ac5-b4bc-0bd94fd5b708','偈頌一百四十一首  其一三七','釋師範','宋','宋诗','song-poetry','','[]','少林消息絕，大地一團鐵。',32,'全唐诗/poet.song.190000.json','["少林消息絕，大地一團鐵。", "愁殺寒山子，無言倚寥泬，悲風流水聲嗚咽。"]'),
('4e8545f3-bd08-4e31-b58d-69b0dd71e4c9','偈頌一百四十一首  其一三八','釋師範','宋','宋诗','song-poetry','','[]','五五二十五，六六三十六。',42,'全唐诗/poet.song.190000.json','["五五二十五，六六三十六。", "縱以大衍數，終是數不足。", "數得足，無不足，碧眼黄頭，口啞舌禿。"]'),
('d3333114-50a9-4e86-a522-45ff1c315291','偈頌一百四十一首  其一三九','釋師範','宋','宋诗','song-poetry','','[]','我與這老漢，本自無交涉。',44,'全唐诗/poet.song.190000.json','["我與這老漢，本自無交涉。", "狹路偶相逢，歡喜成冤結。", "此結不可解，此冤不可雪。", "唵噴噴㗶㗶勑攝。"]'),
('ecf30dc0-29cb-401a-b741-da6e4329ce83','偈頌一百四十一首  其一四○','釋師範','宋','宋诗','song-poetry','','[]','朝碌碌，暮悠悠。',26,'全唐诗/poet.song.190000.json','["朝碌碌，暮悠悠。", "非懈怠，非精修。", "華亭船子，北地趙州。"]'),
('df200b50-f88e-4661-a3d3-0df98f4263a0','偈頌一百四十一首  其一四一','釋師範','宋','宋诗','song-poetry','','[]','九旬今已滿，那事竟如何。',48,'全唐诗/poet.song.190000.json','["九旬今已滿，那事竟如何。", "無爲無事人，往往成蹉跎。", "育王敢道不蹉跎，少年曾決龍蛇陣，老倒還同穉子歌。"]'),
('4a2c0aef-192d-44b5-9853-1c4250c94067','偈頌七十六首  其一','釋師範','宋','宋诗','song-poetry','','[]','廣大樓閣，門戶不扃。',32,'全唐诗/poet.song.190000.json','["廣大樓閣，門戶不扃。", "了事衲僧，未行先到。", "且到後如何，眼不見爲浄。"]'),
('aaf6bd91-9021-4b52-9e6c-e97344eb031a','偈頌七十六首  其二','釋師範','宋','宋诗','song-poetry','','[]','天上無彌勒，人間無釋迦。',27,'全唐诗/poet.song.190000.json','["天上無彌勒，人間無釋迦。", "燒香禮拜誰，唵摩尼達哩吽㗶吒。"]'),
('a1463388-2bfd-4dde-9db6-3fd000be1b68','偈頌七十六首  其三','釋師範','宋','宋诗','song-poetry','','[]','去年底，今年底。',38,'全唐诗/poet.song.190000.json','["去年底，今年底。", "輒莫明年更明年，年年只如是。", "黄花爛爛醉重陽，落葉蕭蕭愁滿地。"]'),
('3f7395f0-f17f-4f7e-becb-7d9ce6f399ba','偈頌七十六首  其四','釋師範','宋','宋诗','song-poetry','','[]','初冬時節又相催，浩浩諸方爐鞴開。',32,'全唐诗/poet.song.190000.json','["初冬時節又相催，浩浩諸方爐鞴開。", "獨有徑山文武火，不知煨殺幾人來。"]'),
('5285543d-f1dd-4099-a4d9-173e0195a71c','偈頌七十六首  其五','釋師範','宋','宋诗','song-poetry','','[]','五峰門下，三箇五箇。',56,'全唐诗/poet.song.190000.json','["五峰門下，三箇五箇。", "衲被幪頭，圍爐打坐。", "鼻笑瞿曇，平欺達磨。", "又誰管你，張三李六。", "諸方爐鞴正炎炎，何似徑山文武火。"]'),
('96d442d1-f956-427f-8624-51a3c03da93b','偈頌七十六首  其六','釋師範','宋','宋诗','song-poetry','','[]','赤手空拳下山去，滿船和月載歸來。',32,'全唐诗/poet.song.190000.json','["赤手空拳下山去，滿船和月載歸來。", "五峰可煞無慚愧，面面相看眼未開。"]'),
('f590feba-e191-4164-80dd-60a0d39bfc55','偈頌七十六首  其七','釋師範','宋','宋诗','song-poetry','','[]','同身共命，同氣連枝。',32,'全唐诗/poet.song.190000.json','["同身共命，同氣連枝。", "阿難合掌，迦葉揚眉。", "就中一句子，不許外人知。"]'),
('b4ee125c-cfe2-488f-aa7b-4815e9abeb1d','偈頌七十六首  其八','釋師範','宋','宋诗','song-poetry','','[]','不寒不熱，好箇時節。',26,'全唐诗/poet.song.190000.json','["不寒不熱，好箇時節。", "黄鶑頻織柳絲烟，子規猶哭松梢月。"]'),
('bba729a8-fa1f-45a3-acdc-5fbe6bc06878','偈頌七十六首  其九','釋師範','宋','宋诗','song-poetry','','[]','指天指地弄精魂，只爲生來無腦門。',54,'全唐诗/poet.song.190000.json','["指天指地弄精魂，只爲生來無腦門。", "韶石一棒打不殺，至今恩愛俱成冤。", "正當四月八，底事與誰論。", "門外千峰萬峰啼斷猿。"]'),
('331a6dfe-090a-46ea-a512-647c13d0a557','偈頌七十六首  其一○','釋師範','宋','宋诗','song-poetry','','[]','南北東西八百牛，時來群聚五峰頭。',32,'全唐诗/poet.song.190000.json','["南北東西八百牛，時來群聚五峰頭。", "饑餐飽卧松風裏，晝不拘兮夜不收。"]'),
('51a65b09-3e3f-4070-b321-17398cd1bbef','偈頌七十六首  其一一','釋師範','宋','宋诗','song-poetry','','[]','萬年石橋，三平石梁。',34,'全唐诗/poet.song.190000.json','["萬年石橋，三平石梁。", "總沒交涉，恰恰相當。", "足陌見錢買賣，一毫不用商量。"]'),
('6a8c51d9-9a85-46ac-815b-32a67fdaa177','偈頌七十六首  其一二','釋師範','宋','宋诗','song-poetry','','[]','劫灰飛盡見靈蹤，突兀凌霄對五峰。',32,'全唐诗/poet.song.190000.json','["劫灰飛盡見靈蹤，突兀凌霄對五峰。", "意在目前誰共委，相同扶起舊家風。"]'),
('d0871a81-3142-4c2a-bc88-36d77cf4f70d','偈頌七十六首  其一三','釋師範','宋','宋诗','song-poetry','','[]','五月端午節，底事不須說。',24,'全唐诗/poet.song.190000.json','["五月端午節，底事不須說。", "百怪盡潜蹤，羣魔俱殄滅。"]'),
('f866201e-6e3a-4b69-b864-1074d2a52cf7','偈頌七十六首  其一四','釋師範','宋','宋诗','song-poetry','','[]','去時萬木含愁色，歸日千峰展笑容。',32,'全唐诗/poet.song.190000.json','["去時萬木含愁色，歸日千峰展笑容。", "此意此心知有自，一爐香爇散天風。"]'),
('0c4f1a7c-b9bf-465c-920b-388af2a1f0a2','偈頌七十六首  其一五','釋師範','宋','宋诗','song-poetry','','[]','七月八月，或凉或熱。',46,'全唐诗/poet.song.190000.json','["七月八月，或凉或熱。", "景色凄清，蟬聲嗚咽。", "觀音菩薩將錢買胡餠，放下手却是饅頭，韶陽老人得一橛。"]'),
('8f35b181-990b-4b67-9748-7414f442b55a','偈頌七十六首  其一六','釋師範','宋','宋诗','song-poetry','','[]','逾月走紅塵，生涯隨處新。',48,'全唐诗/poet.song.190000.json','["逾月走紅塵，生涯隨處新。", "逢人陪笑面，接物强精神。", "僥倖遇明主，帡幪感重臣。", "歸來何以報，只此謝堯仁。"]'),
('377b3e95-9b96-4531-9805-2c5fbb21bc84','偈頌七十六首  其一七','釋師範','宋','宋诗','song-poetry','','[]','三分光陰二早過，靈臺一點不揩磨。',32,'全唐诗/poet.song.190000.json','["三分光陰二早過，靈臺一點不揩磨。", "貪生逐日區區去，喚不回頭爭奈何。"]'),
('cc47c06c-8fe8-4240-b822-b4c36a349a04','偈頌七十六首  其一八','釋師範','宋','宋诗','song-poetry','','[]','九日重陽節，東籬賞菊花。',24,'全唐诗/poet.song.190000.json','["九日重陽節，東籬賞菊花。", "歌懽公子事，淡薄野僧家。"]'),
('f94c5130-441a-4768-998c-05a0c12ad9ff','偈頌七十六首  其一九','釋師範','宋','宋诗','song-poetry','','[]','十五日以前，常在途中，不離家舍。',84,'全唐诗/poet.song.190000.json','["十五日以前，常在途中，不離家舍。", "十五日以後，常在家舍，不離途中。", "正當十五日，跛跛挈挈，百醜千拙。", "張都料，李作頭，鑿竅底鑿竅，著楔底著楔。", "雙徑來來去去人，長安夜夜家家月。"]'),
('35ced4df-5e98-48a9-a68b-a5a94818c90a','偈頌七十六首  其二○','釋師範','宋','宋诗','song-poetry','','[]','六月火邊坐，三冬水裏走。',50,'全唐诗/poet.song.190000.json','["六月火邊坐，三冬水裏走。", "怒中呈笑面，閙處伸毛手。", "滿載沒底船，歸來重抖擻。", "抖擻箇甚麽，蘇州有，常州有。"]'),
('76bcd360-ce69-45c8-8150-c05a9442bc02','偈頌七十六首  其二一','釋師範','宋','宋诗','song-poetry','','[]','傾蓋相逢，已成多事。',20,'全唐诗/poet.song.190000.json','["傾蓋相逢，已成多事。", "側鞭回首，早涉繁詞。"]'),
('2176f7f8-193e-4e44-b857-3d93ac9d5226','偈頌七十六首  其二二','釋師範','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','韶光去也誰能留，長江衮衮無暫休。',32,'全唐诗/poet.song.190000.json','["韶光去也誰能留，長江衮衮無暫休。", "人生既老不復少，此心未了空悠悠。"]'),
('148fbc1e-b431-4621-9b16-68752837e543','偈頌七十六首  其二三','釋師範','宋','宋诗','song-poetry','','[]','指天指地，徒張意氣。',38,'全唐诗/poet.song.190000.json','["指天指地，徒張意氣。", "一棒打殺，更無巴鼻。", "徑山今日都盧放過，且要一時腦門著地。"]'),
('465b0c79-adb0-4486-9a7c-ace5da8d50de','偈頌七十六首  其二四','釋師範','宋','宋诗','song-poetry','','[]','數百禪和數十州，襤襂破衲面搊搜。',32,'全唐诗/poet.song.190000.json','["數百禪和數十州，襤襂破衲面搊搜。", "諸方有道不肯學，甘共山僧拽木頭。"]'),
('0e5fe026-dd0d-46ad-9c7f-8457f9d32216','偈頌七十六首  其二五','釋師範','宋','宋诗','song-poetry','','[]','楊歧設忌，做盡鬼怪。',55,'全唐诗/poet.song.190000.json','["楊歧設忌，做盡鬼怪。", "徑山設忌，一無所解。", "隨分淡淡薄薄，點一盃茶，燒一炷香，謾禮三拜。", "若謂報德酬恩，兔子喫牛奶。"]'),
('9f37418a-6c05-462b-8fa7-f7e1b76efce0','偈頌七十六首  其二六','釋師範','宋','宋诗','song-poetry','','[]','時節不相饒，俄當七月朝。',48,'全唐诗/poet.song.190000.json','["時節不相饒，俄當七月朝。", "未聞桐葉落，已覺稻香飄。", "泣露蟬聲咽，迎秋雁影遥。", "有誰相共委，突兀對凌霄。"]'),
('17717103-b913-4b56-9c77-ed17fe9a8afa','偈頌七十六首  其二七','釋師範','宋','宋诗','song-poetry','','[]','一陽來復，萬彙發生。',20,'全唐诗/poet.song.190000.json','["一陽來復，萬彙發生。", "寒谷回春，冰河解凍。"]'),
('b6ebc2d0-12bd-4a17-bfe0-922fcdc10f37','偈頌七十六首  其二八','釋師範','宋','宋诗','song-poetry','','[]','昔年當此日，生箇老妖孽。',50,'全唐诗/poet.song.190000.json','["昔年當此日，生箇老妖孽。", "殃害大地人，有屈無處雪。", "雲門憤不甘，一棒要打殺。", "打不殺，至今年年有箇四月八。"]'),
('a9266e17-d364-4601-927f-67814abc9a9c','偈頌七十六首  其二九','釋師範','宋','宋诗','song-poetry','','[]','徑山今日結夏，不分上中下座。',49,'全唐诗/poet.song.190000.json','["徑山今日結夏，不分上中下座。", "健則運瓦搬椽，困則橫眠倒卧。", "誰管你孔夫子李老君胡達磨，善賈者不停死貨。"]'),
('0b020e98-13fe-4117-bc8b-67aa0d8b40dc','偈頌七十六首  其三○','釋師範','宋','宋诗','song-poetry','','[]','蜻蜓許是好蜻蜓，飛來飛去不曾停。',32,'全唐诗/poet.song.190000.json','["蜻蜓許是好蜻蜓，飛來飛去不曾停。", "捉來摘除兩箇翼，便是一枚大鐵釘。"]'),
('c1fc1f8b-a78a-4fb6-9531-45e9568d4f0e','偈頌七十六首  其三一','釋師範','宋','宋诗','song-poetry','','[]','這箇老凍儂，猛利如虎狼。',66,'全唐诗/poet.song.190000.json','["這箇老凍儂，猛利如虎狼。", "威凜萬壑風，眼摇百步光。", "我昔編其鬚，脫命於毫芒。", "至今數十載，毒恨不可忘。", "此世後世永永不願見，臨風誓此一爐香。"]'),
('3dbdfc62-70f9-419c-98b8-6f5511f627e5','偈頌七十六首  其三二','釋師範','宋','宋诗','song-poetry','','[]','千峰萬峰濃潑眼，十谿五谿深沒腰。',49,'全唐诗/poet.song.190000.json','["千峰萬峰濃潑眼，十谿五谿深沒腰。", "只有山翁喜相接，聲聲慚愧與難消。", "且道還有所得也無，蝦蟆口裏一粒椒。"]'),
('cdc15e18-aa30-40db-857e-7c53802c15ce','偈頌七十六首  其三三','釋師範','宋','宋诗','song-poetry','','[]','黄菊新開剪剪金，忻逢佳節興難禁。',32,'全唐诗/poet.song.190000.json','["黄菊新開剪剪金，忻逢佳節興難禁。", "臨高無語寫幽思，拄杖爲吾聊一吟。"]'),
('0be5782f-697a-4e16-b862-7daa55e8419d','偈頌七十六首  其三四','釋師範','宋','宋诗','song-poetry','','[]','二由一有，一亦莫守。',20,'全唐诗/poet.song.190000.json','["二由一有，一亦莫守。", "文殊普賢，泥豬疥狗。"]'),
('9b8642f4-6aa3-4a3f-8cff-b175fe5f44a0','偈頌七十六首  其三五','釋師範','宋','宋诗','song-poetry','','[]','天地之根，萬物之主。',26,'全唐诗/poet.song.190000.json','["天地之根，萬物之主。", "大千無以居其尊，劫石難以並其固。"]'),
('267ad96a-da5d-4691-9f29-6f25d3382a18','偈頌七十六首  其三六','釋師範','宋','宋诗','song-poetry','','[]','衲僧家，無本據。',38,'全唐诗/poet.song.190000.json','["衲僧家，無本據。", "動靜去留，無非活路。", "進一步，臨機沒回互。", "退一步，聲色如聾瞽。"]'),
('c1083918-0cff-4e58-a599-22e30c134f1d','偈頌七十六首  其三七','釋師範','宋','宋诗','song-poetry','','[]','此功德海無邊際，流出當人一念中。',32,'全唐诗/poet.song.190000.json','["此功德海無邊際，流出當人一念中。", "一念真心充法界，當知福報亦無窮。"]'),
('1e5738b1-f2b7-4fbe-81f4-f3660c8ce036','偈頌七十六首  其三八','釋師範','宋','宋诗','song-poetry','','[]','恍恍惚惚，杳杳冥冥，非精非物，非佛非心。',57,'全唐诗/poet.song.190000.json','["恍恍惚惚，杳杳冥冥，非精非物，非佛非心。", "缺齒老胡得之而不識，颺在乎嵩山之陰。", "諸人還識得麽，水上青青綠，元來是浮萍。"]'),
('f79c6cfa-050d-49da-ab47-8763edb22763','偈頌七十六首  其三九','釋師範','宋','宋诗','song-poetry','','[]','佛祖命脈，洞然明白。',20,'全唐诗/poet.song.190000.json','["佛祖命脈，洞然明白。", "黑漆屏風，松蘿亮隔。"]'),
('9d932d12-6e17-4616-b953-677f93022260','偈頌七十六首  其四○','釋師範','宋','宋诗','song-poetry','','[]','孟冬薄寒，仲冬嚴寒。',38,'全唐诗/poet.song.190000.json','["孟冬薄寒，仲冬嚴寒。", "寒則普天普地寒，結成冰片，凍破泥團。", "達磨不會，大難大難。"]'),
('6c0b71cd-57d7-416c-8f9d-44122eee7e60','偈頌七十六首  其四一','釋師範','宋','宋诗','song-poetry','','[]','雪山六年凍不死，一麻一麥餓不死。',42,'全唐诗/poet.song.190000.json','["雪山六年凍不死，一麻一麥餓不死。", "無端更道悟明星，躂倒至今扶不起。", "普賢蹙頞，文殊偷喜。"]'),
('e5ac28ac-02f0-49eb-b8ab-abe45dcce412','偈頌七十六首  其四二','釋師範','宋','宋诗','song-poetry','','[]','纔擬恁麽，便不恁麽。',36,'全唐诗/poet.song.190000.json','["纔擬恁麽，便不恁麽。", "成現生涯，陳年滯貨。", "雪峰輥出三箇毬，𡎺著嵩山破竈墮。"]'),
('e3f2d43e-24a2-475f-9f04-079d84e90926','偈頌七十六首  其四三','釋師範','宋','宋诗','song-poetry','','[]','只箇叢林粥飯僧，濫膺徽號愧無能。',32,'全唐诗/poet.song.190000.json','["只箇叢林粥飯僧，濫膺徽號愧無能。", "臨風將底祝君壽，遥指南山千萬層。"]'),
('51d77cc7-8ba1-47d1-8b14-d2a89215fe7c','偈頌七十六首  其四四','釋師範','宋','宋诗','song-poetry','','[]','土宿頷下長髭鬚，浄飯宮中生悉達。',32,'全唐诗/poet.song.190000.json','["土宿頷下長髭鬚，浄飯宮中生悉達。", "西天此土絕知音，千古萬古阿剌剌。"]'),
('994d6f92-d80f-48a5-ae93-132f23fb41f6','偈頌七十六首  其四五','釋師範','宋','宋诗','song-poetry','','[]','昨日九月九，過了重陽節。',93,'全唐诗/poet.song.190000.json','["昨日九月九，過了重陽節。", "今日憶重陽，陞堂何可說。", "擬欲問黄花，黄花雖有在東籬。", "擬欲問白醪，白醪雖有非我知。", "不如一時放下衲被幪頭，從教門外風颼颼，雨颼颼，幽州江口，採石渡頭，三三兩兩釣漁舟。"]'),
('38826f2f-76a1-41d0-b35d-7682b7459bd9','偈頌七十六首  其四六','釋師範','宋','宋诗','song-poetry','','[]','竿頭絲線放還收，時有金鱗上直鈎。',32,'全唐诗/poet.song.190000.json','["竿頭絲線放還收，時有金鱗上直鈎。", "風月滿船雖不惡，爭如峰頂冷湫湫。"]'),
('cd749f97-050c-4f42-9f92-8c2b674f3e7e','偈頌七十六首  其四七','釋師範','宋','宋诗','song-poetry','','[]','雪峰發九重聖箭，誰敢當鋒。',66,'全唐诗/poet.song.190000.json','["雪峰發九重聖箭，誰敢當鋒。", "三聖躍透網金麟，應無雜食。", "要明那畔事，須是這邊人。", "三家村裏，閙市叢中。", "妙應無私，臨機有準。", "不是冤家不與隣。"]'),
('d736c3ef-2971-4cd8-b90b-5b5251c52ae4','偈頌七十六首  其四八','釋師範','宋','宋诗','song-poetry','','[]','徑山結夏，不論功過。',47,'全唐诗/poet.song.190000.json','["徑山結夏，不論功過。", "飯來展鉢盂，困則伸脚卧。", "縱有千人萬人，只消一箇半箇。", "豈不見流支要打胡達磨。"]'),
('72aa4023-a018-4dd2-b0ff-f337caa0934e','偈頌七十六首  其四九','釋師範','宋','宋诗','song-poetry','','[]','雪峰輥毬，睦州擔版。',39,'全唐诗/poet.song.190000.json','["雪峰輥毬，睦州擔版。", "楊歧栗棘蓬，東山鐵酸餡。", "多處添，少處減，留得翠巖眉毛蓋眼。"]'),
('6cf55c41-612e-4bd6-93b7-6cda842d5c1e','偈頌七十六首  其五○','釋師範','宋','宋诗','song-poetry','','[]','一年十二月，月月有月半。',40,'全唐诗/poet.song.190000.json','["一年十二月，月月有月半。", "何獨喜中秋，一時爭賞玩。", "人人盡道十分圓，我道依前缺一半。"]'),
('82c701a8-009e-49d6-81c6-9718e53666da','偈頌七十六首  其五一','釋師範','宋','宋诗','song-poetry','','[]','徑山無伎倆，住院多阻障。',48,'全唐诗/poet.song.190000.json','["徑山無伎倆，住院多阻障。", "飯在平江府，口在凌霄上。", "河港既不通，千里空相望。", "暫假維摩手，一鉢共分餉。"]'),
('d754e5f9-9ab5-4e28-a95d-93b4a2d5b285','偈頌七十六首  其五二','釋師範','宋','宋诗','song-poetry','','[]','現成公案，何事不辦。',48,'全唐诗/poet.song.190000.json','["現成公案，何事不辦。", "百發百中，無邊無畔。", "捏不聚，撥不散。", "萬籟俱沉兮明月半窗，一色難分兮蘆花兩岸。"]'),
('fb4d4106-f542-418c-bf25-9c3b96288e80','偈頌七十六首  其五三','釋師範','宋','宋诗','song-poetry','','[]','達磨西來，添鹽減醤。',46,'全唐诗/poet.song.190000.json','["達磨西來，添鹽減醤。", "後代兒孫，千般萬樣。", "誰信碁盤石，元在凌霄上。", "山僧恁麽道，已是龜毛長數丈。"]'),
('286df3be-88d8-4bda-91e7-95d47cabe378','偈頌七十六首  其五四','釋師範','宋','宋诗','song-poetry','','[]','徑山門下，無彼無我。',51,'全唐诗/poet.song.190000.json','["徑山門下，無彼無我。", "大家疊足挨肩，共向無煙宿火。", "若是香匙火筯，不得動著。", "不見道丹霞燒木佛，院主眉鬚墮。"]'),
('1a643f2e-0b13-427d-89cb-a1305993f8d8','偈頌七十六首  其五五','釋師範','宋','宋诗','song-poetry','','[]','健時要坐禪，困時要打眠。',24,'全唐诗/poet.song.190000.json','["健時要坐禪，困時要打眠。", "肚饑須喫飯，陸地要行船。"]'),
('ed04798d-e9ca-4c74-bb0d-f75534ab3be9','偈頌七十六首  其五六','釋師範','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','戶牖見通，牆壁生礙。',20,'全唐诗/poet.song.190000.json','["戶牖見通，牆壁生礙。", "簸箕有唇，洞庭無蓋。"]'),
('b9267539-ba12-4d65-8659-928ec2b70c86','偈頌七十六首  其五七','釋師範','宋','宋诗','song-poetry','','[]','萬籟沉沉，孤月團團。',32,'全唐诗/poet.song.190000.json','["萬籟沉沉，孤月團團。", "葉零零兮山瘦，風蕭蕭兮夜寒，不知誰共倚欄干。"]'),
('d221afe7-949f-4367-856e-556f071b3ce7','偈頌七十六首  其五八','釋師範','宋','宋诗','song-poetry','','[]','去年不在家，虛過重陽節。',48,'全唐诗/poet.song.190000.json','["去年不在家，虛過重陽節。", "今年既在家，須要强施設。", "淡水煮冬瓜，真箇滋味別。", "不知滋味者，却似嚼生鐵。"]'),
('04a69581-d599-4969-969d-7b2550c30494','偈頌七十六首  其五九','釋師範','宋','宋诗','song-poetry','','[]','重巖風露清，深院霜天曉。',78,'全唐诗/poet.song.190000.json','["重巖風露清，深院霜天曉。", "一曲少林春，幾人彈得妙。", "自古彈者希，亦復聽者少。", "以之贈伯牙，伯牙不肯要。", "以之獻子期，子期拍手笑。", "休休，不如留取自彈一曲，何似大石調。"]'),
('14e55770-14a0-4f62-a21c-903dc8611a36','偈頌七十六首  其六○','釋師範','宋','宋诗','song-poetry','','[]','徑山不敢相謾，開口便見心肝。',28,'全唐诗/poet.song.190000.json','["徑山不敢相謾，開口便見心肝。", "今朝十月十五，下元解厄水官。"]'),
('086dbebc-f713-4440-8ed2-f1290167f6dd','偈頌七十六首  其六一','釋師範','宋','宋诗','song-poetry','','[]','天清地寧，慶襲一人。',37,'全唐诗/poet.song.190000.json','["天清地寧，慶襲一人。", "九州四海，咸被堯仁。", "熙熙然涵泳化育，猶千花萬卉之逢春。"]'),
('89886ec2-c328-4d3e-ad36-0c85def795f7','偈頌七十六首  其六二','釋師範','宋','宋诗','song-poetry','','[]','五峰門下，百種全無。',60,'全唐诗/poet.song.190000.json','["五峰門下，百種全無。", "僧牀迫窄，堂供蕭疎。", "脚下踏著底，破磚頭碎瓦礫。", "面前撞見底，王獦獠李麻胡。", "恁麽薄福住山，真箇辜負老胡。"]'),
('3fec0894-de43-4325-bc96-2c0b9d2a084c','偈頌七十六首  其六三','釋師範','宋','宋诗','song-poetry','','[]','禦寒古有家風在，三個柴頭品字煨。',32,'全唐诗/poet.song.190000.json','["禦寒古有家風在，三個柴頭品字煨。", "今日無柴又無炭，從教各自撥寒灰。"]'),
('5b338305-659e-409d-a5ef-619e1f584ebf','偈頌七十六首  其六四','釋師範','宋','宋诗','song-poetry','','[]','一見便見，更不再見。',20,'全唐诗/poet.song.190000.json','["一見便見，更不再見。", "張顛草書，李廣神箭。"]'),
('276837ae-2d33-4252-b991-b4962710144b','偈頌七十六首  其六五','釋師範','宋','宋诗','song-poetry','','[]','舊年佛法，說到臘月極盡頭。',42,'全唐诗/poet.song.190000.json','["舊年佛法，說到臘月極盡頭。", "新年佛法，又從正月還起頭。", "若論起頭與極頭，都盧只在拄杖頭。"]'),
('d14bf881-3c5b-4e7a-966f-3476a0a2157b','偈頌七十六首  其六六','釋師範','宋','宋诗','song-poetry','','[]','一二三四五，各各面相覩。',24,'全唐诗/poet.song.190000.json','["一二三四五，各各面相覩。", "甜瓜徹蔕甜，苦瓠連根苦。"]'),
('b1bc4eb2-f0bb-423e-9908-9e0ce9547834','偈頌七十六首  其六七','釋師範','宋','宋诗','song-poetry','','["\u8861\u5c71"]','曉來瑞氣鬰葱葱，流出恩波自九重。',32,'全唐诗/poet.song.190000.json','["曉來瑞氣鬰葱葱，流出恩波自九重。", "地厚天高何以報，飽看南嶽祝融峰。"]'),
('49ec7393-5c2c-445a-a839-38922cfc20d0','偈頌七十六首  其六八','釋師範','宋','宋诗','song-poetry','','[]','龍蛇混雜，凡聖交參。',20,'全唐诗/poet.song.190000.json','["龍蛇混雜，凡聖交參。", "儱儱侗侗，顢顢頇頇。"]'),
('7c23c9c7-d627-42fd-bc5f-a3c7641cee84','偈頌七十六首  其六九','釋師範','宋','宋诗','song-poetry','','[]','燒香草舍蚊煙，禮拜小兒匍匐。',35,'全唐诗/poet.song.190000.json','["燒香草舍蚊煙，禮拜小兒匍匐。", "楊歧頂上握拳，何似鎮州蘿蔔。", "噫，有年無德。"]'),
('a177281b-af0a-44b9-be36-0ca88c4ce594','偈頌七十六首  其七○','釋師範','宋','宋诗','song-poetry','','[]','一夏已滿，無事不辦。',20,'全唐诗/poet.song.190000.json','["一夏已滿，無事不辦。", "遂府鉢盂，邛州磁碗。"]'),
('6e76d66b-41ae-48b4-909b-a7500f71ea33','偈頌七十六首  其七一','釋師範','宋','宋诗','song-poetry','','[]','指月與話月，檐雪共填井。',43,'全唐诗/poet.song.190000.json','["指月與話月，檐雪共填井。", "玩月與捧月，未免弄光影。", "月聻彷彿似鹽官扇子，元來恰是雲門胡餠。"]'),
('f1111fa0-2425-4edc-991a-90f3ab379172','偈頌七十六首  其七二','釋師範','宋','宋诗','song-poetry','','[]','世人住處我不住，世人行處我不行。',35,'全唐诗/poet.song.190000.json','["世人住處我不住，世人行處我不行。", "天下叢林今日開爐，諸方老凍儂聲鼓集衆。"]'),
('11725655-e425-4462-8735-92f09e08bba4','偈頌七十六首  其七三','釋師範','宋','宋诗','song-poetry','','[]','喚起凌霄峰頂龍，縱橫變化妙難窮。',32,'全唐诗/poet.song.190000.json','["喚起凌霄峰頂龍，縱橫變化妙難窮。", "一聲霹靂擎頭角，三日爲霖四海通。"]'),
('5c3b7bf6-1bf7-4daa-ab4d-644a1d3bff44','偈頌七十六首  其七四','釋師範','宋','宋诗','song-poetry','','[]','擾擾怱怱，晨鷄暮鐘。',20,'全唐诗/poet.song.190000.json','["擾擾怱怱，晨鷄暮鐘。", "瑞巖不會，喚主人翁。"]'),
('85838768-f85e-4fb5-9751-dcd745582acb','偈頌七十六首  其七五','釋師範','宋','宋诗','song-poetry','','[]','雲收霧歛，地闢天開。',32,'全唐诗/poet.song.190000.json','["雲收霧歛，地闢天開。", "處處彌勒，門門善財。", "安得真男子，同上黄金臺。"]'),
('5c6f0ca8-7d80-46d6-ba7e-4d2b3407cf15','偈頌七十六首  其七六','釋師範','宋','宋诗','song-poetry','','[]','二月復二月，韶光尚可留。',48,'全唐诗/poet.song.190000.json','["二月復二月，韶光尚可留。", "雪消深澗底，花發舊枝頭。", "萬木寒威解，千峰翠色浮。", "有誰知此意，相共倚危樓。"]'),
('2f447b3e-1123-4b54-a67e-95018268a4bf','偈頌十七首  其一','釋師範','宋','宋诗','song-poetry','','[]','二千年前，尺不如寸。',105,'全唐诗/poet.song.190000.json','["二千年前，尺不如寸。", "二千年後，寸不如尺。", "清凉到這裏，眼不見爲浄。", "只將三文錢，娶箇黑老婆。", "長裙短袖，拖泥带水，隈隈𣯧𣯧。", "且恁麽過，更誰管你。", "結制解制，長期短期。", "殺生護生，得念失念。", "阿呵呵，少林穿耳客，元是老臊胡。"]'),
('32542543-5165-4c30-bec5-6293e1463bcf','偈頌十七首  其二','釋師範','宋','宋诗','song-poetry','','[]','法無去來，無動轉相。',50,'全唐诗/poet.song.190000.json','["法無去來，無動轉相。", "燈籠掛在露柱邊，露柱掛在燈籠上。", "一年三百六十日，日日一般，一日十二時，時時一樣。"]'),
('321c239b-b8aa-4a2b-8208-044ed1d82790','偈頌十七首  其三','釋師範','宋','宋诗','song-poetry','','[]','滴水滴凍，渾無罅縫。',20,'全唐诗/poet.song.190000.json','["滴水滴凍，渾無罅縫。", "明眼衲僧，失却鼻孔。"]'),
('0eb8ac81-5bbb-490f-b804-d9c14570658b','偈頌十七首  其四','釋師範','宋','宋诗','song-poetry','','[]','大地黑如漆，古今無消息。',24,'全唐诗/poet.song.190000.json','["大地黑如漆，古今無消息。", "達磨老臊胡，九年空面壁。"]'),
('391172a0-fbcf-4cb4-9ad6-4fd1f9b520b5','偈頌十七首  其五','釋師範','宋','宋诗','song-poetry','','[]','坐斷主人翁，不落第二見。',22,'全唐诗/poet.song.190000.json','["坐斷主人翁，不落第二見。", "一念萬年，萬年一念。"]'),
('69d90965-af64-43ee-a4a1-fbc85a2fb6f8','偈頌十七首  其六','釋師範','宋','宋诗','song-poetry','','[]','百二十日夏，如今已告圓。',24,'全唐诗/poet.song.190000.json','["百二十日夏，如今已告圓。", "就中一句子，切忌錯流傳。"]'),
('4a936c6f-e8b2-4e91-80f0-84d716c20a78','偈頌十七首  其七','釋師範','宋','宋诗','song-poetry','','[]','六爻既窮，陰魔自殄。',20,'全唐诗/poet.song.190000.json','["六爻既窮，陰魔自殄。", "一陽來復，吾道大亨。"]'),
('1294ff64-e721-4476-b1a3-406276c6f88b','偈頌十七首  其八','釋師範','宋','宋诗','song-poetry','','[]','面門一思，長時無間。',20,'全唐诗/poet.song.190000.json','["面門一思，長時無間。", "見成句子，百味完全。"]'),
('55e72ef9-288e-4282-a072-b5c395a8f264','偈頌十七首  其九','釋師範','宋','宋诗','song-poetry','','["\u8861\u5c71"]','諸佛不出世，祖師不西來。',24,'全唐诗/poet.song.190000.json','["諸佛不出世，祖師不西來。", "顢頇一句子，南嶽對天台。"]'),
('68da4abe-a75b-4ffc-9295-76245edd3828','偈頌十七首  其一○','釋師範','宋','宋诗','song-poetry','','[]','舊歲今宵去，去去實不去。',40,'全唐诗/poet.song.190000.json','["舊歲今宵去，去去實不去。", "新年明日來，來來實不來。", "萬古長空無變異，循環日月空相催。"]'),
('7d14bb7a-2f86-4e29-9093-dd082fd9931a','偈頌十七首  其一一','釋師範','宋','宋诗','song-poetry','','[]','機不離位，沉乎醉鄉。',20,'全唐诗/poet.song.190000.json','["機不離位，沉乎醉鄉。", "語不離窠，滯在金網。"]'),
('2c0c38c2-ffae-44ae-bd4d-75c05f8cb89b','偈頌十七首  其一二','釋師範','宋','宋诗','song-poetry','','[]','土木場中過兩冬，朝怱怱兮暮怱怱。',32,'全唐诗/poet.song.190000.json','["土木場中過兩冬，朝怱怱兮暮怱怱。", "從來業識無憑據，說甚東山大脫空。"]'),
('d704c5e8-db38-40bc-b291-55203633ee46','偈頌十七首  其一三','釋師範','宋','宋诗','song-poetry','','[]','言無展事，語不投機。',20,'全唐诗/poet.song.190000.json','["言無展事，語不投機。", "承言者喪，滯句者迷。"]'),
('7b65e5d5-609d-40f8-b338-597073cb8a8a','偈頌十七首  其一四','釋師範','宋','宋诗','song-poetry','','[]','舊歲即新歲，新年即舊年。',24,'全唐诗/poet.song.190000.json','["舊歲即新歲，新年即舊年。", "要知新歲歲，元是舊年年。"]'),
('831904a5-333e-4fda-9938-276f94ab62e6','偈頌十七首  其一五','釋師範','宋','宋诗','song-poetry','','[]','江南兩浙，春寒秋熱。',26,'全唐诗/poet.song.190000.json','["江南兩浙，春寒秋熱。", "塵沙劫事在如今，如今不異塵沙劫。"]'),
('fb611e1a-5086-48bb-8703-6e770248d5d8','偈頌十七首  其一六','釋師範','宋','宋诗','song-poetry','','[]','光景怱怱若逝川，舊年去了又新年。',32,'全唐诗/poet.song.190000.json','["光景怱怱若逝川，舊年去了又新年。", "年來年去自來去，底事何曾有變遷。"]'),
('d4a7f4d4-5ee6-4dfc-954a-0f04eb2d811c','偈頌十七首  其一七','釋師範','宋','宋诗','song-poetry','','[]','金木水火土，大蟲元是虎。',24,'全唐诗/poet.song.190000.json','["金木水火土，大蟲元是虎。", "堪笑李將軍，藍田空沒羽。"]'),
('833682ac-68f1-4be1-b5a4-32ed85a12d75','頌古四十四首  其一','釋師範','宋','宋诗','song-poetry','','[]','靈山一會善隄防，蠱毒之家水莫嘗。',32,'全唐诗/poet.song.190000.json','["靈山一會善隄防，蠱毒之家水莫嘗。", "迦葉無端霑一滴，至今猶自面皮黄。"]'),
('2017a4b8-5c4f-459f-8299-7eb3ba76df0b','頌古四十四首  其二','釋師範','宋','宋诗','song-poetry','','[]','古老相傳鬼叫坑，看來人鬼不多爭。',32,'全唐诗/poet.song.190000.json','["古老相傳鬼叫坑，看來人鬼不多爭。", "早知鬼便是人做，夜半三更也可行。"]'),
('dc61e6d2-66fa-4101-a773-daa57a07b2d2','頌古四十四首  其三','釋師範','宋','宋诗','song-poetry','','[]','君王一語出如綸，尊者眉毛八字分。',32,'全唐诗/poet.song.190000.json','["君王一語出如綸，尊者眉毛八字分。", "四海風清煙浪靜，碧天無際水無垠。"]'),
('b99300d4-b45c-4629-b9a2-4a8195881031','頌古四十四首  其四','釋師範','宋','宋诗','song-poetry','','[]','大士錯解注，誌公錯注解。',24,'全唐诗/poet.song.190000.json','["大士錯解注，誌公錯注解。", "臭肉積屠門，堪笑無人買。"]'),
('21339197-0a09-4cd3-aa96-9cd846ea2e7a','頌古四十四首  其五','釋師範','宋','宋诗','song-poetry','','[]','雨散雲收後，崔嵬數十峰。',24,'全唐诗/poet.song.190000.json','["雨散雲收後，崔嵬數十峰。", "王維雖敏手，難落筆頭蹤。"]'),
('fe6f0ebd-675d-404c-b880-9ccbd4706180','頌古四十四首  其六','釋師範','宋','宋诗','song-poetry','','[]','春生夏長，淡飯粗茶。',20,'全唐诗/poet.song.190000.json','["春生夏長，淡飯粗茶。", "魚投臭水，彩奔齪家。"]'),
('05a5b1ed-9e46-489d-8a19-e8e6984c367f','頌古四十四首  其七','釋師範','宋','宋诗','song-poetry','','[]','地神歸地，天神歸天。',20,'全唐诗/poet.song.190000.json','["地神歸地，天神歸天。", "慇懃奉送，寶馬金錢。"]'),
('206b3319-26cb-4b59-b811-8951206ee9a5','頌古四十四首  其八','釋師範','宋','宋诗','song-poetry','','[]','一柄無情雪刃刀，當鋒誰敢犯秋毫。',32,'全唐诗/poet.song.190000.json','["一柄無情雪刃刀，當鋒誰敢犯秋毫。", "馬師父子親提掇，血噴千山風怒號。"]'),
('a1d38f4e-4a57-4b7d-8a2d-fa0088090b93','頌古四十四首  其九','釋師範','宋','宋诗','song-poetry','','[]','諸子生涯各有成，從來孝順兩邊生。',32,'全唐诗/poet.song.190000.json','["諸子生涯各有成，從來孝順兩邊生。", "貪歡一夜渾家樂，失曉連忙打五更。"]'),
('c4fbf89d-0631-4218-b75b-1fb9070ae984','頌古四十四首  其一○','釋師範','宋','宋诗','song-poetry','','[]','日面月面，突出難辨。',20,'全唐诗/poet.song.190000.json','["日面月面，突出難辨。", "擬欲抬眸，空中兩片。"]'),
('fb3d9fbb-dfc6-44bb-8bb0-5da9e4a6d22f','頌古四十四首  其一一','釋師範','宋','宋诗','song-poetry','','[]','金毛獅子，生鐵秤鎚。',20,'全唐诗/poet.song.190000.json','["金毛獅子，生鐵秤鎚。", "渾崙無縫，切忌針錐。"]'),
('fb33766b-b865-48b9-b5f8-ff72985fde78','頌古四十四首  其一二','釋師範','宋','宋诗','song-poetry','','[]','衝開碧落松千尺，截斷紅塵水一谿。',32,'全唐诗/poet.song.190000.json','["衝開碧落松千尺，截斷紅塵水一谿。", "飽食高眠人不到，日從東出又沉西。"]'),
('fe1f9d2c-0d9b-4e36-a7c8-9ba43eedcfbd','頌古四十四首  其一三','釋師範','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽峰前老石頭，憐兒何事不知羞。',32,'全唐诗/poet.song.190000.json','["南嶽峰前老石頭，憐兒何事不知羞。", "爲人點眼長伸脚，直至而今懶不收。"]'),
('84423e9a-aaab-472d-972d-e85209247092','頌古四十四首  其一四','釋師範','宋','宋诗','song-poetry','','[]','鋪席宏開見也麽，買人何似看人多。',32,'全唐诗/poet.song.190000.json','["鋪席宏開見也麽，買人何似看人多。", "十成好箇吹毛劍，只作陶家壁上梭。"]'),
('d3a965e4-a79b-4e24-94c9-1073b02693cb','頌古四十四首  其一五','釋師範','宋','宋诗','song-poetry','','[]','兀兀地思量，無可得思量。',40,'全唐诗/poet.song.190000.json','["兀兀地思量，無可得思量。", "無可思量處，真箇好思量。", "大庾嶺頭逢六祖，鼇山店上見曾郎。"]'),
('94b94db6-00d6-4981-9685-ab1de4fd577e','頌古四十四首  其一六','釋師範','宋','宋诗','song-poetry','','[]','持來送去樣團團，覆陰兒孫義不寒。',32,'全唐诗/poet.song.190000.json','["持來送去樣團團，覆陰兒孫義不寒。", "何似當時休擘破，渾崙留與後人看。"]'),
('887a0e33-f3d2-452d-adbf-a54ff82a488c','頌古四十四首  其一七','釋師範','宋','宋诗','song-poetry','','[]','蘿蔔從來出鎮州，城南門外水東流。',32,'全唐诗/poet.song.190000.json','["蘿蔔從來出鎮州，城南門外水東流。", "饒君說得渾相似，須是親曾到地頭。"]'),
('05ec4417-908f-43f1-bf3f-933e8db21408','頌古四十四首  其一八','釋師範','宋','宋诗','song-poetry','','[]','千載巖前樹，曾無刀斧痕。',24,'全唐诗/poet.song.190000.json','["千載巖前樹，曾無刀斧痕。", "羚羊纔觸著，滿地葉紛紛。"]'),
('47385103-5e66-4301-9239-89b3f708091c','頌古四十四首  其一九','釋師範','宋','宋诗','song-poetry','','[]','混成一氣，周行四時。',20,'全唐诗/poet.song.190000.json','["混成一氣，周行四時。", "惟天爲大，惟堯則之。"]'),
('3ce2b313-3742-4e34-8d33-e12b093b0c17','頌古四十四首  其二○','釋師範','宋','宋诗','song-poetry','','[]','閃爍旌旗驟往來，幾人遥望起疑猜。',32,'全唐诗/poet.song.190000.json','["閃爍旌旗驟往來，幾人遥望起疑猜。", "此時若得樊公脚，一踏鴻門兩扇開。"]'),
('93d5d921-3727-40de-9905-d7295d0b921a','頌古四十四首  其二一','釋師範','宋','宋诗','song-poetry','','[]','驟馬加鞭上酒樓，何如坐地看楊州。',32,'全唐诗/poet.song.190000.json','["驟馬加鞭上酒樓，何如坐地看楊州。", "是非長短俱裁了，鼠竊終難似狗偷。"]'),
('d62ea0b4-dda8-4e52-8fc3-a1bfcc8c1789','頌古四十四首  其二二','釋師範','宋','宋诗','song-poetry','','[]','臺山路上箇婆婆，平地無風起丈波。',32,'全唐诗/poet.song.190000.json','["臺山路上箇婆婆，平地無風起丈波。", "下却斗門通底閘，更無一滴到黄河。"]'),
('3548a042-d401-4862-acf2-5538af606fa9','頌古四十四首  其二三','釋師範','宋','宋诗','song-poetry','','[]','風前一曲動離愁，那箇行人不舉頭。',32,'全唐诗/poet.song.190000.json','["風前一曲動離愁，那箇行人不舉頭。", "手把花枝半遮面，不令人見轉風流。"]'),
('32f7350c-e6ab-419c-8687-0fd10999ba87','頌古四十四首  其二四','釋師範','宋','宋诗','song-poetry','','[]','分明指出與人看，多少禪和被熱瞞。',32,'全唐诗/poet.song.190000.json','["分明指出與人看，多少禪和被熱瞞。", "舉目只知看雨勢，不知秋水沒欄干。"]'),
('56593436-a533-4ba6-9e76-a44166eea1d3','頌古四十四首  其二五','釋師範','宋','宋诗','song-poetry','','[]','共樂昇平道泰時，相逢終不展鎗旗。',32,'全唐诗/poet.song.190000.json','["共樂昇平道泰時，相逢終不展鎗旗。", "隨宜淡飯清茶外，困卧閑行幾箇知。"]'),
('b32c8b43-4b5e-45f1-acba-4614d0123a62','頌古四十四首  其二六','釋師範','宋','宋诗','song-poetry','','[]','賊火相逢恰五更，見成贓物不須爭。',32,'全唐诗/poet.song.190000.json','["賊火相逢恰五更，見成贓物不須爭。", "暗中多少都分了，天曉依前各自行。"]'),
('207ae52c-4d5c-4095-bf4a-4140894d215d','頌古四十四首  其二七','釋師範','宋','宋诗','song-poetry','','[]','銅公塘，鐵奉化。',28,'全唐诗/poet.song.190000.json','["銅公塘，鐵奉化。", "得人憎，得人怕。", "不是明州人，定說蘇州語。"]'),
('4cfdbcf2-0e85-43cf-a0e8-6cf46d1c4c15','頌古四十四首  其二八','釋師範','宋','宋诗','song-poetry','','[]','洞山平地露尸骸，庵主將身一處埋。',32,'全唐诗/poet.song.190000.json','["洞山平地露尸骸，庵主將身一處埋。", "狼藉髑髏相枕藉，悲風愁霧不勝懷。"]'),
('ae9623bc-ff5c-440f-93af-d08b77f42503','頌古四十四首  其二九','釋師範','宋','宋诗','song-poetry','','[]','骨裹皮兮皮裹骨，大隨放出遼天鶻。',32,'全唐诗/poet.song.190000.json','["骨裹皮兮皮裹骨，大隨放出遼天鶻。", "東西南北謾擡眸，不知已過新羅國。"]'),
('6f184097-700d-4c6b-94de-f2a69a82b7b6','頌古四十四首  其三○','釋師範','宋','宋诗','song-poetry','','[]','頑皮老虎卧林丘，一任傍人放滴油。',32,'全唐诗/poet.song.190000.json','["頑皮老虎卧林丘，一任傍人放滴油。", "滿肚只因曾飽肉，縱加呼喚懶擡頭。"]'),
('735c8e38-c339-4dc6-9ad9-2e84421f1ef3','頌古四十四首  其三一','釋師範','宋','宋诗','song-poetry','','[]','起滅不停誰解看，當機一拶透重關。',32,'全唐诗/poet.song.190000.json','["起滅不停誰解看，當機一拶透重關。", "東西總是長安路，蕩蕩無拘自往還。"]'),
('44e100a1-8fba-4e4d-8889-578afd5d44fb','頌古四十四首  其三二','釋師範','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','同舟共賞洞庭春，終日徘徊柳岸陰。',32,'全唐诗/poet.song.190000.json','["同舟共賞洞庭春，終日徘徊柳岸陰。", "却得漁人加櫓棹，等閑抹過碧波心。"]'),
('d874c63b-6fcd-4bd9-99ad-853365123719','頌古四十四首  其三三','釋師範','宋','宋诗','song-poetry','','[]','一片荆山璞，分明辨者難。',24,'全唐诗/poet.song.190000.json','["一片荆山璞，分明辨者難。", "幾人偷眼覷，只作石頭看。"]'),
('d8baf90d-75d6-40b8-b70c-e75aa0059020','頌古四十四首  其三四','釋師範','宋','宋诗','song-poetry','','[]','種田博飯喫，飽卧長伸脚。',40,'全唐诗/poet.song.190000.json','["種田博飯喫，飽卧長伸脚。", "把將三界來，安向左邊著。", "引得龍牙老古錐，手裏把柄破木杓。"]'),
('5fadb7c1-81ba-4aad-a152-13d7c405fa8b','頌古四十四首  其三五','釋師範','宋','宋诗','song-poetry','','[]','一擲神杯定吉凶，再占重卜轉靈通。',32,'全唐诗/poet.song.190000.json','["一擲神杯定吉凶，再占重卜轉靈通。", "分明見了今年事，却說明年事不同。"]'),
('c08444f4-e453-4f45-80e7-75cd6e516e98','頌古四十四首  其三六','釋師範','宋','宋诗','song-poetry','','[]','夢裏思歸問故鄉，明明說與尚徉狂。',32,'全唐诗/poet.song.190000.json','["夢裏思歸問故鄉，明明說與尚徉狂。", "白雲盡處重回首，無限青山對夕陽。"]'),
('aac92201-01d5-4cc1-9868-bb38f5cd7f22','頌古四十四首  其三七','釋師範','宋','宋诗','song-poetry','','[]','紅輪決定沉西去，未審魂靈往那方。',32,'全唐诗/poet.song.190000.json','["紅輪決定沉西去，未審魂靈往那方。", "哭慟一聲無處避，櫂頭親見本爺娘。"]'),
('bb224acd-553b-4c16-aabb-28b331b90d52','頌古四十四首  其三八','釋師範','宋','宋诗','song-poetry','','[]','一年三百六十日，日日日從東畔出。',32,'全唐诗/poet.song.190000.json','["一年三百六十日，日日日從東畔出。", "昨夜黄昏又落西，茫茫無處尋蹤跡。"]'),
('165ce4ee-c50b-4c43-9f0f-4cadd78e48a0','頌古四十四首  其三九','釋師範','宋','宋诗','song-poetry','','[]','矜誇富貴，賤賣赤窮。',20,'全唐诗/poet.song.190000.json','["矜誇富貴，賤賣赤窮。", "殺人可恕，無禮難容。"]'),
('f9682fe3-11d5-4e07-a591-eedb51cafc26','頌古四十四首  其四○','釋師範','宋','宋诗','song-poetry','','[]','臘月三十日，開口便爲敕。',24,'全唐诗/poet.song.190000.json','["臘月三十日，開口便爲敕。", "更擬問如何，明朝正月一。"]'),
('3127a843-9c14-4155-a5c0-b06cbb385b3e','頌古四十四首  其四一','釋師範','宋','宋诗','song-poetry','','[]','深深親下拜，三代禮全該。',24,'全唐诗/poet.song.190000.json','["深深親下拜，三代禮全該。", "此意如不然，玉帛云乎哉。"]'),
('8d1513ef-7c60-4dc8-99a3-8e81f3cb4321','頌古四十四首  其四二','釋師範','宋','宋诗','song-poetry','','[]','大匠不巧，大儒不學。',38,'全唐诗/poet.song.190000.json','["大匠不巧，大儒不學。", "動輒中方圓，舉皆成禮樂。", "堪笑鄉村賣卜人，徒勞鑽破烏龜殻。"]'),
('3368af7e-b2ba-437e-8947-fc4b12b56eb8','頌古四十四首  其四三','釋師範','宋','宋诗','song-poetry','','[]','黯澹灘，黯澹灘，十隻船來九隻翻。',37,'全唐诗/poet.song.190000.json','["黯澹灘，黯澹灘，十隻船來九隻翻。", "惟有三山陳上舍，我向陸地裏行，看你奈我何。"]'),
('4744e58f-3a41-402e-96f6-5b5c818207a5','頌古四十四首  其四四','釋師範','宋','宋诗','song-poetry','','[]','山花似錦水如藍，突出乾坤不露顔。',32,'全唐诗/poet.song.190000.json','["山花似錦水如藍，突出乾坤不露顔。", "曾踏武陵溪畔路，洞中春色異人間。"]'),
('450d2f5c-f7c8-47f0-b92a-423c8e0d63cb','花光十梅 懸崖放下','釋師範','宋','宋诗','song-poetry','','[]','萬仞崖頭自放身，始知花發不干春。',32,'全唐诗/poet.song.190000.json','["萬仞崖頭自放身，始知花發不干春。", "更從箇裏尋枝葉，笑倒當年樹下人。"]'),
('241e7aef-beab-42f7-9542-5ea8ff867715','花光十梅 絕後再甦','釋師範','宋','宋诗','song-poetry','','[]','孤根脫落偃蒼苔，冷地無端笑眼開。',32,'全唐诗/poet.song.190000.json','["孤根脫落偃蒼苔，冷地無端笑眼開。", "莫怪雪霜欺不得，只因曾向死中來。"]'),
('0c3d5e5c-6da5-4ab3-a7b8-c0304f5c5956','花光十梅 平地回春','釋師範','宋','宋诗','song-poetry','','[]','萬木千花凍未醒，東君無處覓歸程。',32,'全唐诗/poet.song.190000.json','["萬木千花凍未醒，東君無處覓歸程。", "擡眸忽見春風面，的皪枝頭數點青。"]'),
('e1bd79c0-c605-4419-b387-0a72cd4f73f2','花光十梅 淡中有味','釋師範','宋','宋诗','song-poetry','','[]','半開半合榮枯外，似有似無閑淡中。',32,'全唐诗/poet.song.190000.json','["半開半合榮枯外，似有似無閑淡中。", "自是一般風味別，笑他紅紫鬭芳叢。"]'),
('c3370ed8-3731-4184-b035-3ad5763429ea','花光十梅 一枝橫出','釋師範','宋','宋诗','song-poetry','','[]','莫謂南枝能放花，傍分北秀亦堪誇。',32,'全唐诗/poet.song.190000.json','["莫謂南枝能放花，傍分北秀亦堪誇。", "黄梅不用爭高下，草本傳來共一家。"]'),
('42c64ee5-c086-48f3-b688-a6c950cadf6f','花光十梅 五葉聯芳','釋師範','宋','宋诗','song-poetry','','[]','花開五葉自芬芳，欺麝欺蘭別是香。',32,'全唐诗/poet.song.190000.json','["花開五葉自芬芳，欺麝欺蘭別是香。", "傳得靈根元不朽，豈惟流落在花光。"]'),
('30fee103-8b0b-450c-b154-c0ec065007ea','花光十梅 正偏自在','釋師範','宋','宋诗','song-poetry','','[]','花合花開有正偏，不完全處却完全。',32,'全唐诗/poet.song.190000.json','["花合花開有正偏，不完全處却完全。", "要知根蔕從何得，多見生埋洞水邊。"]'),
('653456ed-82ec-4721-8c8c-da47f0060b7a','花光十梅 高下隨宜','釋師範','宋','宋诗','song-poetry','','[]','樹有高低枝短長，花開隨處恰相當。',32,'全唐诗/poet.song.190000.json','["樹有高低枝短長，花開隨處恰相當。", "都緣妙得毫端趣，豎抹橫拖總不妨。"]'),
('4387ad87-3a37-48ce-b557-f7dbd15f72c5','花光十梅 幻花滅盡','釋師範','宋','宋诗','song-poetry','','[]','花分枝北與枝南，向背橫斜有許般。',32,'全唐诗/poet.song.190000.json','["花分枝北與枝南，向背橫斜有許般。", "何待支郎强描邈，開時便作謝時看。"]'),
('8925098c-a755-4ac0-ab48-e2deecf9222a','花光十梅 實相常圓','釋師範','宋','宋诗','song-poetry','','[]','黄底自黄青底青，枝頭一一見天真。',32,'全唐诗/poet.song.190000.json','["黄底自黄青底青，枝頭一一見天真。", "如今酸澀都忘了，核子如何舉似人。"]'),
('b474f881-fe54-4ab4-89c6-bc413113566f','朝陽穿破衲','釋師範','宋','宋诗','song-poetry','','[]','橫片豎片胡亂搭，長針短針信意聯。',32,'全唐诗/poet.song.190000.json','["橫片豎片胡亂搭，長針短針信意聯。", "但見日頭東畔出，不知塵世是何年。"]'),
('3f4a112a-6519-4c77-984a-48ee0c0df96c','對月了殘經','釋師範','宋','宋诗','song-poetry','','[]','入海算沙徒自疲，風前月下幾攢眉。',32,'全唐诗/poet.song.190000.json','["入海算沙徒自疲，風前月下幾攢眉。", "即今休去便休去，欲覓了時無了時。"]'),
('ccf33995-10a1-4f7a-8bde-c67fa33ee30d','入己還閉','釋師範','宋','宋诗','song-poetry','','[]','南方經歷幾雲煙，收得珍奇貨滿船。',32,'全唐诗/poet.song.190000.json','["南方經歷幾雲煙，收得珍奇貨滿船。", "彈指便風帆到岸，一時翻作大光錢。"]'),
('37dbb556-3db9-40c9-99f8-73cf0f7c5656','懷古','釋師範','宋','宋诗','song-poetry','','[]','空山寥寥，黄葉蕭蕭。',58,'全唐诗/poet.song.190000.json','["空山寥寥，黄葉蕭蕭。", "斯人不來兮，暮待之以朝。", "斯人或來兮，兩無語而意消。", "歸去也，衣飄飄，路迢迢。", "誰同其孤標，月在青霄。"]'),
('d3b54f12-fd7d-44a7-b137-08ceabf24ef4','四威儀  其一','釋師範','宋','宋诗','song-poetry','','[]','山中行，移步放教輕。',20,'全唐诗/poet.song.190000.json','["山中行，移步放教輕。", "無別意，恐他幽鳥驚。"]'),
('ef56d9c0-a28e-43c7-8bd7-00d1780fe97d','四威儀  其二','釋師範','宋','宋诗','song-poetry','','[]','山中住，落葉不知數。',20,'全唐诗/poet.song.190000.json','["山中住，落葉不知數。", "無人掃，翳却松門路。"]'),
('8a5202f2-295d-4cbe-801c-28e306332da1','四威儀  其三','釋師範','宋','宋诗','song-poetry','','[]','山中坐，習閑成懶惰。',20,'全唐诗/poet.song.190000.json','["山中坐，習閑成懶惰。", "少獻花，但見猿偷菓。"]'),
('59c7838f-9adb-4a28-b4dd-3d509f8124a1','四威儀  其四','釋師範','宋','宋诗','song-poetry','','[]','山中卧，不知時節過。',20,'全唐诗/poet.song.190000.json','["山中卧，不知時節過。", "雨打窗，好夢都驚破。"]'),
('1a413b49-2251-436a-b9bc-b4fc35719c76','次建康留守趙龍圖雷音堂韵  其一','釋師範','宋','宋诗','song-poetry','','[]','晴空霹靂絕追尋，聽者須教辨者瘖。',32,'全唐诗/poet.song.190000.json','["晴空霹靂絕追尋，聽者須教辨者瘖。", "坐斷封疆行正令，迥然超越去來今。"]'),
('433301fa-a898-44d5-976a-f4d79ffc644c','次建康留守趙龍圖雷音堂韵  其二','釋師範','宋','宋诗','song-poetry','','[]','底事明明不用尋，通身有口却如瘖。',32,'全唐诗/poet.song.190000.json','["底事明明不用尋，通身有口却如瘖。", "笑他盧老能多事，引蔓牽枝誑古今。"]'),
('3cc2069c-6b5d-44b1-a71a-467e105f071f','次建康留守趙龍圖雷音堂韵  其三','釋師範','宋','宋诗','song-poetry','','[]','居士門高幾萬尋，曾聆一語警肓瘖。',32,'全唐诗/poet.song.190000.json','["居士門高幾萬尋，曾聆一語警肓瘖。", "誰知千里同風事，歷歷分明在目今。"]'),
('79a7be3a-38c5-489a-a7f0-c33f56007831','次平江知府鄒編修韵  其一','釋師範','宋','宋诗','song-poetry','','[]','曹谿平地起風濤，後代船高水亦高。',32,'全唐诗/poet.song.190000.json','["曹谿平地起風濤，後代船高水亦高。", "寄語隨流入流者，更須拋却手中篙。"]'),
('4c9d6d42-9c5c-4410-87ab-558c1022f288','次平江知府鄒編修韵  其二','釋師範','宋','宋诗','song-poetry','','[]','曾駕鐵船驚海濤，想應不怕浪頭高。',32,'全唐诗/poet.song.190000.json','["曾駕鐵船驚海濤，想應不怕浪頭高。", "鄞江一滴渾無有，切莫妄傳深幾篙。"]'),
('53856431-30af-4bae-b352-43d6af40a717','次長沙趙督相送惠首座韵  其一','釋師範','宋','宋诗','song-poetry','','[]','行脚親曾到地頭，固知不是等閑遊。',32,'全唐诗/poet.song.190000.json','["行脚親曾到地頭，固知不是等閑遊。", "歸時有問五峰信，爲報龍淵已絕流。"]'),
('e76746ab-3345-406a-ae54-559e5ead79a7','次長沙趙督相送惠首座韵  其二','釋師範','宋','宋诗','song-poetry','','[]','絕流之句許誰知，獨有毗耶老古錐。',32,'全唐诗/poet.song.190000.json','["絕流之句許誰知，獨有毗耶老古錐。", "非是望梅圖止渴，調羹已熟向南枝。"]'),
('ac0aa493-a8d3-46e8-a1e7-e54d082b9abb','次韵題大梅常禪師塔  其一','釋師範','宋','宋诗','song-poetry','','[]','馬師問處沒蹤由，或示三冬話九秋。',32,'全唐诗/poet.song.190000.json','["馬師問處沒蹤由，或示三冬話九秋。", "認著即心心即佛，一絲頭是一絲頭。"]'),
('a7854f8b-8d76-4ba0-b524-5261e567467b','次韵題大梅常禪師塔  其二','釋師範','宋','宋诗','song-poetry','','[]','茫茫摘葉與尋枝，獨許山翁親見伊。',32,'全唐诗/poet.song.190000.json','["茫茫摘葉與尋枝，獨許山翁親見伊。", "點著直行三萬里，至今脚跡少人知。"]'),
('36a36c42-6288-49cc-a978-7a5116883ca5','次韵題大梅常禪師塔  其三','釋師範','宋','宋诗','song-poetry','','[]','視死生如遊戲場，固知老子不曾亡。',32,'全唐诗/poet.song.190000.json','["視死生如遊戲場，固知老子不曾亡。", "祇今何處問消息，風遞梅花撲鼻孔。"]'),
('25f70c7b-0f44-44be-b60b-a14bc1aee4d0','寄雲居掩室和尚  其一','釋師範','宋','宋诗','song-poetry','','[]','鷲峰雲散霜天冷，南北東西片月孤。',32,'全唐诗/poet.song.190000.json','["鷲峰雲散霜天冷，南北東西片月孤。", "喜得江湖好消息，點胸尊者在雲居。"]'),
('0066c2b9-428f-481f-afd3-95d8bd9c4f08','寄雲居掩室和尚  其二','釋師範','宋','宋诗','song-poetry','','[]','幾回夢到白雲顛，欲往難禁懶病牽。',32,'全唐诗/poet.song.190000.json','["幾回夢到白雲顛，欲往難禁懶病牽。", "何日相依傾倒夜，月寒千嶂一聲猿。"]'),
('b22a22e8-a734-4dd8-8ece-a4dd1121b3ba','寄雲居掩室和尚  其三','釋師範','宋','宋诗','song-poetry','','[]','從來有口掛虛壁，誰信如今口亦無。',32,'全唐诗/poet.song.190000.json','["從來有口掛虛壁，誰信如今口亦無。", "因記通身紅爛客，無端白紙强塗糊。"]'),
('69b3d769-52ca-4c1a-932c-4a4e2851b927','少室','釋師範','宋','宋诗','song-poetry','','[]','塵蒙虛壁冷蕭蕭，未厭家風太寂寥。',32,'全唐诗/poet.song.190000.json','["塵蒙虛壁冷蕭蕭，未厭家風太寂寥。", "門外依前積深雪，不知誰肯立齊腰。"]'),
('617ecbc8-d1b2-4e90-9bf1-e6b0770d932a','止翁','釋師範','宋','宋诗','song-poetry','','[]','萬法都盧歸一法，一法不知何所歸。',38,'全唐诗/poet.song.190000.json','["萬法都盧歸一法，一法不知何所歸。", "肚饑買箇油{飠茲}喫，喫了油{飠茲}肚不饑。"]'),
('ab172300-af81-439d-b5eb-b37d7869a292','石田','釋師範','宋','宋诗','song-poetry','','[]','紛紛多是競膏腴，確實誰能下一鋤。',32,'全唐诗/poet.song.190000.json','["紛紛多是競膏腴，確實誰能下一鋤。", "幾見萌心還㦬欛，只緣無處著工夫。"]'),
('4bcb763a-37ed-4ac1-b9bc-2bb99d0aaddd','別浦','釋師範','宋','宋诗','song-poetry','','[]','東海西邊西海南，蘆花裊裊水漫漫。',32,'全唐诗/poet.song.190000.json','["東海西邊西海南，蘆花裊裊水漫漫。", "謝郎猶自不知處，莫作尋常洲渚看。"]'),
('245d1a7f-c6fa-42d0-8073-2ab72760f78e','高原','釋師範','宋','宋诗','song-poetry','','[]','佛祖仰望不及處，暗通一線幾何深。',32,'全唐诗/poet.song.190000.json','["佛祖仰望不及處，暗通一線幾何深。", "冰嚴雪冷無人會，空瀉斷崖千萬尋。"]'),
('65fd5e02-5c08-4f56-8fd0-cd8a7313d630','死翁','釋師範','宋','宋诗','song-poetry','','[]','一驚塗毒皷，脫爾喪全軀。',24,'全唐诗/poet.song.190000.json','["一驚塗毒皷，脫爾喪全軀。", "誰信髑髏上，重生頷下鬚。"]'),
('930e7fa1-3b60-4439-9406-0eaab5eb534e','復古','釋師範','宋','宋诗','song-poetry','','[]','麥已登場稻滿田，蕢桴土鼓樂平平。',32,'全唐诗/poet.song.190000.json','["麥已登場稻滿田，蕢桴土鼓樂平平。", "不知將謂羲皇世，元是天開寶慶年。"]'),
('69ca304f-77f8-4325-b0d2-ab871649c6bc','雲谷','釋師範','宋','宋诗','song-poetry','','[]','或卷或舒多變態，隨呼隨應發天真。',32,'全唐诗/poet.song.190000.json','["或卷或舒多變態，隨呼隨應發天真。", "誰知路轉峰回處，幽鳥啼芳別是春。"]'),
('f9f8b481-ab0b-492a-834f-ae07156e301e','枯木','釋師範','宋','宋诗','song-poetry','','[]','不入樵夫手，不登郢匠門。',24,'全唐诗/poet.song.190000.json','["不入樵夫手，不登郢匠門。", "只麽老丘壑，且無刀斧痕。"]'),
('d0698eb5-8f4e-4eac-ab5a-fa390afe61ce','無際','釋師範','宋','宋诗','song-poetry','','[]','儱侗復儱侗，平夷更平夷。',24,'全唐诗/poet.song.190000.json','["儱侗復儱侗，平夷更平夷。", "伸手不見掌，趙州東院西。"]'),
('75e3330f-20df-425d-a28e-a0afa21fcf4c','訥堂','釋師範','宋','宋诗','song-poetry','','[]','德山無語歸方丈，象骨低頭入草庵。',32,'全唐诗/poet.song.190000.json','["德山無語歸方丈，象骨低頭入草庵。", "大鵬一舉九萬里，籬邊燕雀空呢喃。"]'),
('7922681c-e204-4d23-b03a-ba40631f35d4','淈𣸩','釋師範','宋','宋诗','song-poetry','','[]','抓頭忘癢處，弄物不知名。',24,'全唐诗/poet.song.190000.json','["抓頭忘癢處，弄物不知名。", "一箇無分曉，千金買不成。"]'),
('7fb71c53-5a6c-4ed4-8e9b-d1e1ce42e4ac','常覺','釋師範','宋','宋诗','song-poetry','','[]','暫時不在還同死，徹底惺惺亦自瞞。',32,'全唐诗/poet.song.190000.json','["暫時不在還同死，徹底惺惺亦自瞞。", "長愛東村老婆子，逢僧也解道和南。"]'),
('70e2b5fe-63ae-40d8-bd19-ed433a12acad','琴枕','釋師範','宋','宋诗','song-poetry','','[]','巧出焦桐樣，淳含太古音。',24,'全唐诗/poet.song.190000.json','["巧出焦桐樣，淳含太古音。", "多因和夢聽，只作夜蟲吟。"]'),
('5fe601ee-6036-46f1-afe0-9a2b4d176d94','跛翁','釋師範','宋','宋诗','song-poetry','','[]','平常行一步，却不墮平常。',24,'全唐诗/poet.song.190000.json','["平常行一步，却不墮平常。", "盡道脚長短，誰知脚短長。"]'),
('53d124c8-89f4-4bfb-9b6b-c68f596a9a1a','臭庵','釋師範','宋','宋诗','song-poetry','','[]','全無氣息，直是薰人。',20,'全唐诗/poet.song.190000.json','["全無氣息，直是薰人。", "無鼻孔者，方堪與隣。"]'),
('ee7c8b1d-0b97-42c8-82ae-2f174e225d18','次野雲南和尚雪竇錦鏡韵','釋師範','宋','宋诗','song-poetry','','[]','萬象融一奩，九色猶未多。',48,'全唐诗/poet.song.190000.json','["萬象融一奩，九色猶未多。", "圓浄出良範，羅紋非巧梭。", "有樣不可製，無痕安用磨。", "試問光影亡，如何復如何。"]'),
('6eda2672-089b-4858-a639-adbb0d341e02','送趙龍圖歸四明','釋師範','宋','宋诗','song-poetry','','[]','昔年曾約歸四明，掇鉢共飯莆菜羹。',147,'全唐诗/poet.song.190000.json','["昔年曾約歸四明，掇鉢共飯莆菜羹。", "東園蔬薺幾衰長，望之何以辜斯盟。", "鏗鏗小節何足拘，大名當振聲谹谹。", "旌旗不動剿胡種，屈伸一臂逾長城。", "淮甸既肅四海肅，豐功盛德應難名。", "了知八珍與藜莧，清閑富貴但等平。", "我罹劫火固無悶，公視晝錦不以榮。", "七佛承承竟何據，六祖忉忉空碗鳴。", "君不見剎竿頭上鐵龍頭，鴻毛至重山嶽輕。"]'),
('8a02b777-5bd9-40e0-9b4f-ae86d9585d4a','送無相和尚歸鄉','釋師範','宋','宋诗','song-poetry','','[]','同名同號同桑梓，同住江湖亡彼此。',114,'全唐诗/poet.song.190000.json','["同名同號同桑梓，同住江湖亡彼此。", "有時同上孤峰巔，有時同下滄溟底。", "苦同憂，樂同喜，金博金兮水洗水。", "有時捩轉鐵面皮，心口全然不相似。", "你若住兮我即行，你若行兮我即止。", "白日青天轟怒雷，平地無風波浪起。", "非不非，是不是，西川大隨，桐城投子。"]'),
('2bb2920b-b2c0-450f-9085-6f651dd34a8b','送訥堂和尚住秀之天寧','釋師範','宋','宋诗','song-poetry','','[]','蘇州有，常州有。',84,'全唐诗/poet.song.190000.json','["蘇州有，常州有。", "真箇有，未嘗有。", "賤時傾國不可換，貴則陪錢掗一斗。", "伸一手，縮一手，日月奔忙，山河倒走。", "濟北瞎馿退三步，跛脚雲門大張口。", "阿呵呵，只今此話大行，何待三十年後。"]'),
('3d1ba03e-7a5c-47a9-93ee-d3631a504485','送率庵和尚住雲居','釋師範','宋','宋诗','song-poetry','','[]','東湖水深蟠老龍，晨昏出沒無定蹤。',64,'全唐诗/poet.song.190000.json','["東湖水深蟠老龍，晨昏出沒無定蹤。", "開口合口噴香霧，舉足下足生陰風。", "而今改宅雲居去，威風萬竅聲號怒。", "謂言不是抉珠人，未應輕踏甌峰路。"]'),
('d74b6276-ece0-40d0-a29f-5c2ad44f60fb','送凝藏主歸蜀','釋師範','宋','宋诗','song-poetry','','[]','凝藏主，五載惡相聚。',107,'全唐诗/poet.song.190000.json','["凝藏主，五載惡相聚。", "我既橫點頭，公亦未相許。", "就中猶尀耐，拗折露明柱。", "似此拙去就，端的不可恕。", "蕭蕭九月風露寒，忽來告別還鄉去。", "臨歧可煞沒巴鼻，却要就我覓轉語。", "一轉語，如何舉，濕紙裹大蟲，大棒打老鼠。", "阿呵呵，無你會處。"]');
